/* AUTO-GENERATED — Colorado Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["CO"] = {"code":"CO","name":"Colorado","agency":"Colorado DMV","agencyShort":"DMV","handbook":"https://dmv.colorado.gov/sites/dmv/files/documents/2023_CDL_Manual_DR_2251.pdf","links":{},"en":[{"q":"On Colorado highways, what is the maximum legal width of a standard commercial vehicle (excluding mirrors and required safety appurtenances) before an oversize permit is needed?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"answer":1,"explanation":"Colorado limits vehicle width to 8 feet 6 inches (102 inches). Clearance lights, rearview mirrors, and other required accessories are not counted toward this limit. Source: C.R.S. 42-4-502 (Width of vehicles).","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, laden or unladen, on Colorado highways?","options":["13 feet 6 inches","14 feet 0 inches","14 feet 6 inches","15 feet 0 inches"],"answer":2,"explanation":"A driver may not operate a vehicle, unladen or with a load, that exceeds a height of 14 feet 6 inches. Source: C.R.S. 42-4-504 (Height and length of vehicles).","handbook":"","hbref":""},{"q":"Under Colorado law, what is the maximum overall length of a single motor vehicle (inclusive of front and rear bumpers)?","options":["40 feet","45 feet","53 feet","60 feet"],"answer":1,"explanation":"No single motor vehicle may exceed 45 feet in extreme overall length, including front and rear bumpers. Source: C.R.S. 42-4-504 (Height and length of vehicles).","handbook":"","hbref":""},{"q":"What is the maximum total overall length of a combination of vehicles coupled together on Colorado highways (without a special permit)?","options":["60 feet","65 feet","70 feet","75 feet"],"answer":2,"explanation":"No combination of vehicles may exceed a total overall length of 70 feet, and a combination may consist of no more than four units. Source: C.R.S. 42-4-504 (Height and length of vehicles).","handbook":"","hbref":""},{"q":"In Colorado, the maximum weight allowed on a single axle equipped with pneumatic tires is:","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,000 pounds"],"answer":2,"explanation":"When the wheels on a single axle are equipped with pneumatic tires, the maximum load is 20,000 pounds. Source: C.R.S. 42-4-507 (Wheel and axle loads).","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tandem axle group operating on a Colorado INTERSTATE highway?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":2,"explanation":"On the interstate system Colorado follows the federal tandem-axle limit of 36,000 pounds. (On non-interstate state highways the tandem limit is 40,000 pounds.) Source: C.R.S. 42-4-507 (Wheel and axle loads).","handbook":"","hbref":""},{"q":"On a non-interstate Colorado state highway, what is the maximum weight permitted on a tandem axle group?","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"answer":2,"explanation":"On non-interstate state highways Colorado allows up to 40,000 pounds on a tandem axle, which is higher than the 36,000-pound interstate limit. Source: C.R.S. 42-4-507 (Wheel and axle loads).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight allowed on the INTERSTATE system in Colorado without an overweight permit?","options":["76,000 pounds","80,000 pounds","85,000 pounds","90,000 pounds"],"answer":1,"explanation":"On interstate highways Colorado applies the federal maximum gross weight of 80,000 pounds, governed by the federal bridge formula. Source: C.R.S. 42-4-508 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight allowed on Colorado NON-interstate (state and local) highways under the state weight table, absent a permit?","options":["80,000 pounds","82,000 pounds","85,000 pounds","90,000 pounds"],"answer":2,"explanation":"On non-interstate highways Colorado's own gross-weight table permits up to 85,000 pounds, which exceeds the 80,000-pound interstate cap. Source: C.R.S. 42-4-508 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"How does Colorado define a 'tandem axle' for weight purposes?","options":["Two or more consecutive axles spaced more than 40 inches and not more than 96 inches apart","Two axles spaced exactly 48 inches apart","Any two axles spaced less than 40 inches apart","Three or more axles spaced more than 96 inches apart"],"answer":0,"explanation":"A tandem axle is two or more consecutive axles whose centers fall between parallel vertical planes spaced more than 40 inches and not more than 96 inches apart, extending across the full width of the vehicle. Source: C.R.S. 42-4-507 (Wheel and axle loads).","handbook":"","hbref":""},{"q":"Which formula does Colorado use to determine maximum allowable gross weight based on axle spacing on the interstate system?","options":["The state mileage-tax formula","The federal bridge formula (bridge gross weight formula)","The tire-width-per-inch formula only","A fixed 80,000-pound flat rule with no axle spacing"],"answer":1,"explanation":"On interstate highways Colorado limits gross weight per axle group using the federal bridge formula, which relates allowable weight to the number of axles and the distance between extreme axles, capped at 80,000 pounds. Source: C.R.S. 42-4-508; federal 23 CFR 658 (bridge formula).","handbook":"","hbref":""},{"q":"In Colorado's general (non-interstate) gross weight formula W = 1,000(L + 40), what does 'L' represent?","options":["The number of axles on the vehicle","The total load weight in tons","The distance in feet between the centers of the first and last axles","The legal length of the trailer"],"answer":2,"explanation":"In Colorado's non-interstate gross-weight formula W = 1,000(L + 40), 'L' is the distance in feet between the centers of the first and last axles of the group, and W is the maximum gross weight in pounds, not to exceed 85,000 pounds. Source: C.R.S. 42-4-508 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"A driver hauling a load 11 feet wide on a Colorado state highway must do which of the following?","options":["Nothing; 11 feet is within the legal width limit","Obtain a CDOT oversize permit because the load exceeds 8 feet 6 inches","Only display a flag, with no permit required","Reduce gross weight to 80,000 pounds"],"answer":1,"explanation":"Any load wider than the legal 8 feet 6 inches requires a state oversize permit from CDOT before traveling. An 11-foot-wide load is oversize. Source: C.R.S. 42-4-502 and 42-4-510; CDOT Permit Office.","handbook":"","hbref":""},{"q":"In Colorado, oversize and overweight permits for travel on the state highway system are issued by:","options":["The Colorado Department of Revenue, Motor Vehicle Division","The Colorado Department of Transportation (CDOT) Permit Office","The county sheriff where the trip begins","The Federal Motor Carrier Safety Administration"],"answer":1,"explanation":"Oversize/overweight permits for the state highway system are issued by the CDOT Permit Office, generally through the online COOPR (Colorado Oversize Overweight Permitting and Routing) system. Source: C.R.S. 42-4-510; CDOT freight.colorado.gov.","handbook":"","hbref":""},{"q":"What is the name of the online system Colorado uses for carriers to order oversize/overweight permits and obtain approved routes?","options":["COOPR (Colorado Oversize Overweight Permitting and Routing)","IRP (International Registration Plan)","PRISM (Performance Registration Information Systems Management)","UCR (Unified Carrier Registration)"],"answer":0,"explanation":"Colorado issues oversize/overweight permits through the COOPR system, where carriers apply online, pay fees, and receive routing; many permits can be self-issued. Source: CDOT, coopr.codot.gov; C.R.S. 42-4-510.","handbook":"","hbref":""},{"q":"Under a Colorado oversize permit, loose hay (including round bales) may be hauled up to what width?","options":["8 feet 6 inches","10 feet 6 inches","12 feet","14 feet"],"answer":2,"explanation":"Colorado's width statute allows loose hay, including round bales, to be transported up to 12 feet wide; rectangular (baled) hay is limited to 10 feet 6 inches. Source: C.R.S. 42-4-502 (Width of vehicles).","handbook":"","hbref":""},{"q":"On Colorado highways, what is the maximum weight on any one wheel of a STEEL-tired vehicle, per inch of tire cross-sectional width?","options":["300 pounds per inch","500 pounds per inch","650 pounds per inch","800 pounds per inch"],"answer":1,"explanation":"The gross weight on any one wheel of a steel-tired vehicle may not exceed 500 pounds per inch of cross-sectional width of the tire. Source: C.R.S. 42-4-507 (Wheel and axle loads).","handbook":"","hbref":""},{"q":"Colorado allows certain alternative-fuel vehicles to exceed the standard maximum gross and axle weight limits by how much, to account for the heavier fuel/power system?","options":["Up to 400 pounds","Up to 1,000 pounds","Up to 2,000 pounds","Up to 5,000 pounds"],"answer":2,"explanation":"Colorado permits vehicles powered by alternative fuel to exceed the gross and axle weight limits by up to 2,000 pounds, consistent with the federal natural gas/electric vehicle weight allowance. Source: C.R.S. 42-4-508 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"When a Colorado combination of vehicles is loaded, each vehicle in the combination must generally carry at least what share of the total gross weight (with limited exceptions for certain utility/pole trailers)?","options":["At least 5 percent of overall gross weight","At least 10 percent of overall gross weight","At least 25 percent of overall gross weight","At least 50 percent of overall gross weight"],"answer":1,"explanation":"In a vehicle combination, each vehicle must bear at least 10 percent of the overall gross weight, except for specialized trailers used to haul fixed utility loads or poles. Source: C.R.S. 42-4-508 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"A Colorado peace officer who believes a vehicle is overweight may require the driver to be weighed and, if the vehicle is over the legal limit, may require the driver to do what?","options":["Immediately surrender the commercial driver license","Off-load enough cargo to bring the gross weight down to the legal limit","Pay the overweight fine in cash on the spot before proceeding","Continue to the destination and report to a port of entry within 24 hours"],"answer":1,"explanation":"An officer with reason to believe a vehicle is overweight may require it to be weighed on portable or stationary scales (or nearby public scales within five miles) and, if it is unlawfully overweight, require the driver to remove enough load to reduce the gross weight to the legal limit. Source: C.R.S. 42-4-509 (Vehicles weighed - excess removed).","handbook":"","hbref":""},{"q":"In Colorado, which CDL class is required to operate any combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, where the vehicle being towed has a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Colorado defines a Class A CDL as any combination of vehicles with a GCWR of 26,001 lbs or more, provided the towed unit's GVWR exceeds 10,000 lbs. Source: Colorado CDL Manual (Colorado DMV/Dept. of Revenue), CDL class definitions; C.R.S. 42-2-402.","handbook":"","hbref":""},{"q":"Which Colorado CDL class covers a single vehicle with a GVWR of 26,001 pounds or more that may tow another vehicle not exceeding 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"A Class B CDL in Colorado is required for any single vehicle with a GVWR of 26,001 lbs or more, which may tow a unit not over 10,000 lbs GVWR. Source: Colorado CDL Manual (Colorado DMV), class definitions.","handbook":"","hbref":""},{"q":"A driver operates a single vehicle under 26,001 pounds GVWR that is designed to carry 18 passengers including the driver. Which Colorado CDL class is required?","options":["No CDL is required","Class A","Class B","Class C"],"answer":3,"explanation":"A Class C CDL covers vehicles that do not meet the Class A or B weight definitions but are designed to transport 16 or more passengers (including the driver) or carry placarded hazardous materials. Source: Colorado CDL Manual (Colorado DMV), class definitions.","handbook":"","hbref":""},{"q":"Which endorsement must a Colorado CDL holder obtain to transport hazardous materials in amounts requiring placards?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"answer":2,"explanation":"The H (Hazardous Materials) endorsement is required to haul placarded hazardous materials. In Colorado it requires passing the HazMat knowledge test, completing ELDT theory, and passing a TSA security threat assessment. Source: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Colorado CDL for intrastate (within-state) driving only?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"Colorado allows a CDL at age 18 for intrastate operation only. Drivers aged 18 to 20 receive a 'K' restriction limiting them to driving within Colorado. Source: Colorado DMV; C.R.S. 42-2-403.","handbook":"","hbref":""},{"q":"What is the minimum age required to obtain a Colorado CDL valid for interstate (across state lines) driving?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"Interstate commercial driving requires a minimum age of 21. Drivers 18 to 20 hold a CDL with a 'K' restriction (intrastate only). Source: Colorado DMV; FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Under federal rules adopted in Colorado, how long must a Commercial Learner Permit (CLP) be held before the holder is eligible to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 60 days","At least 180 days"],"answer":0,"explanation":"A CLP holder may not take the CDL skills test until at least 14 days have passed since the CLP's initial issuance. Source: FMCSA 49 CFR 383.25, applied by Colorado DMV.","handbook":"","hbref":""},{"q":"Which endorsement is required for a Colorado driver who hauls a tank vehicle carrying liquids in bulk with an aggregate rated capacity of 1,000 gallons or more?","options":["H endorsement","N endorsement","T endorsement","S endorsement"],"answer":1,"explanation":"The N (Tank Vehicle) endorsement is required to operate a tank vehicle with tanks of individual rated capacity over 119 gallons and aggregate rated capacity of 1,000 gallons or more. It requires passing the tanker knowledge test. Source: Colorado DMV CDL Endorsements; 49 CFR 383.5.","handbook":"","hbref":""},{"q":"A Colorado driver wants the T endorsement to pull double or triple trailers. What must the driver do to add it?","options":["Pass only a knowledge (written) test","Pass a knowledge test and a skills test","Pass a TSA background check","Complete behind-the-wheel ELDT training"],"answer":0,"explanation":"The T (Doubles/Triples) endorsement requires passing only the doubles/triples knowledge test in Colorado; no separate skills test is required. It can be added to a Class A CDL. Source: Colorado DMV CDL Endorsements & Requirements.","handbook":"","hbref":""},{"q":"Which endorsement does a Colorado driver need to transport 16 or more passengers (including the driver) in a commercial vehicle?","options":["S endorsement","N endorsement","P endorsement","H endorsement"],"answer":2,"explanation":"The P (Passenger) endorsement is required to carry 16 or more passengers including the driver. In Colorado it requires the passenger knowledge test, ELDT, and a skills test in a passenger vehicle. Source: Colorado DMV CDL Endorsements & Requirements.","handbook":"","hbref":""},{"q":"In Colorado, which endorsement is a prerequisite that must be obtained together with (or before) the School Bus (S) endorsement?","options":["N (Tanker) endorsement","P (Passenger) endorsement","H (HazMat) endorsement","T (Doubles/Triples) endorsement"],"answer":1,"explanation":"The P (Passenger) endorsement is a prerequisite for the S (School Bus) endorsement; an applicant cannot hold S without P. Source: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which entity maintains the registry that a Colorado CDL applicant's Entry-Level Driver Training (ELDT) provider must be listed on?","options":["The Colorado Department of Education","The FMCSA Training Provider Registry","The Colorado State Patrol","The Transportation Security Administration"],"answer":1,"explanation":"ELDT must be completed through a provider listed on the FMCSA Training Provider Registry (TPR); Colorado DMV verifies completion through the TPR before allowing the skills/knowledge test. Source: FMCSA TPR; Colorado DMV.","handbook":"","hbref":""},{"q":"For which of the following does ELDT (Entry-Level Driver Training) consist of theory-only training completed before the knowledge test, rather than including behind-the-wheel training?","options":["First-time Class A CDL","First-time Class B CDL","H (HazMat) endorsement","P (Passenger) endorsement"],"answer":2,"explanation":"For the H (HazMat) endorsement, ELDT is theory-only and must be completed before taking the HazMat knowledge test. Class A, B, P, and S require both theory and behind-the-wheel ELDT. Source: FMCSA 49 CFR 380 Subpart F; FMCSA TPR.","handbook":"","hbref":""},{"q":"Before being issued or renewing a Colorado HazMat (H) endorsement, what additional clearance must the applicant obtain?","options":["A DOT medical waiver","A TSA Security Threat Assessment (background check)","A Colorado Department of Education AIM registration","An SAE Level 2 inspection certificate"],"answer":1,"explanation":"Applicants for the H endorsement must pass a TSA Security Threat Assessment, which includes fingerprint-based background checks, before the endorsement is issued or renewed. Source: TSA/FMCSA 49 CFR 1572; Colorado DMV CDL FAQ.","handbook":"","hbref":""},{"q":"When applying for a Colorado CDL or CLP, how many proofs of Colorado address (residency) must the applicant present?","options":["One proof of address","Two proofs of address","Three proofs of address","No proof of address is required"],"answer":1,"explanation":"Colorado DMV requires two documents proving Colorado address, dated within the last year, in addition to proof of identity. Source: Colorado DMV Required Identification Documents.","handbook":"","hbref":""},{"q":"In addition to proof of identity and Colorado residency, what else must a Colorado CDL applicant provide at application?","options":["A passport only","Proof of their Social Security number","A notarized employer letter","Two character references"],"answer":1,"explanation":"Colorado requires applicants to present their Social Security card or other acceptable proof of their Social Security number, along with identity and lawful presence/residency documents. Source: Colorado DMV Required Identification Documents.","handbook":"","hbref":""},{"q":"Which of the following is one of the four federal medical self-certification categories a Colorado CDL holder must choose from?","options":["Non-Excepted Interstate","Placarded Interstate","Restricted Intrastate","Conditional Interstate"],"answer":0,"explanation":"The four self-certification categories are Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). A driver subject to federal physical qualification rules selects Non-Excepted Interstate. Source: FMCSA 49 CFR 383.71; Colorado DMV.","handbook":"","hbref":""},{"q":"A Colorado CDL holder who drives only within Colorado but still must meet medical qualification standards should self-certify under which category?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"answer":2,"explanation":"A driver operating only within Colorado who is still required to meet medical standards self-certifies as Non-Excepted Intrastate (NA). Source: FMCSA 49 CFR 383.71; Colorado DMV self-certification categories.","handbook":"","hbref":""},{"q":"Beyond the TSA background check, what must a Colorado driver do to add the HazMat (H) endorsement to a CDL?","options":["Pass a HazMat knowledge (written) test","Pass only a HazMat skills/road test","Submit a doubles/triples inspection report","Hold the endorsement for one year on a CLP first"],"answer":0,"explanation":"Adding the H endorsement requires passing the HazMat knowledge test (plus ELDT theory and a TSA Security Threat Assessment); there is no separate HazMat skills test. Source: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383.","handbook":"","hbref":""},{"q":"What is the maximum blood alcohol concentration (BAC) allowed while operating a commercial motor vehicle in Colorado?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"In Colorado a driver may not operate a CMV with a BAC of 0.04 or greater - half the 0.08 limit for non-commercial drivers. Source: Colorado CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Colorado's implied-consent law, what happens if a CDL holder refuses to submit to a chemical test for alcohol or drugs?","options":["A warning is issued with no disqualification","The CDL is disqualified for the same period as a first major offense","Only a fine is assessed","The license is suspended for 30 days"],"answer":1,"explanation":"Refusing the required test is treated as a major offense in Colorado, carrying a 1-year disqualification (3 years if hauling placarded hazardous materials) - the same as a first DUI/BAC violation. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51; C.R.S. 42-2-126.","handbook":"","hbref":""},{"q":"For a first major offense, such as driving a CMV with a BAC of 0.04 or higher, how long is a Colorado CDL holder disqualified (when NOT hauling placarded hazardous materials)?","options":["60 days","6 months","1 year","3 years"],"answer":2,"explanation":"A first major offense results in a 1-year CDL disqualification in Colorado. Source: Colorado CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long is the disqualification for a first major offense if the driver was transporting placarded hazardous materials at the time?","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"A first major offense while transporting placarded hazardous materials raises the disqualification to 3 years in Colorado. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification for a second major offense (for example, a second DUI) committed by a Colorado CDL holder?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification in Colorado, though reinstatement may be possible after 10 years under certain conditions. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'major offense' for a Colorado CDL holder?","options":["Following the vehicle ahead too closely","Leaving the scene of an accident involving a CMV","Speeding 15 mph over the limit","An improper lane change"],"answer":1,"explanation":"Leaving the scene of an accident is a major offense (1-year first / lifetime second disqualification). The other choices are serious traffic violations, not major offenses. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Using a commercial motor vehicle to commit a felony is treated under Colorado CDL rules as a:","options":["Serious traffic violation","Major offense","Out-of-service violation","Railroad-crossing violation"],"answer":1,"explanation":"Using a CMV in the commission of a felony is a major offense, carrying a 1-year disqualification for a first conviction and lifetime for a second. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A first conviction for any serious traffic violation results in what CDL disqualification in Colorado?","options":["No disqualification","30 days","60 days","120 days"],"answer":0,"explanation":"A single serious traffic violation does not by itself disqualify a driver; disqualification begins only with a second or third such violation within 3 years. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long is a Colorado CDL holder disqualified for a SECOND serious traffic violation committed within a 3-year period?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a 60-day disqualification. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long is the disqualification for a THIRD serious traffic violation within a 3-year period?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"Three serious traffic violations within 3 years result in a 120-day disqualification. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"At what speed over the posted limit does a speeding violation count as a 'serious traffic violation' for a Colorado CDL holder?","options":["10 mph or more over","15 mph or more over","20 mph or more over","25 mph or more over"],"answer":1,"explanation":"Speeding 15 mph or more above the posted speed limit is a serious traffic violation. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is NOT counted as a serious traffic violation for a Colorado CDL holder?","options":["Reckless driving","Following too closely","Driving a CMV with a BAC of 0.04","Erratic or improper lane changes"],"answer":2,"explanation":"Driving with a BAC of 0.04 or higher is a major offense, not a serious traffic violation. Reckless driving, following too closely, and improper lane changes are serious traffic violations. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Texting or using a hand-held mobile phone while driving a CMV repeatedly is categorized under Colorado CDL rules as a:","options":["Major offense","Serious traffic violation","Out-of-service violation","Non-disqualifying infraction"],"answer":1,"explanation":"Texting or using a hand-held phone while driving a CMV is a serious traffic violation; multiple convictions within 3 years trigger 60/120-day disqualifications. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51, 392.80/392.82.","handbook":"","hbref":""},{"q":"Colorado's 2025 hands-free state law (SB24-065) generally bans hand-held device use, but how does it apply to CDL drivers operating a CMV?","options":["CDL drivers are exempt because stricter federal rules already prohibit hand-held phone use","It fully replaces the federal rule for CMV drivers","It does not apply to any driver in Colorado","It allows CMV drivers to text if stopped at a light"],"answer":0,"explanation":"CMV drivers are exempt from the state hands-free law because the more stringent federal rule (in effect since 2012) already bans any hand-held phone use and texting while driving a CMV. Source: Colorado SB24-065; FMCSA 49 CFR 392.80/392.82.","handbook":"","hbref":""},{"q":"Under the federal rule that applies to Colorado CMV drivers, what is the maximum driver fine for texting or using a hand-held phone while driving a CMV?","options":["$500","$1,000","$2,750","$11,000"],"answer":2,"explanation":"Drivers face civil penalties up to $2,750 (the $11,000 figure applies to employers). Source: FMCSA Mobile Phone/No-Texting rule, 49 CFR 392.80/392.82.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification for a FIRST railroad highway-grade-crossing violation in Colorado?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"A first railroad-crossing violation carries a minimum 60-day disqualification. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A SECOND railroad-grade-crossing violation within 3 years results in what minimum CDL disqualification?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"A second railroad-crossing violation within 3 years carries a minimum 120-day disqualification. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A THIRD or subsequent railroad-grade-crossing violation within 3 years results in what minimum disqualification?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"Three or more railroad-crossing violations within 3 years carry a minimum 1-year disqualification. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification range for a FIRST violation of an out-of-service (OOS) order by a Colorado CDL driver NOT hauling hazmat or passengers?","options":["30 to 60 days","90 days only","180 days to 1 year","2 to 5 years"],"answer":2,"explanation":"A first out-of-service order violation results in a disqualification of 180 days to 1 year for a driver not transporting hazmat or passengers. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A SECOND out-of-service order violation within 10 years (non-hazmat, non-passenger) results in what disqualification range?","options":["120 days to 6 months","180 days to 1 year","2 to 5 years","Lifetime"],"answer":2,"explanation":"A second out-of-service order violation within 10 years carries a 2- to 5-year disqualification. Source: Colorado CDL Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Colorado's 'Slow Down, Move Over' law, what must the driver of a CMV do when approaching a stationary tow truck displaying flashing amber/yellow lights on a highway with two lanes in the same direction?","options":["Continue at the posted speed but sound the horn","Move into a lane at least one moving lane away from the stationary vehicle","Stop completely until the tow truck pulls away","Move onto the right shoulder and pass slowly"],"answer":1,"explanation":"Colorado's Move Over law (CRS 42-4-705) requires drivers on a highway with at least two lanes in the same direction to yield by moving into a lane at least one moving lane apart from a stationary emergency, towing, or public-utility vehicle displaying flashing lights. Source: Colorado CDL Manual / CRS 42-4-705.","handbook":"","hbref":""},{"q":"On a Colorado highway posted at 65 mph, a CMV driver cannot safely change lanes for a stopped patrol car because of heavy traffic. What does CRS 42-4-705 presume to be a safe speed?","options":["65 mph, since moving over was impossible","45 mph (20 mph below posted) is presumed safe","25 mph regardless of the posted limit","A complete stop until the lane clears"],"answer":1,"explanation":"Colorado's Move Over law (CRS 42-4-705) provides that when a driver cannot move over, on roads posted 45 mph or higher a speed of 20 mph below the posted limit is presumed safe (here 45 mph), and on roads under 45 mph, 25 mph or less is presumed safe. Source: CRS 42-4-705.","handbook":"","hbref":""},{"q":"When the Colorado school-bus stop signals are activated, at what minimum distance before reaching the bus must an approaching driver stop?","options":["10 feet","15 feet","20 feet","50 feet"],"answer":2,"explanation":"CRS 42-4-1903 requires a driver meeting or overtaking a stopped school bus with its red visual signal lights actuated to stop at least 20 feet before reaching the bus and not proceed until the lights are no longer actuated. Source: Colorado CDL Manual / CRS 42-4-1903.","handbook":"","hbref":""},{"q":"Under Colorado's school-bus law, when is a driver NOT required to stop for a school bus that is loading or unloading children with its red lights flashing?","options":["Whenever the driver is traveling under 25 mph","When the bus is on a different roadway of a highway divided into separate roadways","When there is more than one lane in the driver's direction","Whenever the bus is within a business district"],"answer":1,"explanation":"CRS 42-4-1903 states that a driver upon a highway with separate roadways need not stop upon meeting or passing a school bus that is on a different roadway. On an undivided road, traffic in BOTH directions must stop. Source: CRS 42-4-1903.","handbook":"","hbref":""},{"q":"A Colorado driver hauling placarded hazardous materials approaches a railroad grade crossing. Within what distance from the nearest rail must the vehicle stop?","options":["Within 50 feet but not less than 15 feet","Within 100 feet but not less than 50 feet","Within 25 feet but not less than 10 feet","Within 75 feet but not less than 25 feet"],"answer":0,"explanation":"CRS 42-4-707 requires placarded hazmat vehicles, school buses carrying schoolchildren, and passenger-carrying commercial vehicles to stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen before proceeding. Source: Colorado CDL Manual / CRS 42-4-707.","handbook":"","hbref":""},{"q":"While a placarded Colorado CMV crosses railroad tracks after stopping, what additional restriction applies under CRS 42-4-707?","options":["The driver must cross in reverse-then-forward to test traction","The driver must not manually shift gears while crossing the tracks","The driver must activate four-way flashers across the entire crossing","The driver must cross only at a speed under 5 mph"],"answer":1,"explanation":"CRS 42-4-707 directs that the driver cross only if there is no need to change gears while traversing the crossing and shall not manually shift gears while crossing the tracks, reducing the risk of stalling on the rails. Source: CRS 42-4-707.","handbook":"","hbref":""},{"q":"At which type of railroad crossing does Colorado law NOT require a placarded or bus driver to make the mandatory stop?","options":["Any crossing without automatic gates","A crossing controlled by a police officer or human flagperson directing traffic","Any crossing in a residential district","A crossing with two or more sets of tracks"],"answer":1,"explanation":"CRS 42-4-707 exempts the mandatory stop where a police officer or human flagperson directs traffic, where a traffic-control signal directs traffic, at street-railway crossings in a business district, and at crossings marked with an official 'exempt' sign. Source: CRS 42-4-707.","handbook":"","hbref":""},{"q":"What is the maximum speed limit on a surfaced, four-lane Colorado highway that is part of the interstate system, absent a different posted limit?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":2,"explanation":"CRS 42-4-1101 sets 65 mph on surfaced four-lane highways on the interstate system as the statutory maximum (CDOT may post higher or lower limits on specific segments). Source: CRS 42-4-1101.","handbook":"","hbref":""},{"q":"How does Colorado law treat the speed limit for large trucks compared with passenger cars on the same highway?","options":["Trucks have a separate statewide limit 10 mph below cars","Trucks must stay 15 mph below the posted limit on grades","Trucks follow the same posted limit; Colorado has no general differential truck speed limit","Trucks are capped at 55 mph statewide regardless of posting"],"answer":2,"explanation":"Colorado's speed statute (CRS 42-4-1101) does not establish a separate, lower statewide speed limit for trucks by class or weight; CMVs follow the same posted limits as other vehicles. Source: CRS 42-4-1101.","handbook":"","hbref":""},{"q":"Under CRS 42-4-1101, what is the prima facie speed limit on an 'open mountain highway' in Colorado?","options":["30 mph","40 mph","50 mph","55 mph"],"answer":1,"explanation":"CRS 42-4-1101 lists 40 mph on open mountain highways (and 20 mph on narrow, winding mountain highways or blind curves) among the prima facie limits. Source: CRS 42-4-1101.","handbook":"","hbref":""},{"q":"Colorado's 2024 truck lane law bars trucks of 16,000 lbs or more from the far-left lane at certain I-70 mountain locations. Which of these is one of those designated areas?","options":["Monument Hill on I-25","Vail Pass","Raton Pass on I-25","The Grand Junction interchange"],"answer":1,"explanation":"Colorado's left-lane truck restriction bars trucks 16,000 lbs or heavier from the far-left lane on I-70 segments including Floyd Hill, Georgetown Hill, the Eisenhower Tunnel, Dowd Junction, and Vail Pass, where there are at least three lanes in one direction. Source: CDOT / 2024 Colorado law (SB24-100).","handbook":"","hbref":""},{"q":"On the I-70 segments where Colorado restricts heavy trucks from the far-left lane, what exception does the law allow?","options":["Trucks may use the left lane when traffic is light","Trucks may use the far-left lane to pass another vehicle","Trucks may use the left lane only at night","There is no exception under any condition"],"answer":1,"explanation":"Colorado's truck left-lane restriction on the designated I-70 mountain stretches still permits trucks to use the far-left lane when passing; the ban targets sustained left-lane travel. Source: CDOT / 2024 Colorado law (SB24-100).","handbook":"","hbref":""},{"q":"Colorado's Commercial Vehicle Chain 'Must-Carry' law requires CMVs to carry chains on the I-70 mountain corridor during which annual period?","options":["October 1 through April 30","September 1 through May 31","November 1 through March 31","All year, with no seasonal window"],"answer":1,"explanation":"Colorado's must-carry law requires commercial vehicles (GVWR 16,001 lbs or more) to carry sufficient chains from September 1 through May 31 on I-70 between Dotsero (MP 133) and Morrison (MP 259). Source: CDOT / CRS 42-4-106.","handbook":"","hbref":""},{"q":"When the Colorado Commercial Vehicle Chain Law is in effect, how must a CMV with four or more drive wheels be equipped to proceed?","options":["Chains or ATDs on at least four of the drive-wheel tires","Chains on the steer tires only","Chains on any two tires of the driver's choice","Snow-rated tires alone are always sufficient"],"answer":0,"explanation":"When the chain law is active, a CMV must have chains or alternate traction devices on at least four of the drive-wheel tires (or all drive tires if it has fewer than four). Source: CDOT Chain Law / CRS 42-4-106.","handbook":"","hbref":""},{"q":"The I-70 mountain corridor where Colorado's Commercial Vehicle Chain Law applies runs between which two points?","options":["Grand Junction (MP 26) and Denver (MP 275)","Dotsero (MP 133) and Morrison (MP 259)","Glenwood Springs (MP 116) and Golden (MP 263)","Vail (MP 176) and Idaho Springs (MP 240)"],"answer":1,"explanation":"Colorado's commercial chain/must-carry requirement applies on I-70 between the Dotsero exit (Milepost 133) and the Morrison exit (Milepost 259). Source: CDOT / CRS 42-4-106.","handbook":"","hbref":""},{"q":"On the Colorado interstate highway, after stopping a CMV on the traveled portion, within how many feet must the driver place the three warning devices toward approaching traffic on level, straight roadway?","options":["At 5, 50, and 100 feet","At 10, 100, and 200 feet","At 25, 150, and 300 feet","At 50, 250, and 500 feet"],"answer":1,"explanation":"Colorado follows the federal FMCSR standard requiring warning devices placed at 10 feet, 100 feet, and 200 feet from the stopped CMV toward approaching traffic on an undivided, level roadway. Source: Colorado CDL Manual / 49 CFR 392.22 (adopted in Colorado).","handbook":"","hbref":""},{"q":"A Colorado CMV is forced to stop on the road just beyond a sharp curve that hides it from approaching traffic. How should the warning devices be adjusted?","options":["Place all three within 10 feet of the rear bumper","Move the device toward the curve 100 to 500 feet back to give ample warning","Omit the rear devices and only flag the front","Place all three on the centerline beside the cab"],"answer":1,"explanation":"When stopped within 500 feet of a curve, hillcrest, or other view obstruction, the driver moves the warning device in the direction of the obstruction so it is 100 to 500 feet from the vehicle to give ample warning. Source: Colorado CDL Manual / 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Colorado's most heavily used runaway truck ramp, on westbound I-70 near the Eisenhower Tunnel, is best described as which kind of device?","options":["A gravel arrestor bed that uses deep loose aggregate to stop a runaway truck","A steel cable net stretched across the lane","A water-filled crash cushion at the bottom of the grade","A magnetic braking strip embedded in the pavement"],"answer":0,"explanation":"The Lower Straight Creek ramp on westbound I-70 is the most-used runaway truck ramp in the U.S.; like Colorado's other arrester beds it uses a deep bed of loose crushed aggregate (rounded rock) to dissipate a runaway truck's energy. Source: CDOT / Colorado CDL Manual mountain-driving section.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle WIDTH on Colorado highways before an oversize permit from CDOT is required?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Colorado's legal width limit is 8 feet 6 inches (102 inches); loads exceeding this require a CDOT oversize permit, and over 11 feet wide generally requires a front pilot/escort vehicle on designated state highways. Source: CDOT Freight & Permitting / CRS 42-4-502.","handbook":"","hbref":""},{"q":"On a Colorado mountain grade, what is the correct braking technique a CMV driver should use to avoid needing a runaway ramp?","options":["Hold the service brakes down steadily the entire descent","Select a low gear before the descent and use light, intermittent brake applications","Shift to neutral to save fuel and coast down","Apply the trailer hand valve continuously while in high gear"],"answer":1,"explanation":"The Colorado CDL Manual mountain-driving guidance directs drivers to select a safe low gear BEFORE starting down a long grade and use the brakes intermittently (snub braking) so brakes do not overheat and fade; coasting in neutral is illegal and dangerous. Source: Colorado CDL Manual (Mountain Driving).","handbook":"","hbref":""},{"q":"Which Colorado agency issues commercial driver licenses (CDLs) and administers the required knowledge tests?","options":["The Colorado Department of Transportation (CDOT)","The Colorado Department of Revenue, Division of Motor Vehicles (DMV)","The Colorado State Patrol Ports of Entry Division","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":1,"explanation":"In Colorado, CDLs are issued by the Department of Revenue's Division of Motor Vehicles (DMV); knowledge tests are taken at a full-service DMV/Motor Vehicle office. Source: Colorado DMV, dmv.colorado.gov (First-time CDL Driver / CDL General Information).","handbook":"","hbref":""},{"q":"What is the minimum passing score on the Colorado CDL General Knowledge test, which contains 50 questions?","options":["70% (at least 35 of 50 correct)","75% (at least 38 of 50 correct)","90% (at least 45 of 50 correct)","80% (at least 40 of 50 correct)"],"answer":3,"explanation":"The Colorado CDL General Knowledge test has 50 questions and requires 80% — at least 40 correct — to pass, consistent with the Colorado CDL Manual and DMV testing standards. Source: Colorado DMV / Colorado CDL Manual.","handbook":"","hbref":""},{"q":"The Colorado CDL skills test is made up of three parts. Which set correctly lists those three parts?","options":["Written knowledge, pre-trip inspection, and on-road driving","Air brake check, parallel parking, and a road sign test","Basic vehicle control, hazmat screening, and on-road driving","Pre-trip inspection, basic vehicle control, and on-road driving"],"answer":3,"explanation":"Colorado's CDL skills test has three parts: the pre-trip inspection, basic vehicle control (maneuvers), and the on-road driving test, mirroring the federal CDL skills test structure adopted by Colorado. Source: Colorado CDL Manual; Colorado DMV.","handbook":"","hbref":""},{"q":"Before a first-time Colorado CDL applicant can take the skills test, what federally mandated training must be completed and verified?","options":["A defensive-driving course approved by the Colorado State Patrol","A CDOT oversize/overweight load-securement seminar","Entry-Level Driver Training (ELDT) from an FMCSA-registered provider","A Department of Revenue classroom safety orientation"],"answer":2,"explanation":"Since Feb. 7, 2022, Colorado requires Entry-Level Driver Training (ELDT) completed through an FMCSA-registered provider (logged in the Training Provider Registry) before a new applicant, class upgrade, or new H/P/S endorsement applicant may take the skills test. Source: Colorado DMV; 49 CFR Part 380 / FMCSA TPR.","handbook":"","hbref":""},{"q":"How long is a Colorado Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["Valid for 180 days and renewable once","Valid for 60 days and renewable twice","Valid for five years and renewable yearly","Valid for one year and not eligible for renewal"],"answer":3,"explanation":"A Colorado CLP is valid for one year and is NOT renewable; if it expires before the CDL is obtained, the applicant must retake the knowledge test(s) for a new CLP. Source: Colorado DMV (CDL General Information / First-time CDL Driver).","handbook":"","hbref":""},{"q":"After a Colorado applicant is issued a Commercial Learner's Permit, how long must it be held before the CDL skills test may be taken?","options":["At least 30 calendar days","At least 7 calendar days","At least 14 calendar days","At least 60 calendar days"],"answer":2,"explanation":"Colorado follows the federal rule that a CLP must be held for at least 14 calendar days before the holder may take the CDL skills test. Source: 49 CFR 383.25; Colorado DMV.","handbook":"","hbref":""},{"q":"Colorado CDL applicants must complete a self-certification declaring their type of driving. How many self-certification categories are there?","options":["Two","Three","Five","Four"],"answer":3,"explanation":"There are four self-certification categories: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, and Excepted Intrastate. In Colorado this is declared on form DR 2904/DR 2907. Source: Colorado DMV form DR 2904; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Colorado driver who operates in interstate commerce and must meet 49 CFR Part 391 driver-qualification rules (and therefore must carry a medical certificate) should self-certify under which category?","options":["Excepted Interstate","Non-excepted Intrastate","Excepted Intrastate","Non-excepted Interstate"],"answer":3,"explanation":"A driver operating in interstate commerce who is subject to and meets 49 CFR Part 391 qualification requirements — and must hold a medical examiner's certificate — self-certifies as Non-excepted Interstate. Source: Colorado DMV form DR 2904; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"To satisfy the DOT medical requirement, which document must a Colorado CDL applicant obtain and provide?","options":["A general physician's note confirming good health","A Colorado State Patrol fitness clearance card","A Medical Examiner's Certificate from a provider on the FMCSA National Registry","A CDOT permit medical waiver"],"answer":2,"explanation":"Most Colorado CDL holders must obtain a Medical Examiner's Certificate (DOT medical card) from an examiner listed on the FMCSA National Registry of Certified Medical Examiners. Source: Colorado DMV (CDL DOT Medical); FMCSA National Registry.","handbook":"","hbref":""},{"q":"For a typical non-excepted Colorado CDL driver, what is the maximum length of time a DOT Medical Examiner's Certificate is valid?","options":["Up to two years","Up to five years","Up to one year","Up to three years"],"answer":0,"explanation":"A DOT medical examiner's certificate is issued for a maximum of two years (and may be shorter if the examiner notes a condition needing monitoring). The driver must keep a current certificate on file with the Colorado DMV. Source: 49 CFR 391.43; Colorado DMV (CDL DOT Medical).","handbook":"","hbref":""},{"q":"If a self-certified non-excepted Colorado CDL driver lets the medical certificate on file with the DMV lapse, what is the typical consequence?","options":["The CDL is immediately and permanently revoked","The CDL is downgraded so commercial privileges are removed until a current medical certificate is filed","Nothing happens until the five-year CDL renewal","The driver is automatically reclassified as Excepted Interstate"],"answer":1,"explanation":"If a non-excepted driver's medical certificate expires and a current one is not submitted, Colorado downgrades the license, removing commercial driving privileges until a valid certificate is on file. Source: Colorado DMV (CDL DOT Medical); 49 CFR 383.73.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a Colorado CDL for INTERSTATE commercial driving or to transport placarded hazardous materials?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Colorado follows the federal minimum: a driver must be 21 to operate in interstate commerce or to haul placarded hazardous materials. Drivers 18-20 are limited to intrastate operation. Source: Colorado DMV; 49 CFR 383.","handbook":"","hbref":""},{"q":"A Colorado CDL holder who is 18 to 20 years old is restricted to driving only within Colorado. Which license restriction code reflects this intrastate-only limit?","options":["Restriction \"K\" (intrastate only)","Restriction \"L\" (no air brakes)","Restriction \"Z\" (no full air brakes)","Restriction \"E\" (no manual transmission)"],"answer":0,"explanation":"Colorado applies the \"K\" restriction (intrastate only) to CDL holders who may not operate in interstate commerce, including drivers ages 18-20. Source: Colorado DMV (CDL Restrictions).","handbook":"","hbref":""},{"q":"Which set of documents must a first-time Colorado CDL applicant present at the DMV?","options":["Only a current Colorado regular driver license","Proof of identity, proof of lawful U.S. presence, proof of Social Security number, and proof of Colorado residence","A passport and a CDOT load permit","An employer letter and two passport photos only"],"answer":1,"explanation":"Colorado CDL applicants must prove identity, lawful presence in the U.S., Social Security number, and Colorado residential address (e.g., utility bill or bank statement). Source: Colorado DMV (First-time CDL Driver).","handbook":"","hbref":""},{"q":"How is a Colorado CDL applicant's ELDT completion confirmed by the DMV before the skills test is allowed?","options":["The applicant mails a paper certificate to CDOT for approval","The applicant brings a notarized affidavit from the trainer","The provider electronically reports it to the FMCSA Training Provider Registry, which the DMV checks","The Colorado State Patrol issues an ELDT clearance letter"],"answer":2,"explanation":"FMCSA-registered ELDT providers submit completion records to the federal Training Provider Registry (TPR); Colorado's DMV verifies the record electronically before permitting the skills test. Source: Colorado DMV; FMCSA TPR / 49 CFR Part 380.","handbook":"","hbref":""},{"q":"In the correct order, what are the first three major steps for a first-time Colorado CDL applicant?","options":["Take the skills test, then get the CLP, then complete ELDT","Pass the knowledge test(s) and get the CLP, then complete ELDT, then take the skills test","Complete ELDT, then take the skills test, then pass the knowledge test","Get the medical card, then take the skills test, then take the knowledge test"],"answer":1,"explanation":"The Colorado sequence is: pass the required knowledge test(s) and receive the CLP, complete FMCSA-approved ELDT (theory and behind-the-wheel), then take the three-part skills test (after the 14-day CLP hold). Source: Colorado DMV (First-time CDL Driver).","handbook":"","hbref":""},{"q":"During the on-road portion of the Colorado CDL skills test, what is the examiner primarily evaluating?","options":["The applicant's ability to safely operate the vehicle in real traffic over a set route","Whether the applicant can recite the contents of the CDL manual","The applicant's parallel-parking speed only","The vehicle's compliance with oversize/overweight permit limits"],"answer":0,"explanation":"The on-road test evaluates safe operation in actual traffic over a predetermined route — turns, intersections, lane changes, and general driving. Backing/maneuvers are scored in the separate basic-control portion. Source: Colorado CDL Manual; Colorado DMV.","handbook":"","hbref":""},{"q":"A Colorado driver hauls only farm supplies entirely within Colorado and is exempt from parts of the state driver-qualification rules. Which self-certification category fits this driver?","options":["Excepted Intrastate","Non-excepted Interstate","Excepted Interstate","Non-excepted Intrastate"],"answer":0,"explanation":"A driver operating only within Colorado who is excepted from all or part of the state driver-qualification requirements self-certifies as Excepted Intrastate and generally is not required to file a DOT medical certificate. Source: Colorado DMV form DR 2904; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Regarding CDL fees in Colorado, which statement is the most accurate for a study guide?","options":["CDL knowledge and skills testing are always free of charge in Colorado","Fees are fixed permanently by federal law and never change","Specific fee amounts are set by the state and can change, so applicants should confirm current fees with the DMV","Only the medical exam has a fee; the DMV charges nothing for the license"],"answer":2,"explanation":"Colorado charges fees for CDL testing and issuance, but exact amounts are set by the state and are subject to change; applicants should verify current fees with the DMV rather than rely on a fixed figure. Source: Colorado DMV (CDL General Information / fee schedule).","handbook":"","hbref":""}],"ru":{"0":{"q":"На автомагистралях штата Колорадо какова максимальная разрешённая ширина стандартного коммерческого транспортного средства (без учёта зеркал и обязательных средств обеспечения безопасности), при превышении которой требуется разрешение на негабаритный груз?","options":["8 футов 0 дюймов (96 дюймов)","8 футов 6 дюймов (102 дюйма)","9 футов 0 дюймов (108 дюймов)","10 футов 0 дюймов (120 дюймов)"],"explanation":"Колорадо ограничивает ширину транспортного средства до 8 футов 6 дюймов (102 дюйма). Габаритные огни, зеркала заднего вида и другие обязательные принадлежности в этот предел не включаются. Источник: C.R.S. 42-4-502 (Ширина транспортных средств)."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства, гружёного или порожнего, на автомагистралях Колорадо?","options":["13 футов 6 дюймов","14 футов 0 дюймов","14 футов 6 дюймов","15 футов 0 дюймов"],"explanation":"Водитель не вправе управлять транспортным средством, порожним или с грузом, высота которого превышает 14 футов 6 дюймов. Источник: C.R.S. 42-4-504 (Высота и длина транспортных средств)."},"2":{"q":"Согласно законодательству Колорадо, какова максимальная общая длина одиночного механического транспортного средства (включая передний и задний бамперы)?","options":["40 футов","45 футов","53 фута","60 футов"],"explanation":"Ни одно одиночное механическое транспортное средство не может превышать 45 футов в предельной общей длине, включая передний и задний бамперы. Источник: C.R.S. 42-4-504 (Высота и длина транспортных средств)."},"3":{"q":"Какова максимальная общая длина состава из сцепленных транспортных средств на автомагистралях Колорадо (без специального разрешения)?","options":["60 футов","65 футов","70 футов","75 футов"],"explanation":"Ни один состав транспортных средств не может превышать общую длину 70 футов, и состав может включать не более четырёх единиц. Источник: C.R.S. 42-4-504 (Высота и длина транспортных средств)."},"4":{"q":"В Колорадо максимальная нагрузка, допустимая на одиночную ось, оснащённую пневматическими шинами, составляет:","options":["16 000 фунтов","18 000 фунтов","20 000 фунтов","22 000 фунтов"],"explanation":"Когда колёса на одиночной оси оснащены пневматическими шинами, максимальная нагрузка составляет 20 000 фунтов. Источник: C.R.S. 42-4-507 (Нагрузки на колёса и оси)."},"5":{"q":"Какова максимальная нагрузка, допустимая на сдвоенную группу осей при движении по МЕЖШТАТНОЙ автомагистрали Колорадо?","options":["32 000 фунтов","34 000 фунтов","36 000 фунтов","40 000 фунтов"],"explanation":"На межштатной системе автомагистралей Колорадо применяет федеральный предел для сдвоенной оси в 36 000 фунтов. (На автомагистралях штата, не относящихся к межштатным, предел для сдвоенной оси составляет 40 000 фунтов.) Источник: C.R.S. 42-4-507 (Нагрузки на колёса и оси)."},"6":{"q":"На автомагистрали штата Колорадо, не относящейся к межштатным, какова максимальная нагрузка, разрешённая на сдвоенную группу осей?","options":["34 000 фунтов","36 000 фунтов","40 000 фунтов","44 000 фунтов"],"explanation":"На автомагистралях штата, не относящихся к межштатным, Колорадо допускает до 40 000 фунтов на сдвоенную ось, что выше межштатного предела в 36 000 фунтов. Источник: C.R.S. 42-4-507 (Нагрузки на колёса и оси)."},"7":{"q":"Какова максимальная полная масса транспортного средства, допустимая на МЕЖШТАТНОЙ системе автомагистралей Колорадо без разрешения на перегруз?","options":["76 000 фунтов","80 000 фунтов","85 000 фунтов","90 000 фунтов"],"explanation":"На межштатных автомагистралях Колорадо применяет федеральный максимум полной массы в 80 000 фунтов, регулируемый федеральной мостовой формулой. Источник: C.R.S. 42-4-508 (Полная масса транспортных средств и грузов)."},"8":{"q":"Какова максимальная полная масса транспортного средства, допустимая на автомагистралях Колорадо, не относящихся к межштатным (штата и местного значения), согласно весовой таблице штата, при отсутствии разрешения?","options":["80 000 фунтов","82 000 фунтов","85 000 фунтов","90 000 фунтов"],"explanation":"На автомагистралях, не относящихся к межштатным, собственная весовая таблица Колорадо допускает до 85 000 фунтов, что превышает межштатный предел в 80 000 фунтов. Источник: C.R.S. 42-4-508 (Полная масса транспортных средств и грузов)."},"9":{"q":"Как Колорадо определяет «сдвоенную ось» для целей определения массы?","options":["Две или более последовательные оси, расположенные на расстоянии более 40 дюймов и не более 96 дюймов друг от друга","Две оси, расположенные ровно на расстоянии 48 дюймов друг от друга","Любые две оси, расположенные на расстоянии менее 40 дюймов друг от друга","Три или более оси, расположенные на расстоянии более 96 дюймов друг от друга"],"explanation":"Сдвоенная ось — это две или более последовательные оси, центры которых находятся между параллельными вертикальными плоскостями, расположенными на расстоянии более 40 дюймов и не более 96 дюймов друг от друга, проходящими по всей ширине транспортного средства. Источник: C.R.S. 42-4-507 (Нагрузки на колёса и оси)."},"10":{"q":"Какую формулу использует Колорадо для определения максимально допустимой полной массы на основе межосевого расстояния на межштатной системе?","options":["Формулу налога на пробег штата","Федеральную мостовую формулу (формулу полной массы для мостов)","Только формулу нагрузки на дюйм ширины шины","Фиксированное правило в 80 000 фунтов без учёта межосевого расстояния"],"explanation":"На межштатных автомагистралях Колорадо ограничивает полную массу на группу осей с помощью федеральной мостовой формулы, которая связывает допустимую массу с количеством осей и расстоянием между крайними осями, с ограничением до 80 000 фунтов. Источник: C.R.S. 42-4-508; федеральный 23 CFR 658 (мостовая формула)."},"11":{"q":"В общей (немежштатной) формуле полной массы Колорадо W = 1,000(L + 40), что обозначает «L»?","options":["Количество осей у транспортного средства","Общую массу груза в тоннах","Расстояние в футах между центрами первой и последней осей","Разрешённую длину прицепа"],"explanation":"В немежштатной формуле полной массы Колорадо W = 1,000(L + 40) «L» — это расстояние в футах между центрами первой и последней осей группы, а W — максимальная полная масса в фунтах, не превышающая 85 000 фунтов. Источник: C.R.S. 42-4-508 (Полная масса транспортных средств и грузов)."},"12":{"q":"Водитель, перевозящий груз шириной 11 футов по автомагистрали штата Колорадо, должен сделать следующее:","options":["Ничего; 11 футов находится в пределах разрешённого ограничения по ширине","Получить разрешение CDOT на негабаритный груз, поскольку груз превышает 8 футов 6 дюймов","Только вывесить флажок, разрешение не требуется","Снизить полную массу до 80 000 фунтов"],"explanation":"Любой груз шире разрешённых 8 футов 6 дюймов требует получения разрешения штата на негабаритный груз от CDOT перед поездкой. Груз шириной 11 футов является негабаритным. Источник: C.R.S. 42-4-502 и 42-4-510; Управление разрешений CDOT."},"13":{"q":"В Колорадо разрешения на негабаритные и перегруженные грузы для движения по системе автомагистралей штата выдаются:","options":["Департаментом доходов Колорадо, Отделом транспортных средств","Управлением разрешений Департамента транспорта Колорадо (CDOT)","Шерифом округа, где начинается поездка","Федеральным управлением безопасности автотранспортных перевозчиков"],"explanation":"Разрешения на негабаритные/перегруженные грузы для системы автомагистралей штата выдаются Управлением разрешений CDOT, как правило, через онлайн-систему COOPR (Colorado Oversize Overweight Permitting and Routing). Источник: C.R.S. 42-4-510; CDOT freight.colorado.gov."},"14":{"q":"Как называется онлайн-система, которую Колорадо использует для того, чтобы перевозчики могли заказывать разрешения на негабаритные/перегруженные грузы и получать утверждённые маршруты?","options":["COOPR (Colorado Oversize Overweight Permitting and Routing)","IRP (International Registration Plan)","PRISM (Performance Registration Information Systems Management)","UCR (Unified Carrier Registration)"],"explanation":"Колорадо выдаёт разрешения на негабаритные/перегруженные грузы через систему COOPR, где перевозчики подают заявки онлайн, оплачивают сборы и получают маршрутизацию; многие разрешения можно оформить самостоятельно. Источник: CDOT, coopr.codot.gov; C.R.S. 42-4-510."},"15":{"q":"По разрешению Колорадо на негабаритный груз рассыпное сено (включая рулонные тюки) можно перевозить шириной до:","options":["8 футов 6 дюймов","10 футов 6 дюймов","12 футов","14 футов"],"explanation":"Закон Колорадо о ширине допускает перевозку рассыпного сена, включая рулонные тюки, шириной до 12 футов; прямоугольное (прессованное) сено ограничено 10 футами 6 дюймами. Источник: C.R.S. 42-4-502 (Ширина транспортных средств)."},"16":{"q":"На автомагистралях Колорадо какова максимальная нагрузка на любое одно колесо транспортного средства со СТАЛЬНЫМИ шинами на дюйм ширины поперечного сечения шины?","options":["300 фунтов на дюйм","500 фунтов на дюйм","650 фунтов на дюйм","800 фунтов на дюйм"],"explanation":"Полная нагрузка на любое одно колесо транспортного средства со стальными шинами не может превышать 500 фунтов на дюйм ширины поперечного сечения шины. Источник: C.R.S. 42-4-507 (Нагрузки на колёса и оси)."},"17":{"q":"На сколько Колорадо разрешает некоторым транспортным средствам на альтернативном топливе превышать стандартные пределы максимальной полной и осевой массы, чтобы учесть более тяжёлую топливную/силовую систему?","options":["До 400 фунтов","До 1 000 фунтов","До 2 000 фунтов","До 5 000 фунтов"],"explanation":"Колорадо разрешает транспортным средствам, работающим на альтернативном топливе, превышать пределы полной и осевой массы до 2 000 фунтов, что соответствует федеральной весовой надбавке для транспортных средств на природном газе/электричестве. Источник: C.R.S. 42-4-508 (Полная масса транспортных средств и грузов)."},"18":{"q":"Когда состав транспортных средств в Колорадо загружен, каждое транспортное средство в составе, как правило, должно нести как минимум какую долю общей полной массы (с ограниченными исключениями для определённых коммунальных прицепов/прицепов для столбов)?","options":["Не менее 5 процентов общей полной массы","Не менее 10 процентов общей полной массы","Не менее 25 процентов общей полной массы","Не менее 50 процентов общей полной массы"],"explanation":"В составе транспортных средств каждое транспортное средство должно нести не менее 10 процентов общей полной массы, за исключением специализированных прицепов, используемых для перевозки фиксированных коммунальных грузов или столбов. Источник: C.R.S. 42-4-508 (Полная масса транспортных средств и грузов)."},"19":{"q":"Сотрудник правопорядка Колорадо, который считает, что транспортное средство перегружено, может потребовать взвешивания транспортного средства водителем и, если транспортное средство превышает разрешённый предел, может потребовать от водителя сделать следующее:","options":["Немедленно сдать коммерческое водительское удостоверение","Выгрузить достаточно груза, чтобы снизить полную массу до разрешённого предела","Оплатить штраф за перегруз наличными на месте перед продолжением движения","Продолжить движение к месту назначения и в течение 24 часов явиться в пункт въезда"],"explanation":"Сотрудник, имеющий основания полагать, что транспортное средство перегружено, может потребовать его взвешивания на переносных или стационарных весах (либо на ближайших общественных весах в пределах пяти миль) и, если оно незаконно перегружено, потребовать от водителя снять достаточно груза, чтобы снизить полную массу до разрешённого предела. Источник: C.R.S. 42-4-509 (Взвешивание транспортных средств — снятие излишка)."},"20":{"q":"В Колорадо какой класс CDL требуется для управления любым составом транспортных средств с полной массой автопоезда (GCWR) 26 001 фунт или более, где буксируемое транспортное средство имеет GVWR свыше 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Колорадо определяет CDL класса A как любой состав транспортных средств с GCWR 26 001 фунт или более при условии, что GVWR буксируемой единицы превышает 10 000 фунтов. Источник: Руководство CDL Колорадо (Colorado DMV/Департамент доходов), определения классов CDL; C.R.S. 42-2-402."},"21":{"q":"Какой класс CDL Колорадо охватывает одиночное транспортное средство с GVWR 26 001 фунт или более, которое может буксировать другое транспортное средство с GVWR не более 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"CDL класса B в Колорадо требуется для любого одиночного транспортного средства с GVWR 26 001 фунт или более, которое может буксировать единицу с GVWR не более 10 000 фунтов. Источник: Руководство CDL Колорадо (Colorado DMV), определения классов."},"22":{"q":"Водитель управляет одиночным транспортным средством с GVWR менее 26 001 фунта, рассчитанным на перевозку 18 пассажиров, включая водителя. Какой класс CDL Колорадо требуется?","options":["CDL не требуется","Класс A","Класс B","Класс C"],"explanation":"CDL класса C охватывает транспортные средства, которые не соответствуют весовым определениям класса A или B, но рассчитаны на перевозку 16 или более пассажиров (включая водителя) либо перевозят опасные материалы, требующие размещения предупреждающих табличек. Источник: Руководство CDL Колорадо (Colorado DMV), определения классов."},"23":{"q":"Какое подтверждение (endorsement) должен получить владелец CDL Колорадо для перевозки опасных материалов в количествах, требующих предупреждающих табличек?","options":["Подтверждение N","Подтверждение T","Подтверждение H","Подтверждение P"],"explanation":"Подтверждение H (Опасные материалы, HazMat) требуется для перевозки опасных материалов, требующих размещения предупреждающих табличек. В Колорадо для него необходимо сдать экзамен по знаниям HazMat, пройти теоретическую подготовку ELDT и пройти оценку угрозы безопасности TSA. Источник: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383."},"24":{"q":"Каков минимальный возраст для получения CDL Колорадо только для вождения внутри штата (intrastate)?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Колорадо разрешает получение CDL с 18 лет только для перевозок внутри штата. Водители в возрасте от 18 до 20 лет получают ограничение «K», ограничивающее их вождением в пределах Колорадо. Источник: Colorado DMV; C.R.S. 42-2-403."},"25":{"q":"Каков минимальный возраст, требуемый для получения CDL Колорадо, действительного для вождения между штатами (interstate)?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Для межштатного коммерческого вождения требуется минимальный возраст 21 год. Водители от 18 до 20 лет имеют CDL с ограничением «K» (только внутри штата). Источник: Colorado DMV; FMCSA 49 CFR 391.11."},"26":{"q":"Согласно федеральным правилам, принятым в Колорадо, как долго необходимо владеть коммерческим ученическим разрешением (CLP), прежде чем владелец получит право сдавать экзамен по навыкам CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 60 дней","Не менее 180 дней"],"explanation":"Владелец CLP не может сдавать экзамен по навыкам CDL до тех пор, пока не пройдёт не менее 14 дней с момента первоначальной выдачи CLP. Источник: FMCSA 49 CFR 383.25, применяется Colorado DMV."},"27":{"q":"Какое подтверждение требуется водителю Колорадо, перевозящему цистерну с жидкостями наливом с суммарной номинальной вместимостью 1 000 галлонов или более?","options":["Подтверждение H","Подтверждение N","Подтверждение T","Подтверждение S"],"explanation":"Подтверждение N (Цистерна) требуется для управления цистерной с ёмкостями индивидуальной номинальной вместимостью свыше 119 галлонов и суммарной номинальной вместимостью 1 000 галлонов или более. Для него необходимо сдать экзамен по знаниям по цистернам. Источник: Colorado DMV CDL Endorsements; 49 CFR 383.5."},"28":{"q":"Водитель Колорадо хочет получить подтверждение T для буксировки двойных или тройных прицепов. Что должен сделать водитель, чтобы его добавить?","options":["Сдать только экзамен по знаниям (письменный)","Сдать экзамен по знаниям и экзамен по навыкам","Пройти проверку биографии TSA","Пройти практическую подготовку ELDT за рулём"],"explanation":"Для подтверждения T (Двойные/тройные прицепы) в Колорадо требуется сдать только экзамен по знаниям по двойным/тройным прицепам; отдельный экзамен по навыкам не требуется. Его можно добавить к CDL класса A. Источник: Colorado DMV CDL Endorsements & Requirements."},"29":{"q":"Какое подтверждение нужно водителю Колорадо для перевозки 16 или более пассажиров (включая водителя) в коммерческом транспортном средстве?","options":["Подтверждение S","Подтверждение N","Подтверждение P","Подтверждение H"],"explanation":"Подтверждение P (Пассажиры) требуется для перевозки 16 или более пассажиров, включая водителя. В Колорадо для него необходимо сдать экзамен по знаниям по пассажирским перевозкам, пройти ELDT и сдать экзамен по навыкам на пассажирском транспортном средстве. Источник: Colorado DMV CDL Endorsements & Requirements."},"30":{"q":"В Колорадо какое подтверждение является обязательным условием, которое необходимо получить вместе (или до) подтверждения для школьного автобуса (S)?","options":["Подтверждение N (Цистерна)","Подтверждение P (Пассажиры)","Подтверждение H (HazMat)","Подтверждение T (Двойные/тройные прицепы)"],"explanation":"Подтверждение P (Пассажиры) является обязательным условием для подтверждения S (Школьный автобус); заявитель не может иметь S без P. Источник: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383.93."},"31":{"q":"Какая организация ведёт реестр, в котором должен быть указан поставщик подготовки водителей начального уровня (ELDT) заявителя на CDL Колорадо?","options":["Департамент образования Колорадо","Реестр поставщиков обучения FMCSA (FMCSA Training Provider Registry)","Дорожный патруль штата Колорадо","Управление транспортной безопасности (TSA)"],"explanation":"ELDT необходимо пройти через поставщика, указанного в Реестре поставщиков обучения FMCSA (TPR); Colorado DMV проверяет завершение через TPR, прежде чем допустить к экзамену по навыкам/знаниям. Источник: FMCSA TPR; Colorado DMV."},"32":{"q":"Для чего из перечисленного ELDT (подготовка водителей начального уровня) состоит только из теоретического обучения, завершаемого до экзамена по знаниям, а не включает практическую подготовку за рулём?","options":["Впервые получаемый CDL класса A","Впервые получаемый CDL класса B","Подтверждение H (HazMat)","Подтверждение P (Пассажиры)"],"explanation":"Для подтверждения H (HazMat) ELDT является только теоретическим и должно быть завершено до сдачи экзамена по знаниям HazMat. Класс A, B, P и S требуют как теоретического, так и практического ELDT за рулём. Источник: FMCSA 49 CFR 380 Subpart F; FMCSA TPR."},"33":{"q":"Перед выдачей или продлением подтверждения HazMat (H) в Колорадо какое дополнительное разрешение должен получить заявитель?","options":["Медицинский отказ DOT","Оценку угрозы безопасности TSA (проверку биографии)","Регистрацию AIM Департамента образования Колорадо","Сертификат проверки SAE уровня 2"],"explanation":"Заявители на подтверждение H должны пройти оценку угрозы безопасности TSA, включающую проверку биографии на основе отпечатков пальцев, перед выдачей или продлением подтверждения. Источник: TSA/FMCSA 49 CFR 1572; Colorado DMV CDL FAQ."},"34":{"q":"При подаче заявления на CDL или CLP Колорадо сколько подтверждений адреса (места жительства) в Колорадо должен предъявить заявитель?","options":["Одно подтверждение адреса","Два подтверждения адреса","Три подтверждения адреса","Подтверждение адреса не требуется"],"explanation":"Colorado DMV требует два документа, подтверждающих адрес в Колорадо, датированных в течение последнего года, в дополнение к подтверждению личности. Источник: Colorado DMV Required Identification Documents."},"35":{"q":"В дополнение к подтверждению личности и места жительства в Колорадо, что ещё должен предоставить заявитель на CDL Колорадо при подаче заявления?","options":["Только паспорт","Подтверждение своего номера социального страхования","Нотариально заверенное письмо от работодателя","Две характеристики"],"explanation":"Колорадо требует от заявителей предъявить карту социального страхования или иное приемлемое подтверждение своего номера социального страхования, наряду с документами, подтверждающими личность и законное присутствие/место жительства. Источник: Colorado DMV Required Identification Documents."},"36":{"q":"Что из перечисленного является одной из четырёх федеральных категорий медицинской самосертификации, из которых должен выбрать владелец CDL Колорадо?","options":["Non-Excepted Interstate","Placarded Interstate","Restricted Intrastate","Conditional Interstate"],"explanation":"Четыре категории самосертификации: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Водитель, на которого распространяются федеральные правила физической пригодности, выбирает Non-Excepted Interstate. Источник: FMCSA 49 CFR 383.71; Colorado DMV."},"37":{"q":"Владелец CDL Колорадо, который водит только в пределах Колорадо, но всё же должен соответствовать стандартам медицинской пригодности, должен самосертифицироваться по какой категории?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Водитель, работающий только в пределах Колорадо, который всё же обязан соответствовать медицинским стандартам, самосертифицируется как Non-Excepted Intrastate (NA). Источник: FMCSA 49 CFR 383.71; категории самосертификации Colorado DMV."},"38":{"q":"Помимо проверки биографии TSA, что должен сделать водитель Колорадо, чтобы добавить подтверждение HazMat (H) к CDL?","options":["Сдать экзамен по знаниям HazMat (письменный)","Сдать только экзамен по навыкам/вождению HazMat","Подать отчёт о проверке двойных/тройных прицепов","Сначала владеть подтверждением в течение одного года на CLP"],"explanation":"Для добавления подтверждения H требуется сдать экзамен по знаниям HazMat (плюс теоретическое ELDT и оценку угрозы безопасности TSA); отдельного экзамена по навыкам HazMat не существует. Источник: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383."},"39":{"q":"Какова максимальная концентрация алкоголя в крови (BAC), допустимая при управлении коммерческим механическим транспортным средством в Колорадо?","options":["0.02","0.04","0.08","0.10"],"explanation":"В Колорадо водитель не вправе управлять CMV с BAC 0.04 или выше — это половина предела 0.08 для некоммерческих водителей. Источник: Руководство CDL Колорадо, Раздел 1 (Дисквалификации); 49 CFR 383.51."},"40":{"q":"Согласно закону Колорадо о подразумеваемом согласии, что происходит, если владелец CDL отказывается пройти химический тест на алкоголь или наркотики?","options":["Выносится предупреждение без дисквалификации","CDL дисквалифицируется на тот же срок, что и за первое серьёзное правонарушение","Назначается только штраф","Удостоверение приостанавливается на 30 дней"],"explanation":"Отказ от обязательного теста рассматривается в Колорадо как серьёзное правонарушение, влекущее дисквалификацию на 1 год (3 года при перевозке опасных материалов, требующих предупреждающих табличек) — так же, как за первое нарушение DUI/BAC. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51; C.R.S. 42-2-126."},"41":{"q":"За первое серьёзное правонарушение, такое как управление CMV с BAC 0.04 или выше, на какой срок дисквалифицируется владелец CDL Колорадо (когда НЕ перевозит опасные материалы, требующие предупреждающих табличек)?","options":["60 дней","6 месяцев","1 год","3 года"],"explanation":"Первое серьёзное правонарушение влечёт дисквалификацию CDL на 1 год в Колорадо. Источник: Руководство CDL Колорадо, Раздел 1 (Дисквалификации); 49 CFR 383.51."},"42":{"q":"На какой срок дисквалифицируется водитель за первое серьёзное правонарушение, если в момент нарушения он перевозил опасные материалы, требующие предупреждающих табличек?","options":["1 год","2 года","3 года","5 лет"],"explanation":"Первое серьёзное правонарушение при перевозке опасных материалов, требующих предупреждающих табличек, повышает срок дисквалификации до 3 лет в Колорадо. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"43":{"q":"Какова дисквалификация за второе серьёзное правонарушение (например, второе DUI), совершённое владельцем CDL Колорадо?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Второе серьёзное правонарушение влечёт пожизненную дисквалификацию CDL в Колорадо, хотя восстановление может быть возможно через 10 лет при определённых условиях. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"44":{"q":"Что из перечисленного классифицируется как «серьёзное правонарушение» для владельца CDL Колорадо?","options":["Слишком близкое следование за впереди идущим транспортным средством","Оставление места происшествия с участием CMV","Превышение скорости на 15 mph сверх предела","Неправильная смена полосы движения"],"explanation":"Оставление места происшествия является серьёзным правонарушением (дисквалификация 1 год за первое / пожизненно за второе). Остальные варианты являются серьёзными нарушениями ПДД, а не серьёзными правонарушениями. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"45":{"q":"Использование коммерческого механического транспортного средства для совершения тяжкого преступления (felony) рассматривается по правилам CDL Колорадо как:","options":["Серьёзное нарушение ПДД","Серьёзное правонарушение","Нарушение предписания о выводе из эксплуатации","Нарушение на железнодорожном переезде"],"explanation":"Использование CMV при совершении тяжкого преступления является серьёзным правонарушением, влекущим дисквалификацию на 1 год за первое осуждение и пожизненно за второе. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"46":{"q":"К какой дисквалификации CDL в Колорадо приводит первое осуждение за любое серьёзное нарушение ПДД?","options":["Без дисквалификации","30 дней","60 дней","120 дней"],"explanation":"Одно серьёзное нарушение ПДД само по себе не дисквалифицирует водителя; дисквалификация начинается только со второго или третьего такого нарушения в течение 3 лет. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"47":{"q":"На какой срок дисквалифицируется владелец CDL Колорадо за ВТОРОЕ серьёзное нарушение ПДД, совершённое в течение 3-летнего периода?","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения ПДД в течение 3 лет влекут дисквалификацию на 60 дней. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"48":{"q":"На какой срок дисквалифицируется водитель за ТРЕТЬЕ серьёзное нарушение ПДД в течение 3-летнего периода?","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет влекут дисквалификацию на 120 дней. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"49":{"q":"При каком превышении установленного предела скорости нарушение скоростного режима считается «серьёзным нарушением ПДД» для владельца CDL Колорадо?","options":["На 10 mph или более сверх предела","На 15 mph или более сверх предела","На 20 mph или более сверх предела","На 25 mph или более сверх предела"],"explanation":"Превышение скорости на 15 mph или более сверх установленного предела является серьёзным нарушением ПДД. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"50":{"q":"Что из перечисленного НЕ считается серьёзным нарушением ПДД для владельца CDL Колорадо?","options":["Опасное вождение (reckless driving)","Слишком близкое следование","Управление CMV с BAC 0.04","Беспорядочная или неправильная смена полос движения"],"explanation":"Управление с BAC 0.04 или выше является серьёзным правонарушением, а не серьёзным нарушением ПДД. Опасное вождение, слишком близкое следование и неправильная смена полос являются серьёзными нарушениями ПДД. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"51":{"q":"Отправка текстовых сообщений или использование ручного мобильного телефона при вождении CMV на регулярной основе классифицируется по правилам CDL Колорадо как:","options":["Серьёзное правонарушение","Серьёзное нарушение ПДД","Нарушение предписания о выводе из эксплуатации","Не влекущее дисквалификации нарушение"],"explanation":"Отправка текстовых сообщений или использование ручного телефона при вождении CMV является серьёзным нарушением ПДД; несколько осуждений в течение 3 лет влекут дисквалификацию на 60/120 дней. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51, 392.80/392.82."},"52":{"q":"Закон Колорадо 2025 года о вождении без рук (SB24-065) в целом запрещает использование ручных устройств, но как он применяется к водителям CDL, управляющим CMV?","options":["Водители CDL освобождены, поскольку более строгие федеральные правила уже запрещают использование ручного телефона","Он полностью заменяет федеральное правило для водителей CMV","Он не применяется ни к одному водителю в Колорадо","Он разрешает водителям CMV отправлять текстовые сообщения, если они остановились на светофоре"],"explanation":"Водители CMV освобождены от закона штата о вождении без рук, поскольку более строгое федеральное правило (действующее с 2012 года) уже запрещает любое использование ручного телефона и отправку текстовых сообщений при вождении CMV. Источник: Colorado SB24-065; FMCSA 49 CFR 392.80/392.82."},"53":{"q":"Согласно федеральному правилу, применяемому к водителям CMV в Колорадо, каков максимальный штраф для водителя за отправку текстовых сообщений или использование ручного телефона при вождении CMV?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Водителям грозят гражданские штрафы до $2,750 (сумма $11,000 применяется к работодателям). Источник: FMCSA Mobile Phone/No-Texting rule, 49 CFR 392.80/392.82."},"54":{"q":"Какова минимальная дисквалификация CDL за ПЕРВОЕ нарушение на железнодорожном переезде в одном уровне в Колорадо?","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде влечёт минимальную дисквалификацию на 60 дней. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"55":{"q":"ВТОРОЕ нарушение на железнодорожном переезде в одном уровне в течение 3 лет влечёт какую минимальную дисквалификацию CDL?","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт минимальную дисквалификацию на 120 дней. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"56":{"q":"ТРЕТЬЕ или последующее нарушение на железнодорожном переезде в одном уровне в течение 3 лет влечёт какую минимальную дисквалификацию?","options":["120 дней","180 дней","1 год","3 года"],"explanation":"Три или более нарушения на железнодорожном переезде в течение 3 лет влекут минимальную дисквалификацию на 1 год. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"57":{"q":"Каков диапазон дисквалификации за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (OOS) водителем CDL Колорадо, НЕ перевозящим опасные материалы или пассажиров?","options":["От 30 до 60 дней","Только 90 дней","От 180 дней до 1 года","От 2 до 5 лет"],"explanation":"Первое нарушение предписания о выводе из эксплуатации влечёт дисквалификацию от 180 дней до 1 года для водителя, не перевозящего опасные материалы или пассажиров. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"58":{"q":"ВТОРОЕ нарушение предписания о выводе из эксплуатации в течение 10 лет (без опасных материалов, без пассажиров) влечёт какой диапазон дисквалификации?","options":["От 120 дней до 6 месяцев","От 180 дней до 1 года","От 2 до 5 лет","Пожизненно"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет влечёт дисквалификацию от 2 до 5 лет. Источник: Руководство CDL Колорадо, Раздел 1; 49 CFR 383.51."},"59":{"q":"Согласно закону Колорадо «Сбавь скорость, перестройся» (Slow Down, Move Over), что обязан сделать водитель CMV при приближении к неподвижному эвакуатору с мигающими янтарными/жёлтыми огнями на шоссе с двумя полосами в одном направлении?","options":["Продолжать движение с разрешённой скоростью, но подать звуковой сигнал","Перестроиться в полосу, удалённую как минимум на одну полосу движения от неподвижного транспортного средства","Полностью остановиться, пока эвакуатор не отъедет","Съехать на правую обочину и проехать медленно"],"explanation":"Закон Колорадо «Перестройся» (Move Over, CRS 42-4-705) требует от водителей на шоссе как минимум с двумя полосами в одном направлении уступать дорогу, перестраиваясь в полосу, удалённую как минимум на одну полосу движения от неподвижного аварийного, эвакуирующего или коммунального транспортного средства с мигающими огнями. Источник: Colorado CDL Manual / CRS 42-4-705."},"60":{"q":"На шоссе Колорадо с разрешённой скоростью 65 mph водитель CMV не может безопасно сменить полосу из-за плотного движения, чтобы объехать остановившийся патрульный автомобиль. Какую скорость CRS 42-4-705 презюмирует безопасной?","options":["65 mph, поскольку перестроиться было невозможно","45 mph (на 20 mph ниже разрешённой) презюмируется безопасной","25 mph независимо от установленного ограничения","Полную остановку, пока полоса не освободится"],"explanation":"Закон Колорадо «Перестройся» (Move Over, CRS 42-4-705) предусматривает, что когда водитель не может перестроиться, на дорогах с ограничением 45 mph или выше безопасной презюмируется скорость на 20 mph ниже разрешённой (здесь 45 mph), а на дорогах ниже 45 mph безопасной презюмируется скорость 25 mph или меньше. Источник: CRS 42-4-705."},"61":{"q":"Когда в Колорадо включены сигналы остановки школьного автобуса, на каком минимальном расстоянии до автобуса должен остановиться приближающийся водитель?","options":["10 feet","15 feet","20 feet","50 feet"],"explanation":"CRS 42-4-1903 требует, чтобы водитель, встречающий или обгоняющий остановившийся школьный автобус с включёнными красными визуальными сигнальными огнями, остановился как минимум за 20 feet до автобуса и не продолжал движение, пока огни не будут выключены. Источник: Colorado CDL Manual / CRS 42-4-1903."},"62":{"q":"Согласно закону Колорадо о школьных автобусах, когда водитель НЕ обязан останавливаться перед школьным автобусом, который загружает или высаживает детей с мигающими красными огнями?","options":["Всякий раз, когда водитель движется со скоростью менее 25 mph","Когда автобус находится на другой проезжей части шоссе, разделённого на отдельные проезжие части","Когда в направлении движения водителя более одной полосы","Всякий раз, когда автобус находится в деловом районе"],"explanation":"CRS 42-4-1903 устанавливает, что водитель на шоссе с раздельными проезжими частями не обязан останавливаться при встрече или проезде школьного автобуса, находящегося на другой проезжей части. На неразделённой дороге транспорт в ОБОИХ направлениях обязан остановиться. Источник: CRS 42-4-1903."},"63":{"q":"Водитель в Колорадо, перевозящий опасные грузы с табличками (placards), приближается к железнодорожному переезду. В пределах какого расстояния от ближайшего рельса должно остановиться транспортное средство?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 100 feet, но не ближе 50 feet","В пределах 25 feet, но не ближе 10 feet","В пределах 75 feet, но не ближе 25 feet"],"explanation":"CRS 42-4-707 требует, чтобы транспортные средства с табличками опасного груза, школьные автобусы, перевозящие школьников, и коммерческие транспортные средства, перевозящие пассажиров, останавливались в пределах 50 feet, но не ближе 15 feet от ближайшего рельса, затем смотрели и прислушивались перед продолжением движения. Источник: Colorado CDL Manual / CRS 42-4-707."},"64":{"q":"Когда CMV с табличками в Колорадо пересекает железнодорожные пути после остановки, какое дополнительное ограничение применяется согласно CRS 42-4-707?","options":["Водитель должен пересекать переезд задним ходом, а затем передним, чтобы проверить сцепление","Водитель не должен вручную переключать передачи во время пересечения путей","Водитель должен включить аварийную сигнализацию на протяжении всего переезда","Водитель должен пересекать переезд только со скоростью менее 5 mph"],"explanation":"CRS 42-4-707 предписывает водителю пересекать переезд только если нет необходимости переключать передачи во время проезда, и запрещает вручную переключать передачи во время пересечения путей, снижая риск заглохнуть на рельсах. Источник: CRS 42-4-707."},"65":{"q":"На каком типе железнодорожного переезда закон Колорадо НЕ требует от водителя транспортного средства с табличками или автобуса делать обязательную остановку?","options":["На любом переезде без автоматических шлагбаумов","На переезде, регулируемом сотрудником полиции или регулировщиком, направляющим движение","На любом переезде в жилом районе","На переезде с двумя или более комплектами путей"],"explanation":"CRS 42-4-707 освобождает от обязательной остановки там, где движение направляет сотрудник полиции или регулировщик, где движение регулируется светофором, на переездах трамвайных путей в деловом районе и на переездах, обозначенных официальным знаком «exempt» (освобождён). Источник: CRS 42-4-707."},"66":{"q":"Каково максимальное ограничение скорости на четырёхполосном шоссе Колорадо с покрытием, входящем в систему межштатных автомагистралей, при отсутствии иного установленного ограничения?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"CRS 42-4-1101 устанавливает 65 mph на четырёхполосных шоссе с покрытием в системе межштатных автомагистралей как законодательный максимум (CDOT может устанавливать более высокие или более низкие ограничения на конкретных участках). Источник: CRS 42-4-1101."},"67":{"q":"Как закон Колорадо трактует ограничение скорости для крупных грузовиков по сравнению с легковыми автомобилями на том же шоссе?","options":["У грузовиков есть отдельное общештатное ограничение на 10 mph ниже, чем у легковых автомобилей","Грузовики должны держаться на 15 mph ниже установленного ограничения на уклонах","Грузовики соблюдают то же установленное ограничение; в Колорадо нет общего отдельного ограничения скорости для грузовиков","Грузовики ограничены 55 mph по всему штату независимо от установленных знаков"],"explanation":"Закон Колорадо о скорости (CRS 42-4-1101) не устанавливает отдельного, более низкого общештатного ограничения скорости для грузовиков по классу или весу; CMV соблюдают те же установленные ограничения, что и другие транспортные средства. Источник: CRS 42-4-1101."},"68":{"q":"Согласно CRS 42-4-1101, какое предполагаемое (prima facie) ограничение скорости действует на «открытом горном шоссе» (open mountain highway) в Колорадо?","options":["30 mph","40 mph","50 mph","55 mph"],"explanation":"CRS 42-4-1101 указывает 40 mph на открытых горных шоссе (и 20 mph на узких, извилистых горных шоссе или слепых поворотах) среди предполагаемых (prima facie) ограничений. Источник: CRS 42-4-1101."},"69":{"q":"Закон Колорадо 2024 года о грузовых полосах запрещает грузовикам массой 16,000 lbs и более движение по крайней левой полосе на определённых горных участках I-70. Какой из перечисленных участков является одной из таких обозначенных зон?","options":["Monument Hill на I-25","Vail Pass","Raton Pass на I-25","Развязка Grand Junction"],"explanation":"Ограничение Колорадо на крайнюю левую полосу запрещает грузовикам массой 16,000 lbs и тяжелее движение по крайней левой полосе на участках I-70, включая Floyd Hill, Georgetown Hill, тоннель Eisenhower, Dowd Junction и Vail Pass, где в одном направлении не менее трёх полос. Источник: CDOT / закон Колорадо 2024 года (SB24-100)."},"70":{"q":"На участках I-70, где Колорадо ограничивает движение тяжёлых грузовиков по крайней левой полосе, какое исключение допускает закон?","options":["Грузовики могут использовать левую полосу при слабом движении","Грузовики могут использовать крайнюю левую полосу для обгона другого транспортного средства","Грузовики могут использовать левую полосу только ночью","Никаких исключений ни при каких условиях нет"],"explanation":"Ограничение Колорадо на крайнюю левую полосу для грузовиков на обозначенных горных участках I-70 всё же позволяет грузовикам использовать крайнюю левую полосу при обгоне; запрет нацелен на длительное движение по левой полосе. Источник: CDOT / закон Колорадо 2024 года (SB24-100)."},"71":{"q":"Закон Колорадо об обязательном наличии цепей для коммерческих транспортных средств (Commercial Vehicle Chain «Must-Carry») требует, чтобы CMV возили цепи на горном коридоре I-70 в течение какого ежегодного периода?","options":["С 1 октября по 30 апреля","С 1 сентября по 31 мая","С 1 ноября по 31 марта","Круглый год, без сезонного окна"],"explanation":"Закон Колорадо об обязательном наличии цепей требует, чтобы коммерческие транспортные средства (GVWR 16,001 lbs и более) возили достаточное количество цепей с 1 сентября по 31 мая на I-70 между Dotsero (MP 133) и Morrison (MP 259). Источник: CDOT / CRS 42-4-106."},"72":{"q":"Когда действует закон Колорадо о цепях для коммерческих транспортных средств (Commercial Vehicle Chain Law), как должен быть оснащён CMV с четырьмя или более ведущими колёсами, чтобы продолжить движение?","options":["Цепи или ATD как минимум на четырёх ведущих колёсах","Цепи только на управляемых (передних) колёсах","Цепи на любых двух колёсах по выбору водителя","Шин с зимней маркировкой всегда достаточно"],"explanation":"Когда закон о цепях действует, CMV должен иметь цепи или альтернативные устройства сцепления (ATD) как минимум на четырёх ведущих колёсах (или на всех ведущих колёсах, если их меньше четырёх). Источник: CDOT Chain Law / CRS 42-4-106."},"73":{"q":"Горный коридор I-70, где действует закон Колорадо о цепях для коммерческих транспортных средств (Commercial Vehicle Chain Law), проходит между какими двумя точками?","options":["Grand Junction (MP 26) и Denver (MP 275)","Dotsero (MP 133) и Morrison (MP 259)","Glenwood Springs (MP 116) и Golden (MP 263)","Vail (MP 176) и Idaho Springs (MP 240)"],"explanation":"Требование Колорадо о цепях/обязательном их наличии для коммерческих транспортных средств действует на I-70 между съездом Dotsero (Milepost 133) и съездом Morrison (Milepost 259). Источник: CDOT / CRS 42-4-106."},"74":{"q":"На межштатной автомагистрали Колорадо, после остановки CMV на проезжей части, в пределах скольких футов водитель должен разместить три предупреждающих устройства в сторону приближающегося транспорта на ровной, прямой дороге?","options":["На 5, 50 и 100 feet","На 10, 100 и 200 feet","На 25, 150 и 300 feet","На 50, 250 и 500 feet"],"explanation":"Колорадо следует федеральному стандарту FMCSR, требующему размещения предупреждающих устройств на 10 feet, 100 feet и 200 feet от остановившегося CMV в сторону приближающегося транспорта на неразделённой, ровной дороге. Источник: Colorado CDL Manual / 49 CFR 392.22 (принят в Колорадо)."},"75":{"q":"CMV в Колорадо вынужден остановиться на дороге сразу за крутым поворотом, который скрывает его от приближающегося транспорта. Как следует скорректировать размещение предупреждающих устройств?","options":["Разместить все три в пределах 10 feet от заднего бампера","Перенести устройство в сторону поворота на 100–500 feet назад, чтобы дать достаточное предупреждение","Не ставить задние устройства и обозначить флажком только перёд","Разместить все три на осевой линии рядом с кабиной"],"explanation":"При остановке в пределах 500 feet от поворота, вершины холма или иного препятствия обзору водитель переносит предупреждающее устройство в направлении препятствия так, чтобы оно находилось в 100–500 feet от транспортного средства для достаточного предупреждения. Источник: Colorado CDL Manual / 49 CFR 392.22."},"76":{"q":"Самую загруженную в Колорадо аварийную тормозную полосу (runaway truck ramp), расположенную на западном направлении I-70 рядом с тоннелем Eisenhower, лучше всего описать как какое устройство?","options":["Гравийный улавливающий слой, использующий глубокий слой рыхлого заполнителя для остановки неуправляемого грузовика","Стальная тросовая сеть, натянутая поперёк полосы","Заполненный водой амортизирующий буфер в нижней части уклона","Магнитная тормозная полоса, встроенная в покрытие"],"explanation":"Полоса Lower Straight Creek на западном направлении I-70 — самая используемая аварийная тормозная полоса в США; как и другие улавливающие слои в Колорадо, она использует глубокий слой рыхлого дроблёного заполнителя (округлого камня) для рассеивания энергии неуправляемого грузовика. Источник: CDOT / раздел Colorado CDL Manual о горном вождении."},"77":{"q":"Какова максимальная допустимая по закону ШИРИНА транспортного средства на шоссе Колорадо, прежде чем потребуется разрешение на негабарит от CDOT?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Допустимая по закону ширина в Колорадо составляет 8 feet 6 inches (102 inches); грузы, превышающие её, требуют разрешения CDOT на негабарит, а при ширине более 11 feet, как правило, требуется передний автомобиль сопровождения (pilot/escort) на обозначенных шоссе штата. Источник: CDOT Freight & Permitting / CRS 42-4-502."},"78":{"q":"На горном уклоне в Колорадо какую правильную технику торможения должен использовать водитель CMV, чтобы избежать необходимости в аварийной тормозной полосе?","options":["Удерживать рабочие тормоза нажатыми постоянно на протяжении всего спуска","Выбрать низкую передачу перед спуском и использовать лёгкие, прерывистые нажатия на тормоз","Переключиться на нейтраль для экономии топлива и катиться вниз накатом","Постоянно применять ручной кран прицепа на высокой передаче"],"explanation":"Руководство Colorado CDL Manual по горному вождению предписывает водителям выбирать безопасную низкую передачу ПЕРЕД началом длинного спуска и использовать тормоза прерывисто (snub braking), чтобы тормоза не перегревались и не теряли эффективность; катиться накатом на нейтрали незаконно и опасно. Источник: Colorado CDL Manual (Mountain Driving)."},"79":{"q":"Какое ведомство Колорадо выдаёт коммерческие водительские удостоверения (CDL) и проводит обязательные тесты на знание?","options":["Департамент транспорта Колорадо (CDOT)","Департамент доходов Колорадо, Отдел регистрации транспортных средств (DMV)","Отдел пунктов въезда Дорожного патруля штата Колорадо","Федеральное управление по безопасности автоперевозок (FMCSA)"],"explanation":"В Колорадо CDL выдаются Отделом регистрации транспортных средств (DMV) Департамента доходов; тесты на знание сдаются в полносервисном офисе DMV/Motor Vehicle. Источник: Colorado DMV, dmv.colorado.gov (First-time CDL Driver / CDL General Information)."},"80":{"q":"Каков минимальный проходной балл на тесте Colorado CDL General Knowledge, который содержит 50 вопросов?","options":["70% (как минимум 35 из 50 верных)","75% (как минимум 38 из 50 верных)","90% (как минимум 45 из 50 верных)","80% (как минимум 40 из 50 верных)"],"explanation":"Тест Colorado CDL General Knowledge содержит 50 вопросов и требует 80% — как минимум 40 верных — для прохождения, что соответствует Colorado CDL Manual и стандартам тестирования DMV. Источник: Colorado DMV / Colorado CDL Manual."},"81":{"q":"Тест навыков Colorado CDL состоит из трёх частей. В каком наборе правильно перечислены эти три части?","options":["Письменный тест на знание, предрейсовый осмотр и вождение по дороге","Проверка пневматических тормозов, параллельная парковка и тест по дорожным знакам","Базовое управление транспортным средством, проверка на HazMat и вождение по дороге","Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге"],"explanation":"Тест навыков CDL в Колорадо состоит из трёх частей: предрейсовый осмотр, базовое управление транспортным средством (маневры) и тест вождения по дороге, что отражает федеральную структуру теста навыков CDL, принятую Колорадо. Источник: Colorado CDL Manual; Colorado DMV."},"82":{"q":"Прежде чем впервые подающий заявление на CDL в Колорадо сможет сдать тест навыков, какое федерально предписанное обучение должно быть завершено и подтверждено?","options":["Курс безопасного вождения, одобренный Дорожным патрулём штата Колорадо","Семинар CDOT по креплению негабаритных/перегруженных грузов","Начальное обучение водителей (ELDT) у провайдера, зарегистрированного в FMCSA","Аудиторный инструктаж по безопасности от Департамента доходов"],"explanation":"С 7 февраля 2022 года Колорадо требует прохождения Начального обучения водителей (ELDT) у зарегистрированного в FMCSA провайдера (с записью в Training Provider Registry), прежде чем новый заявитель, заявитель на повышение класса или на новую отметку H/P/S сможет сдать тест навыков. Источник: Colorado DMV; 49 CFR Part 380 / FMCSA TPR."},"83":{"q":"Как долго действует Коммерческое ученическое разрешение Колорадо (CLP) и можно ли его продлить?","options":["Действует 180 дней и продлевается один раз","Действует 60 дней и продлевается дважды","Действует пять лет и продлевается ежегодно","Действует один год и не подлежит продлению"],"explanation":"CLP в Колорадо действует один год и НЕ подлежит продлению; если он истекает до получения CDL, заявитель должен повторно сдать тест(ы) на знание для нового CLP. Источник: Colorado DMV (CDL General Information / First-time CDL Driver)."},"84":{"q":"После того как заявителю в Колорадо выдано Коммерческое ученическое разрешение, как долго его необходимо иметь, прежде чем можно будет сдать тест навыков CDL?","options":["Как минимум 30 календарных дней","Как минимум 7 календарных дней","Как минимум 14 календарных дней","Как минимум 60 календарных дней"],"explanation":"Колорадо следует федеральному правилу, согласно которому CLP должно находиться у держателя как минимум 14 календарных дней, прежде чем он сможет сдать тест навыков CDL. Источник: 49 CFR 383.25; Colorado DMV."},"85":{"q":"Заявители на CDL в Колорадо должны заполнить самосертификацию, декларирующую тип их вождения. Сколько существует категорий самосертификации?","options":["Две","Три","Пять","Четыре"],"explanation":"Существует четыре категории самосертификации: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate и Excepted Intrastate. В Колорадо это декларируется в форме DR 2904/DR 2907. Источник: форма Colorado DMV DR 2904; 49 CFR 383.71."},"86":{"q":"Водитель в Колорадо, осуществляющий межштатные перевозки и обязанный соответствовать требованиям квалификации водителя по 49 CFR Part 391 (и поэтому обязанный иметь при себе медицинское свидетельство), должен пройти самосертификацию по какой категории?","options":["Excepted Interstate","Non-excepted Intrastate","Excepted Intrastate","Non-excepted Interstate"],"explanation":"Водитель, осуществляющий межштатные перевозки, который подпадает под требования квалификации 49 CFR Part 391 и соответствует им — и обязан иметь свидетельство медицинского эксперта — проходит самосертификацию как Non-excepted Interstate. Источник: форма Colorado DMV DR 2904; 49 CFR 383.71."},"87":{"q":"Чтобы выполнить медицинское требование DOT, какой документ должен получить и предоставить заявитель на CDL в Колорадо?","options":["Справку от терапевта общей практики, подтверждающую хорошее состояние здоровья","Карту медицинского допуска Дорожного патруля штата Колорадо","Свидетельство медицинского эксперта (Medical Examiner's Certificate) от провайдера из National Registry FMCSA","Медицинский отказ (waiver) по разрешению CDOT"],"explanation":"Большинство держателей CDL в Колорадо должны получить Свидетельство медицинского эксперта (медицинскую карту DOT) от эксперта, внесённого в FMCSA National Registry of Certified Medical Examiners. Источник: Colorado DMV (CDL DOT Medical); FMCSA National Registry."},"88":{"q":"Для типичного водителя CDL категории non-excepted в Колорадо, каков максимальный срок действия Свидетельства медицинского эксперта DOT?","options":["До двух лет","До пяти лет","До одного года","До трёх лет"],"explanation":"Свидетельство медицинского эксперта DOT выдаётся на срок максимум два года (и может быть короче, если эксперт отмечает состояние, требующее наблюдения). Водитель должен хранить действующее свидетельство в досье в Colorado DMV. Источник: 49 CFR 391.43; Colorado DMV (CDL DOT Medical)."},"89":{"q":"Если самосертифицированный водитель CDL категории non-excepted в Колорадо допускает истечение срока медицинского свидетельства, хранящегося в досье DMV, каково обычное последствие?","options":["CDL немедленно и навсегда аннулируется","CDL понижается, так что коммерческие привилегии снимаются до тех пор, пока не будет подано действующее медицинское свидетельство","Ничего не происходит до пятилетнего продления CDL","Водитель автоматически переклассифицируется как Excepted Interstate"],"explanation":"Если срок медицинского свидетельства водителя категории non-excepted истекает и действующее не предоставлено, Колорадо понижает удостоверение, снимая привилегии коммерческого вождения до тех пор, пока действующее свидетельство не будет в досье. Источник: Colorado DMV (CDL DOT Medical); 49 CFR 383.73."},"90":{"q":"Каков минимальный возраст для выдачи CDL в Колорадо для МЕЖШТАТНОГО коммерческого вождения или для перевозки опасных грузов с табличками?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Колорадо следует федеральному минимуму: водителю должен быть 21 год для осуществления межштатных перевозок или для перевозки опасных грузов с табличками. Водители 18–20 лет ограничены внутриштатными перевозками. Источник: Colorado DMV; 49 CFR 383."},"91":{"q":"Держатель CDL в Колорадо в возрасте от 18 до 20 лет ограничен вождением только в пределах Колорадо. Какой код ограничения удостоверения отражает этот лимит «только внутри штата»?","options":["Ограничение «K» (только внутри штата)","Ограничение «L» (без пневматических тормозов)","Ограничение «Z» (без полных пневматических тормозов)","Ограничение «E» (без механической коробки передач)"],"explanation":"Колорадо применяет ограничение «K» (только внутри штата) к держателям CDL, которые не могут осуществлять межштатные перевозки, включая водителей в возрасте 18–20 лет. Источник: Colorado DMV (CDL Restrictions)."},"92":{"q":"Какой набор документов должен предъявить в DMV впервые подающий заявление на CDL в Колорадо?","options":["Только действующее обычное водительское удостоверение Колорадо","Подтверждение личности, подтверждение законного пребывания в США, подтверждение номера Social Security и подтверждение проживания в Колорадо","Паспорт и разрешение CDOT на груз","Только письмо от работодателя и две фотографии на паспорт"],"explanation":"Заявители на CDL в Колорадо должны подтвердить личность, законное пребывание в США, номер Social Security и адрес проживания в Колорадо (например, счёт за коммунальные услуги или выписку из банка). Источник: Colorado DMV (First-time CDL Driver)."},"93":{"q":"Как DMV подтверждает завершение ELDT заявителем на CDL в Колорадо, прежде чем разрешить тест навыков?","options":["Заявитель отправляет бумажный сертификат по почте в CDOT для утверждения","Заявитель приносит нотариально заверенное письменное показание от инструктора","Провайдер электронно сообщает об этом в FMCSA Training Provider Registry, который проверяет DMV","Дорожный патруль штата Колорадо выдаёт письмо о допуске ELDT"],"explanation":"Зарегистрированные в FMCSA провайдеры ELDT подают записи о завершении в федеральный Training Provider Registry (TPR); DMV Колорадо проверяет запись электронно, прежде чем разрешить тест навыков. Источник: Colorado DMV; FMCSA TPR / 49 CFR Part 380."},"94":{"q":"В правильном порядке, каковы первые три основных шага для впервые подающего заявление на CDL в Колорадо?","options":["Сдать тест навыков, затем получить CLP, затем завершить ELDT","Сдать тест(ы) на знание и получить CLP, затем завершить ELDT, затем сдать тест навыков","Завершить ELDT, затем сдать тест навыков, затем сдать тест на знание","Получить медицинскую карту, затем сдать тест навыков, затем сдать тест на знание"],"explanation":"Последовательность в Колорадо такова: сдать необходимый(е) тест(ы) на знание и получить CLP, завершить одобренное FMCSA ELDT (теория и практика за рулём), затем сдать трёхчастный тест навыков (после 14-дневного срока удержания CLP). Источник: Colorado DMV (First-time CDL Driver)."},"95":{"q":"Во время дорожной части теста навыков Colorado CDL, что главным образом оценивает экзаменатор?","options":["Способность заявителя безопасно управлять транспортным средством в реальном движении по заданному маршруту","Может ли заявитель пересказать содержание руководства CDL","Только скорость параллельной парковки заявителя","Соответствие транспортного средства лимитам разрешения на негабарит/перегруз"],"explanation":"Дорожный тест оценивает безопасное управление в реальном движении по заранее определённому маршруту — повороты, перекрёстки, смену полос и общее вождение. Движение задним ходом/маневры оцениваются в отдельной части базового управления. Источник: Colorado CDL Manual; Colorado DMV."},"96":{"q":"Водитель в Колорадо перевозит только сельскохозяйственные товары исключительно в пределах Колорадо и освобождён от части требований штата по квалификации водителя. Какая категория самосертификации подходит этому водителю?","options":["Excepted Intrastate","Non-excepted Interstate","Excepted Interstate","Non-excepted Intrastate"],"explanation":"Водитель, осуществляющий перевозки только в пределах Колорадо и освобождённый полностью или частично от требований штата по квалификации водителя, проходит самосертификацию как Excepted Intrastate и, как правило, не обязан подавать медицинское свидетельство DOT. Источник: форма Colorado DMV DR 2904; 49 CFR 383.71."},"97":{"q":"Относительно сборов за CDL в Колорадо, какое утверждение наиболее точно для учебного пособия?","options":["Тестирование на знание и навыки CDL в Колорадо всегда бесплатно","Сборы навсегда зафиксированы федеральным законом и никогда не меняются","Конкретные суммы сборов устанавливаются штатом и могут меняться, поэтому заявителям следует уточнять текущие сборы в DMV","Сбор взимается только за медицинский осмотр; DMV ничего не взимает за удостоверение"],"explanation":"Колорадо взимает сборы за тестирование и выдачу CDL, но точные суммы устанавливаются штатом и могут изменяться; заявителям следует уточнять текущие сборы в DMV, а не полагаться на фиксированную цифру. Источник: Colorado DMV (CDL General Information / fee schedule)."}},"tr":{"0":{"q":"Colorado karayollarında, standart bir ticari aracın (aynalar ve zorunlu güvenlik donanımları hariç) oversize izni gerekmeden önceki yasal maksimum genişliği nedir?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"Colorado, araç genişliğini 8 feet 6 inches (102 inches) ile sınırlar. Konum lambaları, dikiz aynaları ve diğer zorunlu aksesuarlar bu sınıra dahil edilmez. Kaynak: C.R.S. 42-4-502 (Araç genişliği)."},"1":{"q":"Colorado karayollarında yüklü veya yüksüz bir aracın yasal maksimum yüksekliği nedir?","options":["13 feet 6 inches","14 feet 0 inches","14 feet 6 inches","15 feet 0 inches"],"explanation":"Bir sürücü, yüksüz veya yüklü olarak 14 feet 6 inches yüksekliği aşan bir aracı kullanamaz. Kaynak: C.R.S. 42-4-504 (Araçların yüksekliği ve uzunluğu)."},"2":{"q":"Colorado yasalarına göre, tek bir motorlu aracın (ön ve arka tamponlar dahil) maksimum toplam uzunluğu nedir?","options":["40 feet","45 feet","53 feet","60 feet"],"explanation":"Hiçbir tek motorlu araç, ön ve arka tamponlar dahil olmak üzere toplam uzunlukta 45 feet'i aşamaz. Kaynak: C.R.S. 42-4-504 (Araçların yüksekliği ve uzunluğu)."},"3":{"q":"Colorado karayollarında birbirine bağlı bir araç kombinasyonunun (özel izin olmadan) maksimum toplam uzunluğu nedir?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"Hiçbir araç kombinasyonu toplam uzunlukta 70 feet'i aşamaz ve bir kombinasyon en fazla dört birimden oluşabilir. Kaynak: C.R.S. 42-4-504 (Araçların yüksekliği ve uzunluğu)."},"4":{"q":"Colorado'da, pnömatik lastiklerle donatılmış tek bir aksa izin verilen maksimum ağırlık nedir?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,000 pounds"],"explanation":"Tek bir aks üzerindeki tekerlekler pnömatik lastiklerle donatıldığında, maksimum yük 20,000 pounds'tur. Kaynak: C.R.S. 42-4-507 (Tekerlek ve aks yükleri)."},"5":{"q":"Colorado INTERSTATE (eyaletler arası) bir karayolunda çalışan bir tandem aks grubuna izin verilen maksimum ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Interstate sisteminde Colorado, 36,000 pounds'luk federal tandem aks sınırını uygular. (Interstate olmayan eyalet karayollarında tandem sınırı 40,000 pounds'tur.) Kaynak: C.R.S. 42-4-507 (Tekerlek ve aks yükleri)."},"6":{"q":"Interstate olmayan bir Colorado eyalet karayolunda, bir tandem aks grubuna izin verilen maksimum ağırlık nedir?","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"Interstate olmayan eyalet karayollarında Colorado, bir tandem aks üzerinde 40,000 pounds'a kadar izin verir; bu, 36,000 pounds'luk interstate sınırından daha yüksektir. Kaynak: C.R.S. 42-4-507 (Tekerlek ve aks yükleri)."},"7":{"q":"Colorado'da INTERSTATE sisteminde aşırı yük izni olmadan izin verilen maksimum brüt araç ağırlığı nedir?","options":["76,000 pounds","80,000 pounds","85,000 pounds","90,000 pounds"],"explanation":"Interstate karayollarında Colorado, federal köprü formülüyle yönetilen 80,000 pounds'luk federal maksimum brüt ağırlığı uygular. Kaynak: C.R.S. 42-4-508 (Araçların ve yüklerin brüt ağırlığı)."},"8":{"q":"Colorado'da INTERSTATE olmayan (eyalet ve yerel) karayollarında, eyalet ağırlık tablosuna göre, izin olmadan izin verilen maksimum brüt araç ağırlığı nedir?","options":["80,000 pounds","82,000 pounds","85,000 pounds","90,000 pounds"],"explanation":"Interstate olmayan karayollarında Colorado'nun kendi brüt ağırlık tablosu, 80,000 pounds'luk interstate üst sınırını aşan 85,000 pounds'a kadar izin verir. Kaynak: C.R.S. 42-4-508 (Araçların ve yüklerin brüt ağırlığı)."},"9":{"q":"Colorado, ağırlık amaçları için bir 'tandem aks'ı nasıl tanımlar?","options":["40 inches'tan fazla ve 96 inches'tan fazla olmayan aralıklarla yerleştirilmiş iki veya daha fazla ardışık aks","Tam olarak 48 inches aralıkla yerleştirilmiş iki aks","40 inches'tan daha az aralıkla yerleştirilmiş herhangi iki aks","96 inches'tan fazla aralıkla yerleştirilmiş üç veya daha fazla aks"],"explanation":"Bir tandem aks, merkezleri 40 inches'tan fazla ve 96 inches'tan fazla olmayan aralıkta birbirine paralel dikey düzlemler arasına düşen, aracın tüm genişliği boyunca uzanan iki veya daha fazla ardışık akstır. Kaynak: C.R.S. 42-4-507 (Tekerlek ve aks yükleri)."},"10":{"q":"Colorado, interstate sisteminde aks aralığına dayalı olarak izin verilen maksimum brüt ağırlığı belirlemek için hangi formülü kullanır?","options":["Eyalet kilometre vergisi formülü","Federal köprü formülü (bridge gross weight formula)","Yalnızca inch başına lastik genişliği formülü","Aks aralığı olmayan sabit 80,000 pounds'luk düz kural"],"explanation":"Interstate karayollarında Colorado, izin verilen ağırlığı aks sayısı ve en uç akslar arasındaki mesafeyle ilişkilendiren ve 80,000 pounds ile sınırlanan federal köprü formülünü kullanarak aks grubu başına brüt ağırlığı sınırlar. Kaynak: C.R.S. 42-4-508; federal 23 CFR 658 (köprü formülü)."},"11":{"q":"Colorado'nun genel (interstate olmayan) brüt ağırlık formülü W = 1,000(L + 40)'ta 'L' neyi temsil eder?","options":["Araçtaki aks sayısı","Ton cinsinden toplam yük ağırlığı","İlk ve son aksların merkezleri arasındaki feet cinsinden mesafe","Treylerin yasal uzunluğu"],"explanation":"Colorado'nun interstate olmayan brüt ağırlık formülü W = 1,000(L + 40)'ta 'L', grubun ilk ve son aksının merkezleri arasındaki feet cinsinden mesafedir ve W, pounds cinsinden maksimum brüt ağırlıktır, 85,000 pounds'u aşmayacaktır. Kaynak: C.R.S. 42-4-508 (Araçların ve yüklerin brüt ağırlığı)."},"12":{"q":"Colorado eyalet karayolunda 11 feet genişliğinde bir yük taşıyan bir sürücü aşağıdakilerden hangisini yapmalıdır?","options":["Hiçbir şey; 11 feet yasal genişlik sınırı içindedir","Yük 8 feet 6 inches'ı aştığı için CDOT oversize izni almalıdır","Yalnızca bir bayrak göstermeli, izin gerekmez","Brüt ağırlığı 80,000 pounds'a düşürmelidir"],"explanation":"Yasal 8 feet 6 inches'tan daha geniş herhangi bir yük, seyahatten önce CDOT'tan eyalet oversize izni gerektirir. 11 feet genişliğindeki bir yük oversize'dır. Kaynak: C.R.S. 42-4-502 ve 42-4-510; CDOT İzin Ofisi."},"13":{"q":"Colorado'da, eyalet karayolu sistemindeki seyahat için oversize ve overweight izinleri kim tarafından verilir?","options":["Colorado Department of Revenue, Motorlu Taşıtlar Bölümü","Colorado Department of Transportation (CDOT) İzin Ofisi","Yolculuğun başladığı ilçenin şerifi","Federal Motor Carrier Safety Administration"],"explanation":"Eyalet karayolu sistemi için oversize/overweight izinleri, genellikle çevrimiçi COOPR (Colorado Oversize Overweight Permitting and Routing) sistemi aracılığıyla CDOT İzin Ofisi tarafından verilir. Kaynak: C.R.S. 42-4-510; CDOT freight.colorado.gov."},"14":{"q":"Colorado'nun taşıyıcıların oversize/overweight izinleri sipariş etmesi ve onaylanmış rotalar alması için kullandığı çevrimiçi sistemin adı nedir?","options":["COOPR (Colorado Oversize Overweight Permitting and Routing)","IRP (International Registration Plan)","PRISM (Performance Registration Information Systems Management)","UCR (Unified Carrier Registration)"],"explanation":"Colorado, oversize/overweight izinlerini, taşıyıcıların çevrimiçi başvuru yaptığı, ücretleri ödediği ve rota aldığı COOPR sistemi aracılığıyla verir; birçok izin sürücü tarafından kendi kendine verilebilir. Kaynak: CDOT, coopr.codot.gov; C.R.S. 42-4-510."},"15":{"q":"Colorado oversize izni kapsamında, gevşek saman (yuvarlak balyalar dahil) hangi genişliğe kadar taşınabilir?","options":["8 feet 6 inches","10 feet 6 inches","12 feet","14 feet"],"explanation":"Colorado'nun genişlik tüzüğü, yuvarlak balyalar dahil gevşek samanın 12 feet genişliğe kadar taşınmasına izin verir; dikdörtgen (balyalanmış) saman 10 feet 6 inches ile sınırlıdır. Kaynak: C.R.S. 42-4-502 (Araç genişliği)."},"16":{"q":"Colorado karayollarında, ÇELİK lastikli bir aracın herhangi bir tekerleğinde, lastiğin kesit genişliğinin inch'i başına maksimum ağırlık nedir?","options":["300 pounds per inch","500 pounds per inch","650 pounds per inch","800 pounds per inch"],"explanation":"Çelik lastikli bir aracın herhangi bir tekerleğindeki brüt ağırlık, lastiğin kesit genişliğinin inch'i başına 500 pounds'u aşamaz. Kaynak: C.R.S. 42-4-507 (Tekerlek ve aks yükleri)."},"17":{"q":"Colorado, daha ağır yakıt/güç sistemini hesaba katmak için bazı alternatif yakıtlı araçların standart maksimum brüt ve aks ağırlık sınırlarını ne kadar aşmasına izin verir?","options":["400 pounds'a kadar","1,000 pounds'a kadar","2,000 pounds'a kadar","5,000 pounds'a kadar"],"explanation":"Colorado, alternatif yakıtla çalışan araçların, federal doğal gaz/elektrikli araç ağırlık toleransıyla tutarlı olarak, brüt ve aks ağırlık sınırlarını 2,000 pounds'a kadar aşmasına izin verir. Kaynak: C.R.S. 42-4-508 (Araçların ve yüklerin brüt ağırlığı)."},"18":{"q":"Bir Colorado araç kombinasyonu yüklendiğinde, kombinasyondaki her araç genellikle toplam brüt ağırlığın en az ne kadarlık payını taşımalıdır (bazı yardımcı/direk treylerleri için sınırlı istisnalarla)?","options":["Toplam brüt ağırlığın en az yüzde 5'i","Toplam brüt ağırlığın en az yüzde 10'u","Toplam brüt ağırlığın en az yüzde 25'i","Toplam brüt ağırlığın en az yüzde 50'si"],"explanation":"Bir araç kombinasyonunda, sabit yardımcı yükleri veya direkleri taşımak için kullanılan özel treylerler hariç, her araç toplam brüt ağırlığın en az yüzde 10'unu taşımalıdır. Kaynak: C.R.S. 42-4-508 (Araçların ve yüklerin brüt ağırlığı)."},"19":{"q":"Bir aracın aşırı yüklü olduğuna inanan bir Colorado kolluk görevlisi, sürücünün tartılmasını isteyebilir ve araç yasal sınırın üzerindeyse sürücüden ne yapmasını isteyebilir?","options":["Ticari sürücü ehliyetini derhal teslim etmesini","Brüt ağırlığı yasal sınıra düşürecek kadar kargoyu boşaltmasını","Devam etmeden önce aşırı yük cezasını yerinde nakit ödemesini","Hedefe devam etmesini ve 24 saat içinde bir giriş noktasına rapor vermesini"],"explanation":"Bir aracın aşırı yüklü olduğuna inanmak için nedeni olan bir görevli, aracın taşınabilir veya sabit kantarlarda (veya beş mil içindeki yakın halka açık kantarlarda) tartılmasını isteyebilir ve araç yasadışı şekilde aşırı yüklüyse, sürücüden brüt ağırlığı yasal sınıra düşürecek kadar yükü çıkarmasını isteyebilir. Kaynak: C.R.S. 42-4-509 (Araçların tartılması - fazlalığın çıkarılması)."},"20":{"q":"Colorado'da, çekilen aracın GVWR'si 10,000 pounds'un üzerinde olduğu durumlarda, Gross Combination Weight Rating (GCWR) 26,001 pounds veya daha fazla olan herhangi bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Colorado, Class A CDL'yi, çekilen birimin GVWR'sinin 10,000 lbs'yi aşması koşuluyla, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: Colorado CDL Manual (Colorado DMV/Dept. of Revenue), CDL sınıf tanımları; C.R.S. 42-2-402."},"21":{"q":"Hangi Colorado CDL sınıfı, GVWR'si 26,001 pounds veya daha fazla olan ve GVWR'si 10,000 pounds'u aşmayan başka bir aracı çekebilen tek bir aracı kapsar?","options":["Class A","Class B","Class C","Class M"],"explanation":"Colorado'da Class B CDL, GVWR'si 26,001 lbs veya daha fazla olan ve GVWR'si 10,000 lbs'yi aşmayan bir birimi çekebilen herhangi bir tek araç için gereklidir. Kaynak: Colorado CDL Manual (Colorado DMV), sınıf tanımları."},"22":{"q":"Bir sürücü, GVWR'si 26,001 pounds'un altında olan ve sürücü dahil 18 yolcu taşıyacak şekilde tasarlanmış tek bir aracı kullanıyor. Hangi Colorado CDL sınıfı gereklidir?","options":["CDL gerekmez","Class A","Class B","Class C"],"explanation":"Class C CDL, Class A veya B ağırlık tanımlarını karşılamayan ancak (sürücü dahil) 16 veya daha fazla yolcu taşıyacak şekilde tasarlanmış ya da plakart gerektiren tehlikeli maddeler taşıyan araçları kapsar. Kaynak: Colorado CDL Manual (Colorado DMV), sınıf tanımları."},"23":{"q":"Bir Colorado CDL sahibinin plakart gerektiren miktarlarda tehlikeli madde taşıması için hangi onayı (endorsement) alması gerekir?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"Plakart gerektiren tehlikeli maddeleri taşımak için H (Hazardous Materials) onayı gereklidir. Colorado'da bu, HazMat bilgi testini geçmeyi, ELDT teorisini tamamlamayı ve bir TSA güvenlik tehdidi değerlendirmesini geçmeyi gerektirir. Kaynak: Colorado DMV CDL Onayları ve Gereksinimleri; 49 CFR 383."},"24":{"q":"Yalnızca eyalet içi (intrastate) sürüş için bir Colorado CDL almak için minimum yaş nedir?","options":["16 yaşında","18 yaşında","19 yaşında","21 yaşında"],"explanation":"Colorado, yalnızca eyalet içi (intrastate) çalışma için 18 yaşında CDL'ye izin verir. 18 ila 20 yaş arasındaki sürücüler, kendilerini Colorado içinde sürmekle sınırlayan bir 'K' kısıtlaması alırlar. Kaynak: Colorado DMV; C.R.S. 42-2-403."},"25":{"q":"Eyaletler arası (interstate, eyalet sınırlarını aşan) sürüş için geçerli bir Colorado CDL almak için gereken minimum yaş nedir?","options":["18 yaşında","19 yaşında","21 yaşında","25 yaşında"],"explanation":"Eyaletler arası ticari sürüş, minimum 21 yaş gerektirir. 18 ila 20 yaş arasındaki sürücüler, 'K' kısıtlaması (yalnızca eyalet içi) olan bir CDL'ye sahiptir. Kaynak: Colorado DMV; FMCSA 49 CFR 391.11."},"26":{"q":"Colorado'da benimsenen federal kurallara göre, sahibinin CDL beceri testine girme hakkı kazanmadan önce bir Commercial Learner Permit (CLP) ne kadar süre elde tutulmalıdır?","options":["En az 14 days","En az 30 days","En az 60 days","En az 180 days"],"explanation":"Bir CLP sahibi, CLP'nin ilk verilişinden bu yana en az 14 days geçene kadar CDL beceri testine giremez. Kaynak: FMCSA 49 CFR 383.25, Colorado DMV tarafından uygulanır."},"27":{"q":"Toplam nominal kapasitesi 1,000 gallons veya daha fazla olan sıvıları dökme halinde taşıyan bir tank aracı kullanan bir Colorado sürücüsü için hangi onay gereklidir?","options":["H endorsement","N endorsement","T endorsement","S endorsement"],"explanation":"N (Tank Vehicle) onayı, bireysel nominal kapasitesi 119 gallons'un üzerinde ve toplam nominal kapasitesi 1,000 gallons veya daha fazla olan tanklara sahip bir tank aracını kullanmak için gereklidir. Tanker bilgi testini geçmeyi gerektirir. Kaynak: Colorado DMV CDL Onayları; 49 CFR 383.5."},"28":{"q":"Bir Colorado sürücüsü, çift veya üçlü treyler çekmek için T onayını istiyor. Sürücünün bunu eklemek için ne yapması gerekir?","options":["Yalnızca bir bilgi (yazılı) testini geçmek","Bir bilgi testi ve bir beceri testini geçmek","Bir TSA arka plan kontrolünü geçmek","Direksiyon başında ELDT eğitimini tamamlamak"],"explanation":"T (Doubles/Triples) onayı, Colorado'da yalnızca çift/üçlü bilgi testini geçmeyi gerektirir; ayrı bir beceri testi gerekmez. Bir Class A CDL'ye eklenebilir. Kaynak: Colorado DMV CDL Onayları ve Gereksinimleri."},"29":{"q":"Bir Colorado sürücüsünün ticari bir araçta (sürücü dahil) 16 veya daha fazla yolcu taşıması için hangi onaya ihtiyacı vardır?","options":["S endorsement","N endorsement","P endorsement","H endorsement"],"explanation":"P (Passenger) onayı, sürücü dahil 16 veya daha fazla yolcu taşımak için gereklidir. Colorado'da bu, yolcu bilgi testini, ELDT'yi ve bir yolcu aracında beceri testini gerektirir. Kaynak: Colorado DMV CDL Onayları ve Gereksinimleri."},"30":{"q":"Colorado'da, School Bus (S) onayıyla birlikte (veya ondan önce) alınması gereken bir önkoşul onay hangisidir?","options":["N (Tanker) endorsement","P (Passenger) endorsement","H (HazMat) endorsement","T (Doubles/Triples) endorsement"],"explanation":"P (Passenger) onayı, S (School Bus) onayı için bir önkoşuldur; bir başvuru sahibi P olmadan S'ye sahip olamaz. Kaynak: Colorado DMV CDL Onayları ve Gereksinimleri; 49 CFR 383.93."},"31":{"q":"Bir Colorado CDL başvuru sahibinin Entry-Level Driver Training (ELDT) sağlayıcısının listelenmesi gereken kaydı hangi kuruluş tutar?","options":["Colorado Department of Education","FMCSA Training Provider Registry","Colorado State Patrol","Transportation Security Administration"],"explanation":"ELDT, FMCSA Training Provider Registry'de (TPR) listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır; Colorado DMV, beceri/bilgi testine izin vermeden önce tamamlanmayı TPR aracılığıyla doğrular. Kaynak: FMCSA TPR; Colorado DMV."},"32":{"q":"Aşağıdakilerden hangisi için ELDT (Entry-Level Driver Training), direksiyon başında eğitimi içermek yerine, bilgi testinden önce tamamlanan yalnızca teorik eğitimden oluşur?","options":["İlk kez Class A CDL","İlk kez Class B CDL","H (HazMat) endorsement","P (Passenger) endorsement"],"explanation":"H (HazMat) onayı için ELDT yalnızca teoriktir ve HazMat bilgi testine girmeden önce tamamlanmalıdır. Class A, B, P ve S hem teori hem de direksiyon başında ELDT gerektirir. Kaynak: FMCSA 49 CFR 380 Subpart F; FMCSA TPR."},"33":{"q":"Bir Colorado HazMat (H) onayı verilmeden veya yenilenmeden önce, başvuru sahibinin ek olarak hangi onayı alması gerekir?","options":["Bir DOT tıbbi muafiyeti","Bir TSA Security Threat Assessment (arka plan kontrolü)","Bir Colorado Department of Education AIM kaydı","Bir SAE Level 2 muayene sertifikası"],"explanation":"H onayı için başvuranlar, onay verilmeden veya yenilenmeden önce, parmak izine dayalı arka plan kontrollerini içeren bir TSA Security Threat Assessment'ı geçmelidir. Kaynak: TSA/FMCSA 49 CFR 1572; Colorado DMV CDL SSS."},"34":{"q":"Bir Colorado CDL veya CLP için başvururken, başvuru sahibinin kaç adet Colorado adres (ikamet) kanıtı sunması gerekir?","options":["Bir adres kanıtı","İki adres kanıtı","Üç adres kanıtı","Adres kanıtı gerekmez"],"explanation":"Colorado DMV, kimlik kanıtına ek olarak, son bir yıl içinde tarihlenmiş, Colorado adresini kanıtlayan iki belge gerektirir. Kaynak: Colorado DMV Gerekli Kimlik Belgeleri."},"35":{"q":"Kimlik ve Colorado ikamet kanıtına ek olarak, bir Colorado CDL başvuru sahibinin başvuru sırasında başka neyi sağlaması gerekir?","options":["Yalnızca bir pasaport","Social Security numaralarının kanıtı","Noter onaylı bir işveren mektubu","İki karakter referansı"],"explanation":"Colorado, başvuru sahiplerinin kimlik ve yasal mevcudiyet/ikamet belgeleriyle birlikte Social Security kartlarını veya Social Security numaralarının diğer kabul edilebilir kanıtını sunmasını gerektirir. Kaynak: Colorado DMV Gerekli Kimlik Belgeleri."},"36":{"q":"Aşağıdakilerden hangisi, bir Colorado CDL sahibinin seçmesi gereken dört federal tıbbi öz-sertifikasyon kategorisinden biridir?","options":["Non-Excepted Interstate","Placarded Interstate","Restricted Intrastate","Conditional Interstate"],"explanation":"Dört öz-sertifikasyon kategorisi: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Federal fiziksel yeterlilik kurallarına tabi olan bir sürücü, Non-Excepted Interstate'i seçer. Kaynak: FMCSA 49 CFR 383.71; Colorado DMV."},"37":{"q":"Yalnızca Colorado içinde sürüş yapan ancak yine de tıbbi yeterlilik standartlarını karşılaması gereken bir Colorado CDL sahibi, hangi kategori altında öz-sertifikasyon yapmalıdır?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Yalnızca Colorado içinde çalışan ve yine de tıbbi standartları karşılaması gereken bir sürücü, Non-Excepted Intrastate (NA) olarak öz-sertifikasyon yapar. Kaynak: FMCSA 49 CFR 383.71; Colorado DMV öz-sertifikasyon kategorileri."},"38":{"q":"TSA arka plan kontrolünün ötesinde, bir Colorado sürücüsünün bir CDL'ye HazMat (H) onayı eklemek için ne yapması gerekir?","options":["Bir HazMat bilgi (yazılı) testini geçmek","Yalnızca bir HazMat beceri/yol testini geçmek","Bir çift/üçlü muayene raporu sunmak","Önce bir CLP üzerinde onayı bir yıl elde tutmak"],"explanation":"H onayı eklemek, HazMat bilgi testini geçmeyi (artı ELDT teorisi ve bir TSA Security Threat Assessment) gerektirir; ayrı bir HazMat beceri testi yoktur. Kaynak: Colorado DMV CDL Onayları ve Gereksinimleri; 49 CFR 383."},"39":{"q":"Colorado'da ticari bir motorlu aracı kullanırken izin verilen maksimum kan alkol konsantrasyonu (BAC) nedir?","options":["0.02","0.04","0.08","0.10"],"explanation":"Colorado'da bir sürücü, ticari olmayan sürücüler için 0.08 sınırının yarısı olan 0.04 veya daha yüksek bir BAC ile bir CMV kullanamaz. Kaynak: Colorado CDL Manual, Section 1 (Diskalifiyeler); 49 CFR 383.51."},"40":{"q":"Colorado'nun zımni rıza (implied-consent) yasasına göre, bir CDL sahibi alkol veya uyuşturucu için kimyasal bir testi yapmayı reddederse ne olur?","options":["Diskalifiye olmaksızın bir uyarı verilir","CDL, ilk büyük suçla aynı süre boyunca diskalifiye edilir","Yalnızca bir para cezası uygulanır","Ehliyet 30 gün süreyle askıya alınır"],"explanation":"Gerekli testi reddetmek, Colorado'da büyük bir suç olarak ele alınır ve 1 yıllık diskalifiye (plakart gerektiren tehlikeli maddeler taşınıyorsa 3 yıl) taşır - ilk DUI/BAC ihlaliyle aynıdır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51; C.R.S. 42-2-126."},"41":{"q":"0.04 veya daha yüksek bir BAC ile bir CMV kullanmak gibi ilk büyük suç için, bir Colorado CDL sahibi (plakart gerektiren tehlikeli maddeler taşımıyorken) ne kadar süre diskalifiye edilir?","options":["60 days","6 ay","1 yıl","3 yıl"],"explanation":"İlk büyük suç, Colorado'da 1 yıllık CDL diskalifiyesiyle sonuçlanır. Kaynak: Colorado CDL Manual, Section 1 (Diskalifiyeler); 49 CFR 383.51."},"42":{"q":"Sürücü o sırada plakart gerektiren tehlikeli maddeler taşıyorsa, ilk büyük suç için diskalifiye süresi ne kadardır?","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"Plakart gerektiren tehlikeli maddeler taşırken işlenen ilk büyük suç, Colorado'da diskalifiyeyi 3 yıla yükseltir. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"43":{"q":"Bir Colorado CDL sahibi tarafından işlenen ikinci bir büyük suç (örneğin ikinci bir DUI) için diskalifiye süresi ne kadardır?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"İkinci bir büyük suç, Colorado'da ömür boyu CDL diskalifiyesiyle sonuçlanır, ancak belirli koşullar altında 10 yıl sonra yeniden ehliyet alınması mümkün olabilir. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"44":{"q":"Aşağıdakilerden hangisi bir Colorado CDL sahibi için 'büyük suç' olarak sınıflandırılır?","options":["Öndeki araca çok yakın takip etmek","Bir CMV'nin karıştığı bir kaza yerini terk etmek","Limitin 15 mph üzerinde hız yapmak","Uygunsuz şerit değiştirme"],"explanation":"Bir kaza yerini terk etmek büyük bir suçtur (ilk için 1 yıl / ikinci için ömür boyu diskalifiye). Diğer seçenekler büyük suçlar değil, ciddi trafik ihlalleridir. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"45":{"q":"Bir suç işlemek için ticari bir motorlu araç kullanmak, Colorado CDL kuralları kapsamında ne olarak ele alınır?","options":["Ciddi trafik ihlali","Büyük suç","Hizmet dışı (out-of-service) ihlali","Demiryolu geçidi ihlali"],"explanation":"Bir suçun işlenmesinde bir CMV kullanmak büyük bir suçtur ve ilk mahkumiyet için 1 yıllık ve ikincisi için ömür boyu diskalifiye taşır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"46":{"q":"Herhangi bir ciddi trafik ihlali için ilk mahkumiyet, Colorado'da hangi CDL diskalifiyesiyle sonuçlanır?","options":["Diskalifiye yok","30 days","60 days","120 days"],"explanation":"Tek bir ciddi trafik ihlali, kendi başına bir sürücüyü diskalifiye etmez; diskalifiye yalnızca 3 yıl içinde ikinci veya üçüncü böyle bir ihlalle başlar. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"47":{"q":"Bir Colorado CDL sahibi, 3 yıllık bir süre içinde işlenen İKİNCİ bir ciddi trafik ihlali için ne kadar süre diskalifiye edilir?","options":["30 days","60 days","120 days","1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, 60 günlük diskalifiyeyle sonuçlanır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"48":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir ciddi trafik ihlali için diskalifiye süresi ne kadardır?","options":["60 days","90 days","120 days","1 yıl"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, 120 günlük diskalifiyeyle sonuçlanır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"49":{"q":"Bir hız ihlali, bir Colorado CDL sahibi için belirtilen limitin üzerinde hangi hızda 'ciddi trafik ihlali' olarak sayılır?","options":["10 mph veya daha fazla üzerinde","15 mph veya daha fazla üzerinde","20 mph veya daha fazla üzerinde","25 mph veya daha fazla üzerinde"],"explanation":"Belirtilen hız limitinin 15 mph veya daha fazla üzerinde hız yapmak ciddi bir trafik ihlalidir. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"50":{"q":"Aşağıdakilerden hangisi bir Colorado CDL sahibi için ciddi trafik ihlali olarak SAYILMAZ?","options":["Dikkatsiz sürüş","Çok yakın takip etmek","0.04 BAC ile bir CMV kullanmak","Düzensiz veya uygunsuz şerit değişiklikleri"],"explanation":"0.04 veya daha yüksek bir BAC ile sürmek, ciddi bir trafik ihlali değil, büyük bir suçtur. Dikkatsiz sürüş, çok yakın takip etmek ve uygunsuz şerit değişiklikleri ciddi trafik ihlalleridir. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"51":{"q":"Bir CMV kullanırken tekrar tekrar mesaj atmak veya elde tutulan bir cep telefonu kullanmak, Colorado CDL kuralları kapsamında ne olarak kategorize edilir?","options":["Büyük suç","Ciddi trafik ihlali","Hizmet dışı (out-of-service) ihlali","Diskalifiye etmeyen ihlal"],"explanation":"Bir CMV kullanırken mesaj atmak veya elde tutulan bir telefon kullanmak ciddi bir trafik ihlalidir; 3 yıl içinde birden fazla mahkumiyet 60/120 günlük diskalifiyeleri tetikler. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51, 392.80/392.82."},"52":{"q":"Colorado'nun 2025 eller serbest eyalet yasası (SB24-065), genel olarak elde tutulan cihaz kullanımını yasaklar, ancak bir CMV kullanan CDL sürücülerine nasıl uygulanır?","options":["CDL sürücüleri muaftır çünkü daha katı federal kurallar zaten elde tutulan telefon kullanımını yasaklar","CMV sürücüleri için federal kuralı tamamen değiştirir","Colorado'da hiçbir sürücüye uygulanmaz","CMV sürücülerinin ışıkta durduklarında mesaj atmasına izin verir"],"explanation":"CMV sürücüleri eyalet eller serbest yasasından muaftır çünkü daha katı olan federal kural (2012'den beri yürürlükte), bir CMV kullanırken herhangi bir elde tutulan telefon kullanımını ve mesaj atmayı zaten yasaklamaktadır. Kaynak: Colorado SB24-065; FMCSA 49 CFR 392.80/392.82."},"53":{"q":"Colorado CMV sürücülerine uygulanan federal kurala göre, bir CMV kullanırken mesaj atmak veya elde tutulan bir telefon kullanmak için maksimum sürücü para cezası nedir?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Sürücüler $2,750'ye kadar idari para cezalarıyla karşı karşıya kalır ($11,000 rakamı işverenler için geçerlidir). Kaynak: FMCSA Cep Telefonu/Mesaj Yasağı kuralı, 49 CFR 392.80/392.82."},"54":{"q":"Colorado'da İLK demiryolu karayolu hemzemin geçit ihlali için minimum CDL diskalifiyesi nedir?","options":["30 days","60 days","120 days","1 yıl"],"explanation":"İlk demiryolu geçidi ihlali, minimum 60 günlük diskalifiye taşır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"55":{"q":"3 yıl içinde İKİNCİ bir demiryolu hemzemin geçit ihlali hangi minimum CDL diskalifiyesiyle sonuçlanır?","options":["60 days","90 days","120 days","1 yıl"],"explanation":"3 yıl içinde ikinci bir demiryolu geçidi ihlali, minimum 120 günlük diskalifiye taşır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"56":{"q":"3 yıl içinde ÜÇÜNCÜ veya sonraki bir demiryolu hemzemin geçit ihlali hangi minimum diskalifiyeyle sonuçlanır?","options":["120 days","180 days","1 yıl","3 yıl"],"explanation":"3 yıl içinde üç veya daha fazla demiryolu geçidi ihlali, minimum 1 yıllık diskalifiye taşır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"57":{"q":"Tehlikeli madde veya yolcu taşımayan bir Colorado CDL sürücüsünün bir hizmet dışı (OOS) emrini İLK ihlali için diskalifiye aralığı nedir?","options":["30 ila 60 days","Yalnızca 90 days","180 days ila 1 yıl","2 ila 5 yıl"],"explanation":"İlk hizmet dışı emir ihlali, tehlikeli madde veya yolcu taşımayan bir sürücü için 180 days ila 1 yıllık diskalifiyeyle sonuçlanır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"58":{"q":"10 yıl içinde İKİNCİ bir hizmet dışı emir ihlali (tehlikeli madde olmayan, yolcu olmayan) hangi diskalifiye aralığıyla sonuçlanır?","options":["120 days ila 6 ay","180 days ila 1 yıl","2 ila 5 yıl","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir hizmet dışı emir ihlali, 2 ila 5 yıllık diskalifiye taşır. Kaynak: Colorado CDL Manual, Section 1; 49 CFR 383.51."},"59":{"q":"Colorado'nun 'Yavaşla, Şeritten Çekil' (Slow Down, Move Over) yasasına göre, aynı yönde iki şeridi bulunan bir otoyolda yanıp sönen sarı/amber ışıkları açık duran sabit bir çekici kamyona yaklaşan bir ticari motorlu araç (CMV) sürücüsü ne yapmalıdır?","options":["Belirlenen hızda devam et, ancak korna çal","Sabit araçtan en az bir hareketli şerit uzakta bir şeride geç","Çekici uzaklaşana kadar tamamen dur","Sağ banket üzerine geç ve yavaşça geçiş yap"],"explanation":"Colorado'nun Şeritten Çekil yasası (CRS 42-4-705), aynı yönde en az iki şeridi olan bir otoyoldaki sürücülerin, yanıp sönen ışıkları açık olan sabit bir acil durum, çekici veya kamu hizmeti aracından en az bir hareketli şerit uzakta bir şeride geçerek yol vermelerini gerektirir. Kaynak: Colorado CDL Manual / CRS 42-4-705."},"60":{"q":"65 mph hız sınırı belirlenmiş bir Colorado otoyolunda, bir CMV sürücüsü yoğun trafik nedeniyle durmuş bir devriye aracı için güvenli bir şekilde şerit değiştiremiyor. CRS 42-4-705 hangi hızı güvenli olarak varsayar?","options":["Şeritten çekilmek imkansız olduğundan 65 mph","45 mph (belirlenen sınırın 20 mph altı) güvenli olarak varsayılır","Belirlenen sınıra bakılmaksızın 25 mph","Şerit boşalana kadar tamamen durmak"],"explanation":"Colorado'nun Şeritten Çekil yasası (CRS 42-4-705), bir sürücü şerit değiştiremediğinde, 45 mph veya daha yüksek hız belirlenmiş yollarda belirlenen sınırın 20 mph altındaki bir hızın (burada 45 mph) güvenli olarak varsayıldığını, 45 mph altındaki yollarda ise 25 mph veya daha düşük bir hızın güvenli olarak varsayıldığını öngörür. Kaynak: CRS 42-4-705."},"61":{"q":"Colorado okul otobüsü durma sinyalleri devreye girdiğinde, yaklaşan bir sürücü otobüse ulaşmadan önce en az ne kadar mesafede durmalıdır?","options":["10 fit","15 fit","20 fit","50 fit"],"explanation":"CRS 42-4-1903, kırmızı görsel sinyal ışıkları devrede olan durmuş bir okul otobüsüyle karşılaşan veya onu sollayan bir sürücünün, otobüse ulaşmadan en az 20 fit önce durmasını ve ışıklar devreden çıkana kadar ilerlememesini gerektirir. Kaynak: Colorado CDL Manual / CRS 42-4-1903."},"62":{"q":"Colorado okul otobüsü yasasına göre, kırmızı ışıkları yanıp sönerek çocukları bindiren veya indiren bir okul otobüsü için bir sürücünün durmasının gerekmediği durum nedir?","options":["Sürücü 25 mph altında seyahat ediyorsa her zaman","Otobüs, ayrı yollara bölünmüş bir otoyolun farklı bir yolundayken","Sürücünün yönünde birden fazla şerit olduğunda","Otobüs bir ticari bölge içindeyken her zaman"],"explanation":"CRS 42-4-1903, ayrı yolları olan bir otoyoldaki bir sürücünün, farklı bir yolda bulunan bir okul otobüsüyle karşılaştığında veya onu geçtiğinde durmasının gerekmediğini belirtir. Bölünmemiş bir yolda, HER İKİ yöndeki trafik de durmalıdır. Kaynak: CRS 42-4-1903."},"63":{"q":"Plakartlanmış tehlikeli madde taşıyan bir Colorado sürücüsü bir demiryolu hemzemin geçidine yaklaşır. Araç en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["50 fit içinde ancak 15 fitten az olmamak üzere","100 fit içinde ancak 50 fitten az olmamak üzere","25 fit içinde ancak 10 fitten az olmamak üzere","75 fit içinde ancak 25 fitten az olmamak üzere"],"explanation":"CRS 42-4-707, plakartlanmış tehlikeli madde araçlarının, okul çocuklarını taşıyan okul otobüslerinin ve yolcu taşıyan ticari araçların en yakın raydan 50 fit içinde ancak 15 fitten az olmamak üzere durmasını, ardından ilerlemeden önce bakıp dinlemesini gerektirir. Kaynak: Colorado CDL Manual / CRS 42-4-707."},"64":{"q":"Plakartlanmış bir Colorado CMV'si durduktan sonra demiryolu raylarını geçerken, CRS 42-4-707 uyarınca hangi ek kısıtlama geçerlidir?","options":["Sürücü, çekiş testi için önce geri sonra ileri giderek geçmelidir","Sürücü, rayları geçerken manuel olarak vites değiştirmemelidir","Sürücü, geçişin tamamı boyunca dörtlü flaşörleri yakmalıdır","Sürücü, geçişi yalnızca 5 mph altında bir hızla yapmalıdır"],"explanation":"CRS 42-4-707, sürücünün geçişi yalnızca geçiş sırasında vites değiştirmeye gerek olmaması durumunda yapmasını ve rayların üzerinde durup kalma riskini azaltmak için rayları geçerken manuel olarak vites değiştirmemesini öngörür. Kaynak: CRS 42-4-707."},"65":{"q":"Colorado yasası, plakartlanmış bir araç veya otobüs sürücüsünün zorunlu durmayı yapmasını hangi tür demiryolu geçidinde GEREKTİRMEZ?","options":["Otomatik bariyerleri olmayan herhangi bir geçit","Bir polis memuru veya trafiği yönlendiren insan işaretçi tarafından kontrol edilen bir geçit","Bir yerleşim bölgesindeki herhangi bir geçit","İki veya daha fazla ray grubu olan bir geçit"],"explanation":"CRS 42-4-707, bir polis memuru veya insan işaretçinin trafiği yönlendirdiği, bir trafik kontrol sinyalinin trafiği yönlendirdiği, bir ticari bölgedeki sokak demiryolu geçitlerinde ve resmi bir 'muaf' (exempt) işaretiyle işaretlenmiş geçitlerde zorunlu durmayı muaf tutar. Kaynak: CRS 42-4-707."},"66":{"q":"Farklı bir hız sınırı belirtilmediği takdirde, eyaletler arası sistemin bir parçası olan kaplamalı, dört şeritli bir Colorado otoyolundaki maksimum hız sınırı nedir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"CRS 42-4-1101, eyaletler arası sistemdeki kaplamalı dört şeritli otoyollarda yasal maksimum olarak 65 mph belirler (CDOT belirli kesimlerde daha yüksek veya daha düşük sınırlar koyabilir). Kaynak: CRS 42-4-1101."},"67":{"q":"Colorado yasası, büyük kamyonların hız sınırını aynı otoyoldaki binek otomobillere kıyasla nasıl ele alır?","options":["Kamyonların, otomobillerden 10 mph daha düşük ayrı bir eyalet çapında sınırı vardır","Kamyonlar, yokuşlarda belirlenen sınırın 15 mph altında kalmalıdır","Kamyonlar aynı belirlenen sınıra uyar; Colorado'nun genel bir kamyon hız sınırı farklılaştırması yoktur","Kamyonlar, belirlemeye bakılmaksızın eyalet çapında 55 mph ile sınırlandırılmıştır"],"explanation":"Colorado'nun hız yasası (CRS 42-4-1101), kamyonlar için sınıfa veya ağırlığa göre ayrı, daha düşük bir eyalet çapında hız sınırı belirlemez; CMV'ler diğer araçlarla aynı belirlenen sınırlara uyar. Kaynak: CRS 42-4-1101."},"68":{"q":"CRS 42-4-1101 uyarınca, Colorado'da bir 'açık dağ otoyolundaki' (open mountain highway) ilk bakışta geçerli (prima facie) hız sınırı nedir?","options":["30 mph","40 mph","50 mph","55 mph"],"explanation":"CRS 42-4-1101, ilk bakışta geçerli sınırlar arasında açık dağ otoyollarında 40 mph'yi (ve dar, virajlı dağ otoyollarında veya kör virajlarda 20 mph'yi) listeler. Kaynak: CRS 42-4-1101."},"69":{"q":"Colorado'nun 2024 kamyon şeridi yasası, 16,000 lbs veya daha ağır kamyonların belirli I-70 dağ noktalarında en sol şeridi kullanmasını yasaklar. Bunlardan hangisi bu belirlenmiş alanlardan biridir?","options":["I-25 üzerindeki Monument Hill","Vail Pass","I-25 üzerindeki Raton Pass","Grand Junction kavşağı"],"explanation":"Colorado'nun sol şerit kamyon kısıtlaması, tek yönde en az üç şeridin bulunduğu Floyd Hill, Georgetown Hill, Eisenhower Tüneli, Dowd Junction ve Vail Pass dahil I-70 kesimlerinde 16,000 lbs veya daha ağır kamyonların en sol şeridi kullanmasını yasaklar. Kaynak: CDOT / 2024 Colorado yasası (SB24-100)."},"70":{"q":"Colorado'nun ağır kamyonları en sol şeritten kısıtladığı I-70 kesimlerinde, yasa hangi istisnaya izin verir?","options":["Kamyonlar trafik az olduğunda sol şeridi kullanabilir","Kamyonlar başka bir aracı geçmek için en sol şeridi kullanabilir","Kamyonlar sol şeridi yalnızca geceleri kullanabilir","Hiçbir koşulda istisna yoktur"],"explanation":"Colorado'nun belirlenmiş I-70 dağ kesimlerindeki kamyon sol şerit kısıtlaması, kamyonların geçiş yaparken en sol şeridi kullanmasına yine de izin verir; yasak, sürekli sol şerit seyahatini hedefler. Kaynak: CDOT / 2024 Colorado yasası (SB24-100)."},"71":{"q":"Colorado'nun Ticari Araç Zincir 'Bulundurma Zorunluluğu' (Must-Carry) yasası, CMV'lerin I-70 dağ koridorunda hangi yıllık dönem boyunca zincir bulundurmasını gerektirir?","options":["1 Ekim'den 30 Nisan'a kadar","1 Eylül'den 31 Mayıs'a kadar","1 Kasım'dan 31 Mart'a kadar","Mevsimsel bir pencere olmaksızın tüm yıl boyunca"],"explanation":"Colorado'nun bulundurma zorunluluğu yasası, ticari araçların (16,001 lbs veya daha fazla GVWR) Dotsero (MP 133) ile Morrison (MP 259) arasındaki I-70'te 1 Eylül'den 31 Mayıs'a kadar yeterli zincir bulundurmasını gerektirir. Kaynak: CDOT / CRS 42-4-106."},"72":{"q":"Colorado Ticari Araç Zincir Yasası yürürlükteyken, dört veya daha fazla çekiş tekerleği olan bir CMV ilerleyebilmek için nasıl donatılmalıdır?","options":["Çekiş tekerleği lastiklerinin en az dördünde zincir veya ATD'ler","Yalnızca direksiyon lastiklerinde zincirler","Sürücünün seçtiği herhangi iki lastikte zincirler","Yalnızca kar lastikleri her zaman yeterlidir"],"explanation":"Zincir yasası aktif olduğunda, bir CMV'nin çekiş tekerleği lastiklerinin en az dördünde (veya dörtten az çekiş tekerleği varsa tüm çekiş lastiklerinde) zincir veya alternatif çekiş cihazları bulunmalıdır. Kaynak: CDOT Chain Law / CRS 42-4-106."},"73":{"q":"Colorado'nun Ticari Araç Zincir Yasasının uygulandığı I-70 dağ koridoru hangi iki nokta arasında uzanır?","options":["Grand Junction (MP 26) ve Denver (MP 275)","Dotsero (MP 133) ve Morrison (MP 259)","Glenwood Springs (MP 116) ve Golden (MP 263)","Vail (MP 176) ve Idaho Springs (MP 240)"],"explanation":"Colorado'nun ticari zincir/bulundurma zorunluluğu, Dotsero çıkışı (Milepost 133) ile Morrison çıkışı (Milepost 259) arasındaki I-70'te uygulanır. Kaynak: CDOT / CRS 42-4-106."},"74":{"q":"Colorado eyaletler arası otoyolunda, bir CMV'yi yolun seyir kısmında durdurduktan sonra, sürücü düz ve seviyeli yolda yaklaşan trafiğe doğru üç uyarı cihazını kaç fit içinde yerleştirmelidir?","options":["5, 50 ve 100 fit mesafede","10, 100 ve 200 fit mesafede","25, 150 ve 300 fit mesafede","50, 250 ve 500 fit mesafede"],"explanation":"Colorado, uyarı cihazlarının bölünmemiş, seviyeli bir yolda durmuş CMV'den yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit mesafede yerleştirilmesini gerektiren federal FMCSR standardını izler. Kaynak: Colorado CDL Manual / 49 CFR 392.22 (Colorado'da benimsenmiştir)."},"75":{"q":"Bir Colorado CMV'si, yaklaşan trafikten kendisini gizleyen keskin bir virajın hemen ötesinde yolda durmak zorunda kalır. Uyarı cihazları nasıl ayarlanmalıdır?","options":["Üçünü de arka tamponun 10 fit içine yerleştir","Virajdan tarafa doğru cihazı 100 ila 500 fit geriye taşıyarak yeterli uyarı sağla","Arka cihazları çıkar ve yalnızca önü işaretle","Üçünü de kabinin yanında orta çizgi üzerine yerleştir"],"explanation":"Bir virajın, tepe noktasının veya başka bir görüş engelinin 500 fit içinde durulduğunda, sürücü uyarı cihazını engelin yönüne doğru taşıyarak araçtan 100 ila 500 fit uzakta olmasını sağlar ve böylece yeterli uyarı verir. Kaynak: Colorado CDL Manual / 49 CFR 392.22."},"76":{"q":"Colorado'nun en yoğun kullanılan kaçak kamyon rampası, batı yönündeki I-70'te Eisenhower Tüneli yakınında bulunmaktadır ve hangi tür cihaz olarak en iyi şekilde tanımlanır?","options":["Kaçak bir kamyonu durdurmak için derin, gevşek agrega kullanan bir çakıllı yakalama yatağı","Şerit boyunca gerilmiş çelik bir halat ağı","Yokuşun dibinde su dolu bir çarpışma yastığı","Kaplamaya gömülü manyetik bir frenleme şeridi"],"explanation":"Batı yönündeki I-70'teki Lower Straight Creek rampası, ABD'de en çok kullanılan kaçak kamyon rampasıdır; Colorado'nun diğer yakalama yatakları gibi, kaçak bir kamyonun enerjisini dağıtmak için derin bir gevşek kırılmış agrega (yuvarlak taş) yatağı kullanır. Kaynak: CDOT / Colorado CDL Manual dağ sürüşü bölümü."},"77":{"q":"CDOT'tan bir aşırı boyut izni gerekmeden önce Colorado otoyollarında izin verilen maksimum yasal araç GENİŞLİĞİ nedir?","options":["8 fit 0 inç","8 fit 6 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"Colorado'nun yasal genişlik sınırı 8 fit 6 inç'tir (102 inç); bunu aşan yükler bir CDOT aşırı boyut izni gerektirir ve 11 fit genişliği aşanlar genellikle belirlenmiş eyalet otoyollarında bir ön pilot/eskort aracı gerektirir. Kaynak: CDOT Freight & Permitting / CRS 42-4-502."},"78":{"q":"Bir Colorado dağ yokuşunda, bir CMV sürücüsünün kaçak rampaya ihtiyaç duymaktan kaçınmak için kullanması gereken doğru frenleme tekniği nedir?","options":["Tüm iniş boyunca servis frenlerini sabit şekilde basılı tut","İnişten önce düşük bir vites seç ve hafif, aralıklı fren uygulamaları kullan","Yakıt tasarrufu için boşa al ve yokuş aşağı yuvarlan","Yüksek viteste römork el valfini sürekli uygula"],"explanation":"Colorado CDL Manual dağ sürüşü rehberi, sürücülerin uzun bir yokuştan inmeye başlamadan ÖNCE güvenli bir düşük vites seçmelerini ve frenlerin aşırı ısınıp güç kaybetmemesi için frenleri aralıklı (snub braking) kullanmalarını öngörür; boşta yuvarlanmak yasa dışı ve tehlikelidir. Kaynak: Colorado CDL Manual (Mountain Driving)."},"79":{"q":"Hangi Colorado kurumu ticari sürücü belgelerini (CDL) verir ve gerekli bilgi testlerini yönetir?","options":["Colorado Ulaştırma Departmanı (CDOT)","Colorado Gelir Departmanı, Motorlu Araçlar Bölümü (DMV)","Colorado Eyalet Polisi Giriş Noktaları Bölümü","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)"],"explanation":"Colorado'da CDL'ler, Gelir Departmanının Motorlu Araçlar Bölümü (DMV) tarafından verilir; bilgi testleri tam hizmet veren bir DMV/Motorlu Araçlar ofisinde yapılır. Kaynak: Colorado DMV, dmv.colorado.gov (İlk Kez CDL Sürücüsü / CDL Genel Bilgileri)."},"80":{"q":"50 soru içeren Colorado CDL Genel Bilgi testinden geçmek için gereken minimum puan nedir?","options":["%70 (50'de en az 35 doğru)","%75 (50'de en az 38 doğru)","%90 (50'de en az 45 doğru)","%80 (50'de en az 40 doğru)"],"explanation":"Colorado CDL Genel Bilgi testi 50 soru içerir ve Colorado CDL Manual ile DMV test standartlarına uygun olarak geçmek için %80 — en az 40 doğru — gerektirir. Kaynak: Colorado DMV / Colorado CDL Manual."},"81":{"q":"Colorado CDL beceri testi üç bölümden oluşur. Hangi grup bu üç bölümü doğru şekilde listeler?","options":["Yazılı bilgi, sefer öncesi muayene ve yolda sürüş","Hava freni kontrolü, paralel park ve trafik işareti testi","Temel araç kontrolü, hazmat taraması ve yolda sürüş","Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş"],"explanation":"Colorado'nun CDL beceri testinin üç bölümü vardır: sefer öncesi muayene, temel araç kontrolü (manevralar) ve yolda sürüş testi; bu yapı, Colorado tarafından benimsenen federal CDL beceri testi yapısını yansıtır. Kaynak: Colorado CDL Manual; Colorado DMV."},"82":{"q":"İlk kez başvuran bir Colorado CDL adayı beceri testine girmeden önce, hangi federal olarak zorunlu kılınan eğitim tamamlanmış ve doğrulanmış olmalıdır?","options":["Colorado Eyalet Polisi tarafından onaylanmış bir savunmacı sürüş kursu","Bir CDOT aşırı boyut/aşırı ağırlık yük sabitleme semineri","FMCSA'ya kayıtlı bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","Bir Gelir Departmanı sınıf güvenlik oryantasyonu"],"explanation":"7 Şubat 2022'den bu yana Colorado, yeni bir başvuru sahibinin, sınıf yükseltme başvurusunun veya yeni H/P/S onay başvurusunun beceri testine girebilmesi için FMCSA'ya kayıtlı bir sağlayıcı aracılığıyla tamamlanmış (Eğitim Sağlayıcı Sicilinde kaydedilmiş) Giriş Seviyesi Sürücü Eğitimi (ELDT) gerektirir. Kaynak: Colorado DMV; 49 CFR Part 380 / FMCSA TPR."},"83":{"q":"Bir Colorado Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["180 gün geçerlidir ve bir kez yenilenebilir","60 gün geçerlidir ve iki kez yenilenebilir","Beş yıl geçerlidir ve yılda bir yenilenebilir","Bir yıl geçerlidir ve yenileme hakkı yoktur"],"explanation":"Bir Colorado CLP'si bir yıl geçerlidir ve yenilenemez; CDL alınmadan önce süresi dolarsa, başvuru sahibinin yeni bir CLP için bilgi test(ler)ini yeniden yapması gerekir. Kaynak: Colorado DMV (CDL Genel Bilgileri / İlk Kez CDL Sürücüsü)."},"84":{"q":"Bir Colorado başvuru sahibine Ticari Öğrenci İzni verildikten sonra, CDL beceri testine girilebilmesi için ne kadar süre tutulmalıdır?","options":["En az 30 takvim günü","En az 7 takvim günü","En az 14 takvim günü","En az 60 takvim günü"],"explanation":"Colorado, bir CLP'nin sahibi CDL beceri testine girmeden önce en az 14 takvim günü tutulması gerektiği federal kuralı izler. Kaynak: 49 CFR 383.25; Colorado DMV."},"85":{"q":"Colorado CDL başvuru sahipleri, sürüş türlerini beyan eden bir öz-sertifikasyon tamamlamalıdır. Kaç öz-sertifikasyon kategorisi vardır?","options":["İki","Üç","Beş","Dört"],"explanation":"Dört öz-sertifikasyon kategorisi vardır: İstisna Dışı Eyaletler Arası (Non-excepted Interstate), İstisnalı Eyaletler Arası (Excepted Interstate), İstisna Dışı Eyalet İçi (Non-excepted Intrastate) ve İstisnalı Eyalet İçi (Excepted Intrastate). Colorado'da bu, DR 2904/DR 2907 formunda beyan edilir. Kaynak: Colorado DMV formu DR 2904; 49 CFR 383.71."},"86":{"q":"Eyaletler arası ticarette faaliyet gösteren ve 49 CFR Part 391 sürücü yeterlilik kurallarını karşılaması gereken (ve dolayısıyla bir sağlık sertifikası taşıması gereken) bir Colorado sürücüsü hangi kategori altında öz-sertifikasyon yapmalıdır?","options":["İstisnalı Eyaletler Arası (Excepted Interstate)","İstisna Dışı Eyalet İçi (Non-excepted Intrastate)","İstisnalı Eyalet İçi (Excepted Intrastate)","İstisna Dışı Eyaletler Arası (Non-excepted Interstate)"],"explanation":"Eyaletler arası ticarette faaliyet gösteren, 49 CFR Part 391 yeterlilik gerekliliklerine tabi olan ve bunları karşılayan — ve bir sağlık muayenecisi sertifikası taşıması gereken — bir sürücü, İstisna Dışı Eyaletler Arası (Non-excepted Interstate) olarak öz-sertifikasyon yapar. Kaynak: Colorado DMV formu DR 2904; 49 CFR 383.71."},"87":{"q":"DOT sağlık gerekliliğini karşılamak için, bir Colorado CDL başvuru sahibi hangi belgeyi edinmeli ve sunmalıdır?","options":["İyi sağlık durumunu onaylayan genel bir hekim notu","Bir Colorado Eyalet Polisi sağlık onay kartı","FMCSA Ulusal Sicilinde yer alan bir sağlayıcıdan bir Sağlık Muayenecisi Sertifikası","Bir CDOT izin sağlık muafiyeti"],"explanation":"Çoğu Colorado CDL sahibi, FMCSA Onaylı Sağlık Muayenecileri Ulusal Sicilinde listelenen bir muayeneciden bir Sağlık Muayenecisi Sertifikası (DOT sağlık kartı) edinmelidir. Kaynak: Colorado DMV (CDL DOT Medical); FMCSA Ulusal Sicili."},"88":{"q":"Tipik bir istisna dışı Colorado CDL sürücüsü için, bir DOT Sağlık Muayenecisi Sertifikasının geçerli olduğu maksimum süre nedir?","options":["İki yıla kadar","Beş yıla kadar","Bir yıla kadar","Üç yıla kadar"],"explanation":"Bir DOT sağlık muayenecisi sertifikası en fazla iki yıl için verilir (ve muayeneci izlenmesi gereken bir durum belirtirse daha kısa olabilir). Sürücü, Colorado DMV'de güncel bir sertifika bulundurmalıdır. Kaynak: 49 CFR 391.43; Colorado DMV (CDL DOT Medical)."},"89":{"q":"Öz-sertifikasyon yapmış istisna dışı bir Colorado CDL sürücüsü, DMV'de bulunan sağlık sertifikasının süresinin dolmasına izin verirse, tipik sonuç nedir?","options":["CDL derhal ve kalıcı olarak iptal edilir","Güncel bir sağlık sertifikası dosyalanana kadar ticari ayrıcalıklar kaldırılacak şekilde CDL düşürülür (downgrade)","Beş yıllık CDL yenilemesine kadar hiçbir şey olmaz","Sürücü otomatik olarak İstisnalı Eyaletler Arası (Excepted Interstate) olarak yeniden sınıflandırılır"],"explanation":"İstisna dışı bir sürücünün sağlık sertifikasının süresi dolar ve güncel bir tane sunulmazsa, Colorado lisansı düşürür (downgrade) ve geçerli bir sertifika dosyalanana kadar ticari sürüş ayrıcalıklarını kaldırır. Kaynak: Colorado DMV (CDL DOT Medical); 49 CFR 383.73."},"90":{"q":"EYALETLER ARASI ticari sürüş veya plakartlanmış tehlikeli madde taşımacılığı için bir Colorado CDL'si verilmesinin minimum yaşı nedir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Colorado federal minimumu izler: bir sürücünün eyaletler arası ticarette faaliyet göstermek veya plakartlanmış tehlikeli madde taşımak için 21 yaşında olması gerekir. 18-20 yaşındaki sürücüler eyalet içi faaliyetle sınırlıdır. Kaynak: Colorado DMV; 49 CFR 383."},"91":{"q":"18 ile 20 yaşları arasındaki bir Colorado CDL sahibi yalnızca Colorado içinde araç kullanmakla kısıtlıdır. Hangi lisans kısıtlama kodu bu yalnızca-eyalet-içi sınırını yansıtır?","options":["Kısıtlama \"K\" (yalnızca eyalet içi)","Kısıtlama \"L\" (hava freni yok)","Kısıtlama \"Z\" (tam hava freni yok)","Kısıtlama \"E\" (manuel şanzıman yok)"],"explanation":"Colorado, 18-20 yaşlarındaki sürücüler dahil eyaletler arası ticarette faaliyet gösteremeyen CDL sahiplerine \"K\" kısıtlamasını (yalnızca eyalet içi) uygular. Kaynak: Colorado DMV (CDL Kısıtlamaları)."},"92":{"q":"İlk kez başvuran bir Colorado CDL adayı DMV'de hangi belge grubunu sunmalıdır?","options":["Yalnızca güncel bir Colorado normal sürücü belgesi","Kimlik kanıtı, ABD'de yasal varlık kanıtı, Sosyal Güvenlik numarası kanıtı ve Colorado ikamet kanıtı","Bir pasaport ve bir CDOT yük izni","Bir işveren mektubu ve yalnızca iki vesikalık fotoğraf"],"explanation":"Colorado CDL başvuru sahipleri kimliklerini, ABD'de yasal varlıklarını, Sosyal Güvenlik numaralarını ve Colorado ikamet adreslerini (örneğin, fatura veya banka ekstresi) kanıtlamalıdır. Kaynak: Colorado DMV (İlk Kez CDL Sürücüsü)."},"93":{"q":"Beceri testine izin verilmeden önce, bir Colorado CDL başvuru sahibinin ELDT tamamlaması DMV tarafından nasıl onaylanır?","options":["Başvuru sahibi onay için CDOT'a kağıt bir sertifika postalar","Başvuru sahibi eğitmenden noter onaylı bir beyanname getirir","Sağlayıcı bunu elektronik olarak FMCSA Eğitim Sağlayıcı Siciline bildirir ve DMV bunu kontrol eder","Colorado Eyalet Polisi bir ELDT onay mektubu verir"],"explanation":"FMCSA'ya kayıtlı ELDT sağlayıcıları tamamlama kayıtlarını federal Eğitim Sağlayıcı Siciline (TPR) gönderir; Colorado'nun DMV'si beceri testine izin vermeden önce kaydı elektronik olarak doğrular. Kaynak: Colorado DMV; FMCSA TPR / 49 CFR Part 380."},"94":{"q":"Doğru sırayla, ilk kez başvuran bir Colorado CDL adayı için ilk üç ana adım nedir?","options":["Beceri testine gir, sonra CLP'yi al, sonra ELDT'yi tamamla","Bilgi test(ler)ini geç ve CLP'yi al, sonra ELDT'yi tamamla, sonra beceri testine gir","ELDT'yi tamamla, sonra beceri testine gir, sonra bilgi testini geç","Sağlık kartını al, sonra beceri testine gir, sonra bilgi testine gir"],"explanation":"Colorado sırası şöyledir: gerekli bilgi test(ler)ini geç ve CLP'yi al, FMCSA onaylı ELDT'yi (teorik ve direksiyon başında) tamamla, sonra (14 günlük CLP tutma süresinden sonra) üç bölümlü beceri testine gir. Kaynak: Colorado DMV (İlk Kez CDL Sürücüsü)."},"95":{"q":"Colorado CDL beceri testinin yolda sürüş bölümü sırasında, muayeneci öncelikle neyi değerlendirir?","options":["Başvuru sahibinin belirlenmiş bir rota üzerinde gerçek trafikte aracı güvenli şekilde kullanma yeteneği","Başvuru sahibinin CDL kılavuzunun içeriğini ezbere söyleyip söyleyemeyeceği","Yalnızca başvuru sahibinin paralel park hızı","Aracın aşırı boyut/aşırı ağırlık izin sınırlarına uygunluğu"],"explanation":"Yolda sürüş testi, önceden belirlenmiş bir rota üzerinde gerçek trafikte güvenli kullanımı değerlendirir — dönüşler, kavşaklar, şerit değiştirmeler ve genel sürüş. Geri gitme/manevralar ayrı temel kontrol bölümünde puanlanır. Kaynak: Colorado CDL Manual; Colorado DMV."},"96":{"q":"Bir Colorado sürücüsü yalnızca tamamen Colorado içinde çiftlik malzemeleri taşır ve eyalet sürücü yeterlilik kurallarının bazı bölümlerinden muaftır. Hangi öz-sertifikasyon kategorisi bu sürücüye uyar?","options":["İstisnalı Eyalet İçi (Excepted Intrastate)","İstisna Dışı Eyaletler Arası (Non-excepted Interstate)","İstisnalı Eyaletler Arası (Excepted Interstate)","İstisna Dışı Eyalet İçi (Non-excepted Intrastate)"],"explanation":"Yalnızca Colorado içinde faaliyet gösteren ve eyalet sürücü yeterlilik gerekliliklerinin tamamından veya bir kısmından muaf olan bir sürücü, İstisnalı Eyalet İçi (Excepted Intrastate) olarak öz-sertifikasyon yapar ve genellikle bir DOT sağlık sertifikası dosyalaması gerekmez. Kaynak: Colorado DMV formu DR 2904; 49 CFR 383.71."},"97":{"q":"Colorado'daki CDL ücretleri ile ilgili olarak, bir çalışma kılavuzu için hangi ifade en doğrudur?","options":["CDL bilgi ve beceri testleri Colorado'da her zaman ücretsizdir","Ücretler federal yasa tarafından kalıcı olarak sabitlenmiştir ve asla değişmez","Belirli ücret tutarları eyalet tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri güncel ücretleri DMV ile teyit etmelidir","Yalnızca sağlık muayenesinin bir ücreti vardır; DMV lisans için hiçbir ücret almaz"],"explanation":"Colorado, CDL testi ve belge verme için ücret alır, ancak tam tutarlar eyalet tarafından belirlenir ve değişebilir; başvuru sahipleri sabit bir rakama güvenmek yerine güncel ücretleri DMV ile doğrulamalıdır. Kaynak: Colorado DMV (CDL Genel Bilgileri / ücret çizelgesi)."}},"es":{"0":{"q":"En las carreteras de Colorado, ¿cuál es el ancho máximo legal de un vehículo comercial estándar (excluyendo los espejos y los accesorios de seguridad requeridos) antes de necesitar un permiso de sobredimensión?","options":["8 pies 0 pulgadas (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies 0 pulgadas (108 pulgadas)","10 pies 0 pulgadas (120 pulgadas)"],"explanation":"Colorado limita el ancho del vehículo a 8 pies 6 pulgadas (102 pulgadas). Las luces de gálibo, los espejos retrovisores y otros accesorios requeridos no se cuentan dentro de este límite. Fuente: C.R.S. 42-4-502 (Ancho de los vehículos)."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, cargado o sin carga, en las carreteras de Colorado?","options":["13 pies 6 pulgadas","14 pies 0 pulgadas","14 pies 6 pulgadas","15 pies 0 pulgadas"],"explanation":"Un conductor no puede operar un vehículo, sin carga o con carga, que supere una altura de 14 pies 6 pulgadas. Fuente: C.R.S. 42-4-504 (Altura y longitud de los vehículos)."},"2":{"q":"Según la ley de Colorado, ¿cuál es la longitud total máxima de un solo vehículo de motor (incluyendo los parachoques delantero y trasero)?","options":["40 pies","45 pies","53 pies","60 pies"],"explanation":"Ningún vehículo de motor individual puede superar los 45 pies de longitud total extrema, incluyendo los parachoques delantero y trasero. Fuente: C.R.S. 42-4-504 (Altura y longitud de los vehículos)."},"3":{"q":"¿Cuál es la longitud total máxima de una combinación de vehículos acoplados entre sí en las carreteras de Colorado (sin un permiso especial)?","options":["60 pies","65 pies","70 pies","75 pies"],"explanation":"Ninguna combinación de vehículos puede superar una longitud total de 70 pies, y una combinación no puede constar de más de cuatro unidades. Fuente: C.R.S. 42-4-504 (Altura y longitud de los vehículos)."},"4":{"q":"En Colorado, el peso máximo permitido sobre un solo eje equipado con neumáticos es:","options":["16,000 libras","18,000 libras","20,000 libras","22,000 libras"],"explanation":"Cuando las ruedas de un solo eje están equipadas con neumáticos, la carga máxima es de 20,000 libras. Fuente: C.R.S. 42-4-507 (Cargas por rueda y por eje)."},"5":{"q":"¿Cuál es el peso máximo permitido sobre un grupo de ejes en tándem que circula por una carretera INTERESTATAL de Colorado?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"En el sistema interestatal, Colorado sigue el límite federal de eje en tándem de 36,000 libras. (En las carreteras estatales no interestatales, el límite de tándem es de 40,000 libras.) Fuente: C.R.S. 42-4-507 (Cargas por rueda y por eje)."},"6":{"q":"En una carretera estatal no interestatal de Colorado, ¿cuál es el peso máximo permitido sobre un grupo de ejes en tándem?","options":["34,000 libras","36,000 libras","40,000 libras","44,000 libras"],"explanation":"En las carreteras estatales no interestatales, Colorado permite hasta 40,000 libras sobre un eje en tándem, lo cual es mayor que el límite interestatal de 36,000 libras. Fuente: C.R.S. 42-4-507 (Cargas por rueda y por eje)."},"7":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en el sistema INTERESTATAL de Colorado sin un permiso de sobrepeso?","options":["76,000 libras","80,000 libras","85,000 libras","90,000 libras"],"explanation":"En las carreteras interestatales, Colorado aplica el peso bruto máximo federal de 80,000 libras, regido por la fórmula federal de puentes. Fuente: C.R.S. 42-4-508 (Peso bruto de vehículos y cargas)."},"8":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en las carreteras NO interestatales (estatales y locales) de Colorado según la tabla de pesos estatal, en ausencia de un permiso?","options":["80,000 libras","82,000 libras","85,000 libras","90,000 libras"],"explanation":"En las carreteras no interestatales, la propia tabla de peso bruto de Colorado permite hasta 85,000 libras, lo cual supera el tope interestatal de 80,000 libras. Fuente: C.R.S. 42-4-508 (Peso bruto de vehículos y cargas)."},"9":{"q":"¿Cómo define Colorado un 'eje en tándem' para efectos de peso?","options":["Dos o más ejes consecutivos separados más de 40 pulgadas y no más de 96 pulgadas entre sí","Dos ejes separados exactamente 48 pulgadas entre sí","Cualquier par de ejes separados menos de 40 pulgadas entre sí","Tres o más ejes separados más de 96 pulgadas entre sí"],"explanation":"Un eje en tándem es dos o más ejes consecutivos cuyos centros se ubican entre planos verticales paralelos separados más de 40 pulgadas y no más de 96 pulgadas, extendiéndose a lo ancho de todo el vehículo. Fuente: C.R.S. 42-4-507 (Cargas por rueda y por eje)."},"10":{"q":"¿Qué fórmula utiliza Colorado para determinar el peso bruto máximo permitido según la separación de los ejes en el sistema interestatal?","options":["La fórmula estatal de impuesto por milla","La fórmula federal de puentes (fórmula de peso bruto de puentes)","Únicamente la fórmula de ancho de neumático por pulgada","Una regla fija y uniforme de 80,000 libras sin tener en cuenta la separación de los ejes"],"explanation":"En las carreteras interestatales, Colorado limita el peso bruto por grupo de ejes usando la fórmula federal de puentes, que relaciona el peso permitido con el número de ejes y la distancia entre los ejes extremos, con un tope de 80,000 libras. Fuente: C.R.S. 42-4-508; 23 CFR 658 federal (fórmula de puentes)."},"11":{"q":"En la fórmula general (no interestatal) de peso bruto de Colorado W = 1,000(L + 40), ¿qué representa la 'L'?","options":["El número de ejes del vehículo","El peso total de la carga en toneladas","La distancia en pies entre los centros del primer y el último eje","La longitud legal del remolque"],"explanation":"En la fórmula de peso bruto no interestatal de Colorado W = 1,000(L + 40), la 'L' es la distancia en pies entre los centros del primer y el último eje del grupo, y W es el peso bruto máximo en libras, sin exceder 85,000 libras. Fuente: C.R.S. 42-4-508 (Peso bruto de vehículos y cargas)."},"12":{"q":"Un conductor que transporta una carga de 11 pies de ancho en una carretera estatal de Colorado debe hacer cuál de las siguientes cosas?","options":["Nada; 11 pies está dentro del límite legal de ancho","Obtener un permiso de sobredimensión del CDOT porque la carga supera los 8 pies 6 pulgadas","Solo mostrar una bandera, sin necesidad de permiso","Reducir el peso bruto a 80,000 libras"],"explanation":"Cualquier carga más ancha que el límite legal de 8 pies 6 pulgadas requiere un permiso estatal de sobredimensión del CDOT antes de circular. Una carga de 11 pies de ancho es de sobredimensión. Fuente: C.R.S. 42-4-502 y 42-4-510; Oficina de Permisos del CDOT."},"13":{"q":"En Colorado, los permisos de sobredimensión y de sobrepeso para circular por el sistema de carreteras estatales son emitidos por:","options":["El Departamento de Hacienda de Colorado, División de Vehículos Motorizados","La Oficina de Permisos del Departamento de Transporte de Colorado (CDOT)","El alguacil del condado donde comienza el viaje","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"Los permisos de sobredimensión/sobrepeso para el sistema de carreteras estatales son emitidos por la Oficina de Permisos del CDOT, generalmente a través del sistema en línea COOPR (Colorado Oversize Overweight Permitting and Routing). Fuente: C.R.S. 42-4-510; CDOT freight.colorado.gov."},"14":{"q":"¿Cuál es el nombre del sistema en línea que utiliza Colorado para que los transportistas soliciten permisos de sobredimensión/sobrepeso y obtengan rutas aprobadas?","options":["COOPR (Colorado Oversize Overweight Permitting and Routing)","IRP (International Registration Plan)","PRISM (Performance Registration Information Systems Management)","UCR (Unified Carrier Registration)"],"explanation":"Colorado emite los permisos de sobredimensión/sobrepeso a través del sistema COOPR, donde los transportistas solicitan en línea, pagan tarifas y reciben el enrutamiento; muchos permisos pueden autoemitirse. Fuente: CDOT, coopr.codot.gov; C.R.S. 42-4-510."},"15":{"q":"Con un permiso de sobredimensión de Colorado, el heno suelto (incluyendo las pacas redondas) puede transportarse hasta qué ancho?","options":["8 pies 6 pulgadas","10 pies 6 pulgadas","12 pies","14 pies"],"explanation":"El estatuto de ancho de Colorado permite que el heno suelto, incluyendo las pacas redondas, se transporte hasta 12 pies de ancho; el heno rectangular (en pacas) está limitado a 10 pies 6 pulgadas. Fuente: C.R.S. 42-4-502 (Ancho de los vehículos)."},"16":{"q":"En las carreteras de Colorado, ¿cuál es el peso máximo sobre cualquier rueda individual de un vehículo con neumáticos de ACERO, por pulgada de ancho transversal del neumático?","options":["300 libras por pulgada","500 libras por pulgada","650 libras por pulgada","800 libras por pulgada"],"explanation":"El peso bruto sobre cualquier rueda individual de un vehículo con neumáticos de acero no puede superar las 500 libras por pulgada de ancho transversal del neumático. Fuente: C.R.S. 42-4-507 (Cargas por rueda y por eje)."},"17":{"q":"Colorado permite que ciertos vehículos de combustible alternativo superen los límites estándar de peso bruto y por eje, ¿en cuánto, para tener en cuenta el sistema de combustible/propulsión más pesado?","options":["Hasta 400 libras","Hasta 1,000 libras","Hasta 2,000 libras","Hasta 5,000 libras"],"explanation":"Colorado permite que los vehículos impulsados por combustible alternativo superen los límites de peso bruto y por eje en hasta 2,000 libras, de manera consistente con la tolerancia federal de peso para vehículos de gas natural/eléctricos. Fuente: C.R.S. 42-4-508 (Peso bruto de vehículos y cargas)."},"18":{"q":"Cuando una combinación de vehículos de Colorado está cargada, cada vehículo de la combinación generalmente debe soportar al menos qué proporción del peso bruto total (con excepciones limitadas para ciertos remolques de servicios públicos/postes)?","options":["Al menos el 5 por ciento del peso bruto total","Al menos el 10 por ciento del peso bruto total","Al menos el 25 por ciento del peso bruto total","Al menos el 50 por ciento del peso bruto total"],"explanation":"En una combinación de vehículos, cada vehículo debe soportar al menos el 10 por ciento del peso bruto total, excepto los remolques especializados que se usan para transportar cargas fijas de servicios públicos o postes. Fuente: C.R.S. 42-4-508 (Peso bruto de vehículos y cargas)."},"19":{"q":"Un agente del orden de Colorado que considere que un vehículo tiene sobrepeso puede exigir que el conductor sea pesado y, si el vehículo está por encima del límite legal, puede exigir que el conductor haga qué?","options":["Entregar de inmediato la licencia de conducir comercial","Descargar suficiente carga para reducir el peso bruto al límite legal","Pagar la multa por sobrepeso en efectivo en el lugar antes de continuar","Continuar hasta el destino y presentarse en un puerto de entrada dentro de 24 horas"],"explanation":"Un agente con motivos para creer que un vehículo tiene sobrepeso puede exigir que sea pesado en básculas portátiles o fijas (o en básculas públicas cercanas, dentro de un radio de cinco millas) y, si tiene sobrepeso de manera ilegal, exigir que el conductor retire suficiente carga para reducir el peso bruto al límite legal. Fuente: C.R.S. 42-4-509 (Vehículos pesados - exceso retirado)."},"20":{"q":"En Colorado, ¿qué clase de CDL se requiere para operar cualquier combinación de vehículos con una Clasificación de Peso Bruto Combinado (GCWR) de 26,001 libras o más, donde el vehículo remolcado tiene un GVWR superior a 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Colorado define una CDL Clase A como cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que el GVWR de la unidad remolcada supere las 10,000 lbs. Fuente: Manual de CDL de Colorado (Colorado DMV/Dept. of Revenue), definiciones de clases de CDL; C.R.S. 42-2-402."},"21":{"q":"¿Qué clase de CDL de Colorado cubre un solo vehículo con un GVWR de 26,001 libras o más que puede remolcar otro vehículo que no exceda los 10,000 libras de GVWR?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Se requiere una CDL Clase B en Colorado para cualquier vehículo individual con un GVWR de 26,001 lbs o más, el cual puede remolcar una unidad que no supere las 10,000 lbs de GVWR. Fuente: Manual de CDL de Colorado (Colorado DMV), definiciones de clases."},"22":{"q":"Un conductor opera un solo vehículo de menos de 26,001 libras de GVWR que está diseñado para transportar 18 pasajeros incluido el conductor. ¿Qué clase de CDL de Colorado se requiere?","options":["No se requiere CDL","Clase A","Clase B","Clase C"],"explanation":"Una CDL Clase C cubre los vehículos que no cumplen con las definiciones de peso de Clase A o B, pero que están diseñados para transportar 16 o más pasajeros (incluido el conductor) o para transportar materiales peligrosos que requieren rótulos. Fuente: Manual de CDL de Colorado (Colorado DMV), definiciones de clases."},"23":{"q":"¿Qué endoso debe obtener un titular de CDL de Colorado para transportar materiales peligrosos en cantidades que requieren rótulos?","options":["Endoso N","Endoso T","Endoso H","Endoso P"],"explanation":"El endoso H (Materiales Peligrosos) se requiere para transportar materiales peligrosos que requieren rótulos. En Colorado se requiere aprobar el examen de conocimientos de HazMat, completar la teoría de ELDT y aprobar una evaluación de amenazas de seguridad de la TSA. Fuente: Endosos y Requisitos de CDL del Colorado DMV; 49 CFR 383."},"24":{"q":"¿Cuál es la edad mínima para obtener una CDL de Colorado únicamente para conducir dentro del estado (intraestatal)?","options":["16 años","18 años","19 años","21 años"],"explanation":"Colorado permite una CDL a los 18 años únicamente para operación intraestatal. Los conductores de 18 a 20 años reciben una restricción 'K' que los limita a conducir dentro de Colorado. Fuente: Colorado DMV; C.R.S. 42-2-403."},"25":{"q":"¿Cuál es la edad mínima requerida para obtener una CDL de Colorado válida para conducir entre estados (interestatal)?","options":["18 años","19 años","21 años","25 años"],"explanation":"La conducción comercial interestatal requiere una edad mínima de 21 años. Los conductores de 18 a 20 años tienen una CDL con una restricción 'K' (solo intraestatal). Fuente: Colorado DMV; FMCSA 49 CFR 391.11."},"26":{"q":"Según las normas federales adoptadas en Colorado, ¿cuánto tiempo debe mantenerse un Permiso de Aprendiz Comercial (CLP) antes de que el titular sea elegible para tomar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 60 días","Al menos 180 días"],"explanation":"Un titular de CLP no puede tomar el examen de habilidades de la CDL hasta que hayan transcurrido al menos 14 días desde la emisión inicial del CLP. Fuente: FMCSA 49 CFR 383.25, aplicado por el Colorado DMV."},"27":{"q":"¿Qué endoso se requiere para un conductor de Colorado que transporta un vehículo cisterna que lleva líquidos a granel con una capacidad nominal total de 1,000 galones o más?","options":["Endoso H","Endoso N","Endoso T","Endoso S"],"explanation":"El endoso N (Vehículo Cisterna) se requiere para operar un vehículo cisterna con tanques de capacidad nominal individual superior a 119 galones y una capacidad nominal total de 1,000 galones o más. Requiere aprobar el examen de conocimientos de cisternas. Fuente: Endosos de CDL del Colorado DMV; 49 CFR 383.5."},"28":{"q":"Un conductor de Colorado quiere el endoso T para arrastrar remolques dobles o triples. ¿Qué debe hacer el conductor para agregarlo?","options":["Aprobar únicamente un examen de conocimientos (escrito)","Aprobar un examen de conocimientos y un examen de habilidades","Aprobar una verificación de antecedentes de la TSA","Completar la capacitación práctica al volante de ELDT"],"explanation":"El endoso T (Dobles/Triples) requiere aprobar únicamente el examen de conocimientos de dobles/triples en Colorado; no se requiere un examen de habilidades aparte. Puede agregarse a una CDL Clase A. Fuente: Endosos y Requisitos de CDL del Colorado DMV."},"29":{"q":"¿Qué endoso necesita un conductor de Colorado para transportar 16 o más pasajeros (incluido el conductor) en un vehículo comercial?","options":["Endoso S","Endoso N","Endoso P","Endoso H"],"explanation":"El endoso P (Pasajeros) se requiere para transportar 16 o más pasajeros incluido el conductor. En Colorado requiere el examen de conocimientos de pasajeros, ELDT y un examen de habilidades en un vehículo de pasajeros. Fuente: Endosos y Requisitos de CDL del Colorado DMV."},"30":{"q":"En Colorado, ¿qué endoso es un requisito previo que debe obtenerse junto con (o antes de) el endoso de Autobús Escolar (S)?","options":["Endoso N (Cisterna)","Endoso P (Pasajeros)","Endoso H (HazMat)","Endoso T (Dobles/Triples)"],"explanation":"El endoso P (Pasajeros) es un requisito previo para el endoso S (Autobús Escolar); un solicitante no puede tener el S sin el P. Fuente: Endosos y Requisitos de CDL del Colorado DMV; 49 CFR 383.93."},"31":{"q":"¿Qué entidad mantiene el registro en el que debe figurar el proveedor de Capacitación de Conductores de Nivel Inicial (ELDT) de un solicitante de CDL de Colorado?","options":["El Departamento de Educación de Colorado","El Registro de Proveedores de Capacitación de la FMCSA","La Patrulla Estatal de Colorado","La Administración de Seguridad del Transporte"],"explanation":"La ELDT debe completarse a través de un proveedor que figure en el Registro de Proveedores de Capacitación (TPR) de la FMCSA; el Colorado DMV verifica la finalización a través del TPR antes de permitir el examen de habilidades/conocimientos. Fuente: TPR de la FMCSA; Colorado DMV."},"32":{"q":"¿Para cuál de los siguientes la ELDT (Capacitación de Conductores de Nivel Inicial) consiste en capacitación solo de teoría completada antes del examen de conocimientos, en lugar de incluir capacitación práctica al volante?","options":["CDL Clase A por primera vez","CDL Clase B por primera vez","Endoso H (HazMat)","Endoso P (Pasajeros)"],"explanation":"Para el endoso H (HazMat), la ELDT es solo de teoría y debe completarse antes de tomar el examen de conocimientos de HazMat. Las Clases A, B, P y S requieren ELDT tanto de teoría como práctica al volante. Fuente: FMCSA 49 CFR 380 Subparte F; TPR de la FMCSA."},"33":{"q":"Antes de que se emita o renueve un endoso de HazMat (H) de Colorado, ¿qué autorización adicional debe obtener el solicitante?","options":["Una exención médica del DOT","Una Evaluación de Amenazas de Seguridad de la TSA (verificación de antecedentes)","Un registro AIM del Departamento de Educación de Colorado","Un certificado de inspección SAE Nivel 2"],"explanation":"Los solicitantes del endoso H deben aprobar una Evaluación de Amenazas de Seguridad de la TSA, que incluye verificaciones de antecedentes basadas en huellas dactilares, antes de que se emita o renueve el endoso. Fuente: TSA/FMCSA 49 CFR 1572; Preguntas frecuentes de CDL del Colorado DMV."},"34":{"q":"Al solicitar una CDL o un CLP de Colorado, ¿cuántas pruebas de domicilio (residencia) en Colorado debe presentar el solicitante?","options":["Una prueba de domicilio","Dos pruebas de domicilio","Tres pruebas de domicilio","No se requiere prueba de domicilio"],"explanation":"El Colorado DMV requiere dos documentos que prueben el domicilio en Colorado, fechados dentro del último año, además de la prueba de identidad. Fuente: Documentos de Identificación Requeridos del Colorado DMV."},"35":{"q":"Además de la prueba de identidad y de residencia en Colorado, ¿qué más debe proporcionar un solicitante de CDL de Colorado al presentar la solicitud?","options":["Únicamente un pasaporte","Prueba de su número de Seguro Social","Una carta notariada del empleador","Dos referencias de carácter"],"explanation":"Colorado requiere que los solicitantes presenten su tarjeta de Seguro Social u otra prueba aceptable de su número de Seguro Social, junto con los documentos de identidad y de presencia legal/residencia. Fuente: Documentos de Identificación Requeridos del Colorado DMV."},"36":{"q":"¿Cuál de las siguientes es una de las cuatro categorías federales de autocertificación médica que un titular de CDL de Colorado debe elegir?","options":["Interestatal No Exceptuado","Interestatal con Rótulos","Intraestatal Restringido","Interestatal Condicional"],"explanation":"Las cuatro categorías de autocertificación son Interestatal No Exceptuado (NI), Interestatal Exceptuado (EI), Intraestatal No Exceptuado (NA) e Intraestatal Exceptuado (EA). Un conductor sujeto a las normas federales de calificación física selecciona Interestatal No Exceptuado. Fuente: FMCSA 49 CFR 383.71; Colorado DMV."},"37":{"q":"Un titular de CDL de Colorado que conduce únicamente dentro de Colorado pero que aún debe cumplir con los estándares de calificación médica debe autocertificarse bajo qué categoría?","options":["Interestatal No Exceptuado","Interestatal Exceptuado","Intraestatal No Exceptuado","Intraestatal Exceptuado"],"explanation":"Un conductor que opera únicamente dentro de Colorado y que aún está obligado a cumplir con los estándares médicos se autocertifica como Intraestatal No Exceptuado (NA). Fuente: FMCSA 49 CFR 383.71; categorías de autocertificación del Colorado DMV."},"38":{"q":"Además de la verificación de antecedentes de la TSA, ¿qué debe hacer un conductor de Colorado para agregar el endoso de HazMat (H) a una CDL?","options":["Aprobar un examen de conocimientos (escrito) de HazMat","Aprobar únicamente un examen de habilidades/manejo de HazMat","Presentar un informe de inspección de dobles/triples","Mantener primero el endoso durante un año en un CLP"],"explanation":"Agregar el endoso H requiere aprobar el examen de conocimientos de HazMat (además de la teoría de ELDT y una Evaluación de Amenazas de Seguridad de la TSA); no hay un examen de habilidades de HazMat aparte. Fuente: Endosos y Requisitos de CDL del Colorado DMV; 49 CFR 383."},"39":{"q":"¿Cuál es la concentración máxima de alcohol en la sangre (BAC) permitida al operar un vehículo motorizado comercial en Colorado?","options":["0.02","0.04","0.08","0.10"],"explanation":"En Colorado, un conductor no puede operar un CMV con un BAC de 0.04 o mayor, la mitad del límite de 0.08 para conductores no comerciales. Fuente: Manual de CDL de Colorado, Sección 1 (Descalificaciones); 49 CFR 383.51."},"40":{"q":"Según la ley de consentimiento implícito de Colorado, ¿qué sucede si un titular de CDL se niega a someterse a una prueba química de alcohol o drogas?","options":["Se emite una advertencia sin descalificación","La CDL se descalifica por el mismo período que una primera infracción grave","Solo se impone una multa","La licencia se suspende por 30 días"],"explanation":"Negarse a la prueba requerida se trata como una infracción grave en Colorado, lo que conlleva una descalificación de 1 año (3 años si se transportan materiales peligrosos con rótulos), igual que una primera infracción de DUI/BAC. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51; C.R.S. 42-2-126."},"41":{"q":"Por una primera infracción grave, como conducir un CMV con un BAC de 0.04 o mayor, ¿por cuánto tiempo se descalifica a un titular de CDL de Colorado (cuando NO se transportan materiales peligrosos con rótulos)?","options":["60 días","6 meses","1 año","3 años"],"explanation":"Una primera infracción grave resulta en una descalificación de CDL de 1 año en Colorado. Fuente: Manual de CDL de Colorado, Sección 1 (Descalificaciones); 49 CFR 383.51."},"42":{"q":"¿Cuánto dura la descalificación por una primera infracción grave si el conductor estaba transportando materiales peligrosos con rótulos en ese momento?","options":["1 año","2 años","3 años","5 años"],"explanation":"Una primera infracción grave mientras se transportan materiales peligrosos con rótulos eleva la descalificación a 3 años en Colorado. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"43":{"q":"¿Cuál es la descalificación por una segunda infracción grave (por ejemplo, un segundo DUI) cometida por un titular de CDL de Colorado?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción grave resulta en una descalificación de CDL de por vida en Colorado, aunque la reincorporación puede ser posible después de 10 años bajo ciertas condiciones. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"44":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción grave' para un titular de CDL de Colorado?","options":["Seguir demasiado cerca al vehículo de adelante","Abandonar la escena de un accidente que involucra un CMV","Exceder el límite de velocidad en 15 mph","Un cambio de carril indebido"],"explanation":"Abandonar la escena de un accidente es una infracción grave (descalificación de 1 año la primera vez / de por vida la segunda). Las otras opciones son violaciones de tránsito serias, no infracciones graves. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"45":{"q":"Usar un vehículo motorizado comercial para cometer un delito grave se trata según las normas de CDL de Colorado como una:","options":["Violación de tránsito seria","Infracción grave","Violación de fuera de servicio","Violación de cruce ferroviario"],"explanation":"Usar un CMV en la comisión de un delito grave es una infracción grave, que conlleva una descalificación de 1 año por una primera condena y de por vida por una segunda. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"46":{"q":"¿Una primera condena por cualquier violación de tránsito seria resulta en qué descalificación de CDL en Colorado?","options":["Sin descalificación","30 días","60 días","120 días"],"explanation":"Una sola violación de tránsito seria no descalifica por sí misma a un conductor; la descalificación comienza solo con una segunda o tercera violación de este tipo dentro de 3 años. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"47":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Colorado por una SEGUNDA violación de tránsito seria cometida dentro de un período de 3 años?","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos violaciones de tránsito serias dentro de 3 años resultan en una descalificación de 60 días. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"48":{"q":"¿Cuánto dura la descalificación por una TERCERA violación de tránsito seria dentro de un período de 3 años?","options":["60 días","90 días","120 días","1 año"],"explanation":"Tres violaciones de tránsito serias dentro de 3 años resultan en una descalificación de 120 días. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"49":{"q":"¿A qué velocidad por encima del límite indicado una infracción de velocidad cuenta como una 'violación de tránsito seria' para un titular de CDL de Colorado?","options":["10 mph o más por encima","15 mph o más por encima","20 mph o más por encima","25 mph o más por encima"],"explanation":"Exceder el límite de velocidad indicado en 15 mph o más es una violación de tránsito seria. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"50":{"q":"¿Cuál de las siguientes NO se cuenta como una violación de tránsito seria para un titular de CDL de Colorado?","options":["Conducción imprudente","Seguir demasiado cerca","Conducir un CMV con un BAC de 0.04","Cambios de carril erráticos o indebidos"],"explanation":"Conducir con un BAC de 0.04 o mayor es una infracción grave, no una violación de tránsito seria. La conducción imprudente, seguir demasiado cerca y los cambios de carril indebidos son violaciones de tránsito serias. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"51":{"q":"Enviar mensajes de texto o usar un teléfono móvil de mano de manera reiterada mientras se conduce un CMV se categoriza según las normas de CDL de Colorado como una:","options":["Infracción grave","Violación de tránsito seria","Violación de fuera de servicio","Infracción que no conlleva descalificación"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV es una violación de tránsito seria; varias condenas dentro de 3 años desencadenan descalificaciones de 60/120 días. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51, 392.80/392.82."},"52":{"q":"La ley estatal de manos libres de 2025 de Colorado (SB24-065) generalmente prohíbe el uso de dispositivos de mano, pero ¿cómo se aplica a los conductores de CDL que operan un CMV?","options":["Los conductores de CDL están exentos porque las normas federales más estrictas ya prohíben el uso de teléfonos de mano","Reemplaza por completo la norma federal para los conductores de CMV","No se aplica a ningún conductor en Colorado","Permite a los conductores de CMV enviar mensajes de texto si están detenidos en un semáforo"],"explanation":"Los conductores de CMV están exentos de la ley estatal de manos libres porque la norma federal más estricta (en vigor desde 2012) ya prohíbe cualquier uso de teléfono de mano y el envío de mensajes de texto mientras se conduce un CMV. Fuente: Colorado SB24-065; FMCSA 49 CFR 392.80/392.82."},"53":{"q":"Según la norma federal que se aplica a los conductores de CMV de Colorado, ¿cuál es la multa máxima para el conductor por enviar mensajes de texto o usar un teléfono de mano mientras conduce un CMV?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Los conductores enfrentan sanciones civiles de hasta $2,750 (la cifra de $11,000 se aplica a los empleadores). Fuente: Norma de Teléfono Móvil/No Mensajes de Texto de la FMCSA, 49 CFR 392.80/392.82."},"54":{"q":"¿Cuál es la descalificación mínima de CDL por una PRIMERA violación de cruce ferroviario a nivel en Colorado?","options":["30 días","60 días","120 días","1 año"],"explanation":"Una primera violación de cruce ferroviario conlleva una descalificación mínima de 60 días. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"55":{"q":"¿Una SEGUNDA violación de cruce ferroviario a nivel dentro de 3 años resulta en qué descalificación mínima de CDL?","options":["60 días","90 días","120 días","1 año"],"explanation":"Una segunda violación de cruce ferroviario dentro de 3 años conlleva una descalificación mínima de 120 días. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"56":{"q":"¿Una TERCERA violación de cruce ferroviario a nivel, o posterior, dentro de 3 años resulta en qué descalificación mínima?","options":["120 días","180 días","1 año","3 años"],"explanation":"Tres o más violaciones de cruce ferroviario dentro de 3 años conllevan una descalificación mínima de 1 año. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"57":{"q":"¿Cuál es el rango de descalificación por una PRIMERA violación de una orden de fuera de servicio (OOS) por un conductor de CDL de Colorado que NO transporta materiales peligrosos ni pasajeros?","options":["30 a 60 días","Solo 90 días","180 días a 1 año","2 a 5 años"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de 180 días a 1 año para un conductor que no transporta materiales peligrosos ni pasajeros. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"58":{"q":"¿Una SEGUNDA violación de una orden de fuera de servicio dentro de 10 años (sin materiales peligrosos, sin pasajeros) resulta en qué rango de descalificación?","options":["120 días a 6 meses","180 días a 1 año","2 a 5 años","De por vida"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años conlleva una descalificación de 2 a 5 años. Fuente: Manual de CDL de Colorado, Sección 1; 49 CFR 383.51."},"59":{"q":"Según la ley 'Reduzca la velocidad, muévase' (Slow Down, Move Over) de Colorado, ¿qué debe hacer el conductor de un CMV al acercarse a una grúa detenida que muestra luces ámbar/amarillas intermitentes en una autopista con dos carriles en la misma dirección?","options":["Continuar a la velocidad indicada pero tocar la bocina","Cambiarse a un carril que esté al menos a un carril de circulación de distancia del vehículo detenido","Detenerse por completo hasta que la grúa se retire","Pasarse al acotamiento derecho y pasar despacio"],"explanation":"La ley de cambio de carril (Move Over) de Colorado (CRS 42-4-705) exige que los conductores en una autopista con al menos dos carriles en la misma dirección cedan el paso cambiándose a un carril que esté al menos a un carril de circulación de distancia de un vehículo de emergencia, de remolque o de servicio público detenido que muestre luces intermitentes. Fuente: Manual CDL de Colorado / CRS 42-4-705."},"60":{"q":"En una autopista de Colorado señalizada a 65 mph, el conductor de un CMV no puede cambiar de carril de forma segura por una patrulla detenida debido al tráfico intenso. ¿Qué velocidad presume el CRS 42-4-705 como segura?","options":["65 mph, ya que cambiarse de carril era imposible","Se presume segura 45 mph (20 mph por debajo de la velocidad indicada)","25 mph sin importar el límite indicado","Detenerse por completo hasta que el carril se despeje"],"explanation":"La ley de cambio de carril (Move Over) de Colorado (CRS 42-4-705) establece que, cuando un conductor no puede cambiarse de carril, en vías señalizadas a 45 mph o más se presume segura una velocidad de 20 mph por debajo del límite indicado (aquí 45 mph), y en vías por debajo de 45 mph se presume segura una velocidad de 25 mph o menos. Fuente: CRS 42-4-705."},"61":{"q":"Cuando se activan las señales de parada del autobús escolar de Colorado, ¿a qué distancia mínima antes de llegar al autobús debe detenerse un conductor que se aproxima?","options":["10 pies","15 pies","20 pies","50 pies"],"explanation":"El CRS 42-4-1903 exige que el conductor que se cruza o adelanta a un autobús escolar detenido con sus luces rojas de señalización visual activadas se detenga al menos 20 pies antes de llegar al autobús y no avance hasta que las luces dejen de estar activadas. Fuente: Manual CDL de Colorado / CRS 42-4-1903."},"62":{"q":"Según la ley de autobuses escolares de Colorado, ¿cuándo NO está obligado un conductor a detenerse ante un autobús escolar que está subiendo o bajando niños con sus luces rojas intermitentes?","options":["Siempre que el conductor circule a menos de 25 mph","Cuando el autobús está en una calzada distinta de una autopista dividida en calzadas separadas","Cuando hay más de un carril en la dirección del conductor","Siempre que el autobús esté dentro de un distrito comercial"],"explanation":"El CRS 42-4-1903 establece que un conductor en una autopista con calzadas separadas no necesita detenerse al cruzarse o pasar a un autobús escolar que está en una calzada distinta. En una vía no dividida, el tráfico en AMBAS direcciones debe detenerse. Fuente: CRS 42-4-1903."},"63":{"q":"Un conductor de Colorado que transporta materiales peligrosos con placas se acerca a un cruce de ferrocarril a nivel. ¿Dentro de qué distancia del riel más cercano debe detenerse el vehículo?","options":["Dentro de 50 pies pero no menos de 15 pies","Dentro de 100 pies pero no menos de 50 pies","Dentro de 25 pies pero no menos de 10 pies","Dentro de 75 pies pero no menos de 25 pies"],"explanation":"El CRS 42-4-707 exige que los vehículos con placas de materiales peligrosos, los autobuses escolares que transportan niños y los vehículos comerciales de pasajeros se detengan dentro de 50 pies pero no menos de 15 pies del riel más cercano, y luego miren y escuchen antes de avanzar. Fuente: Manual CDL de Colorado / CRS 42-4-707."},"64":{"q":"Mientras un CMV de Colorado con placas cruza las vías del ferrocarril después de detenerse, ¿qué restricción adicional aplica según el CRS 42-4-707?","options":["El conductor debe cruzar en reversa y luego hacia adelante para probar la tracción","El conductor no debe cambiar de marcha manualmente mientras cruza las vías","El conductor debe activar las luces de emergencia durante todo el cruce","El conductor debe cruzar solo a una velocidad menor a 5 mph"],"explanation":"El CRS 42-4-707 indica que el conductor solo debe cruzar si no hay necesidad de cambiar de marcha mientras atraviesa el cruce, y no debe cambiar de marcha manualmente mientras cruza las vías, lo que reduce el riesgo de quedarse parado sobre los rieles. Fuente: CRS 42-4-707."},"65":{"q":"¿En qué tipo de cruce de ferrocarril la ley de Colorado NO exige que un conductor con placas o de autobús haga la parada obligatoria?","options":["Cualquier cruce sin barreras automáticas","Un cruce controlado por un agente de policía o un encargado de tránsito humano que dirige el tráfico","Cualquier cruce en un distrito residencial","Un cruce con dos o más conjuntos de vías"],"explanation":"El CRS 42-4-707 exime de la parada obligatoria cuando un agente de policía o un encargado de tránsito humano dirige el tráfico, cuando una señal de control de tráfico dirige el tráfico, en cruces de tranvía en un distrito comercial y en cruces marcados con un letrero oficial de 'exento' (exempt). Fuente: CRS 42-4-707."},"66":{"q":"¿Cuál es el límite máximo de velocidad en una autopista pavimentada de cuatro carriles de Colorado que forma parte del sistema interestatal, a falta de un límite diferente señalizado?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"El CRS 42-4-1101 fija 65 mph en las autopistas pavimentadas de cuatro carriles del sistema interestatal como el máximo legal (CDOT puede señalizar límites mayores o menores en segmentos específicos). Fuente: CRS 42-4-1101."},"67":{"q":"¿Cómo trata la ley de Colorado el límite de velocidad para los camiones grandes en comparación con los autos de pasajeros en la misma autopista?","options":["Los camiones tienen un límite estatal aparte, 10 mph por debajo del de los autos","Los camiones deben mantenerse 15 mph por debajo del límite indicado en las pendientes","Los camiones siguen el mismo límite indicado; Colorado no tiene un límite de velocidad diferenciado general para camiones","Los camiones están limitados a 55 mph en todo el estado sin importar la señalización"],"explanation":"El estatuto de velocidad de Colorado (CRS 42-4-1101) no establece un límite de velocidad estatal aparte y menor para los camiones según su clase o peso; los CMV siguen los mismos límites indicados que los demás vehículos. Fuente: CRS 42-4-1101."},"68":{"q":"Según el CRS 42-4-1101, ¿cuál es el límite de velocidad prima facie en una 'autopista de montaña abierta' (open mountain highway) en Colorado?","options":["30 mph","40 mph","50 mph","55 mph"],"explanation":"El CRS 42-4-1101 incluye 40 mph en las autopistas de montaña abiertas (y 20 mph en las autopistas de montaña estrechas y sinuosas o en curvas sin visibilidad) entre los límites prima facie. Fuente: CRS 42-4-1101."},"69":{"q":"La ley de carriles para camiones de Colorado de 2024 prohíbe que los camiones de 16,000 lbs o más circulen por el carril del extremo izquierdo en ciertos puntos montañosos de la I-70. ¿Cuál de estos es una de esas áreas designadas?","options":["Monument Hill en la I-25","Vail Pass","Raton Pass en la I-25","El intercambiador de Grand Junction"],"explanation":"La restricción del carril izquierdo para camiones de Colorado prohíbe que los camiones de 16,000 lbs o más circulen por el carril del extremo izquierdo en segmentos de la I-70 que incluyen Floyd Hill, Georgetown Hill, el túnel Eisenhower, Dowd Junction y Vail Pass, donde hay al menos tres carriles en una dirección. Fuente: CDOT / ley de Colorado de 2024 (SB24-100)."},"70":{"q":"En los segmentos de la I-70 donde Colorado restringe a los camiones pesados del carril del extremo izquierdo, ¿qué excepción permite la ley?","options":["Los camiones pueden usar el carril izquierdo cuando el tráfico es ligero","Los camiones pueden usar el carril del extremo izquierdo para adelantar a otro vehículo","Los camiones pueden usar el carril izquierdo solo de noche","No hay excepción bajo ninguna condición"],"explanation":"La restricción del carril izquierdo para camiones de Colorado en los tramos montañosos designados de la I-70 sí permite que los camiones usen el carril del extremo izquierdo al adelantar; la prohibición apunta a la circulación sostenida por el carril izquierdo. Fuente: CDOT / ley de Colorado de 2024 (SB24-100)."},"71":{"q":"La ley de Colorado que obliga a los vehículos comerciales a 'llevar cadenas obligatoriamente' (Must-Carry) exige que los CMV lleven cadenas en el corredor montañoso de la I-70 durante cuál periodo anual?","options":["Del 1 de octubre al 30 de abril","Del 1 de septiembre al 31 de mayo","Del 1 de noviembre al 31 de marzo","Todo el año, sin ventana estacional"],"explanation":"La ley de Colorado de llevar cadenas obligatoriamente exige que los vehículos comerciales (GVWR de 16,001 lbs o más) lleven cadenas suficientes del 1 de septiembre al 31 de mayo en la I-70 entre Dotsero (MP 133) y Morrison (MP 259). Fuente: CDOT / CRS 42-4-106."},"72":{"q":"Cuando la Ley de Cadenas para Vehículos Comerciales de Colorado está en vigor, ¿cómo debe estar equipado un CMV con cuatro o más ruedas de tracción para poder avanzar?","options":["Cadenas o ATD en al menos cuatro de los neumáticos de las ruedas de tracción","Cadenas solo en los neumáticos de dirección","Cadenas en dos neumáticos cualesquiera a elección del conductor","Los neumáticos clasificados para nieve por sí solos siempre son suficientes"],"explanation":"Cuando la ley de cadenas está activa, un CMV debe tener cadenas o dispositivos de tracción alternativos en al menos cuatro de los neumáticos de las ruedas de tracción (o en todos los neumáticos de tracción si tiene menos de cuatro). Fuente: Ley de Cadenas de CDOT / CRS 42-4-106."},"73":{"q":"El corredor montañoso de la I-70 donde aplica la Ley de Cadenas para Vehículos Comerciales de Colorado se extiende entre cuáles dos puntos?","options":["Grand Junction (MP 26) y Denver (MP 275)","Dotsero (MP 133) y Morrison (MP 259)","Glenwood Springs (MP 116) y Golden (MP 263)","Vail (MP 176) e Idaho Springs (MP 240)"],"explanation":"El requisito de cadenas comerciales/llevar cadenas obligatoriamente de Colorado aplica en la I-70 entre la salida de Dotsero (Milla 133) y la salida de Morrison (Milla 259). Fuente: CDOT / CRS 42-4-106."},"74":{"q":"En la autopista interestatal de Colorado, después de detener un CMV en la parte transitable de la vía, ¿dentro de cuántos pies debe el conductor colocar los tres dispositivos de advertencia hacia el tráfico que se aproxima en una vía plana y recta?","options":["A 5, 50 y 100 pies","A 10, 100 y 200 pies","A 25, 150 y 300 pies","A 50, 250 y 500 pies"],"explanation":"Colorado sigue la norma federal FMCSR que exige colocar dispositivos de advertencia a 10 pies, 100 pies y 200 pies del CMV detenido hacia el tráfico que se aproxima en una vía no dividida y plana. Fuente: Manual CDL de Colorado / 49 CFR 392.22 (adoptado en Colorado)."},"75":{"q":"Un CMV de Colorado se ve obligado a detenerse en la vía justo después de una curva cerrada que lo oculta del tráfico que se aproxima. ¿Cómo deben ajustarse los dispositivos de advertencia?","options":["Colocar los tres dentro de 10 pies del parachoques trasero","Mover el dispositivo hacia la curva, de 100 a 500 pies atrás, para dar amplia advertencia","Omitir los dispositivos traseros y solo señalizar el frente","Colocar los tres en la línea central junto a la cabina"],"explanation":"Cuando el vehículo se detiene dentro de 500 pies de una curva, la cima de una colina u otra obstrucción de la visibilidad, el conductor mueve el dispositivo de advertencia en dirección de la obstrucción para que quede de 100 a 500 pies del vehículo, dando amplia advertencia. Fuente: Manual CDL de Colorado / 49 CFR 392.22."},"76":{"q":"La rampa de frenado de emergencia más utilizada de Colorado, en la I-70 en dirección oeste cerca del túnel Eisenhower, se describe mejor como cuál tipo de dispositivo?","options":["Un lecho de grava que usa agregado suelto y profundo para detener un camión sin frenos","Una red de cable de acero tendida a través del carril","Un amortiguador de impacto lleno de agua al pie de la pendiente","Una franja de frenado magnético incrustada en el pavimento"],"explanation":"La rampa Lower Straight Creek en la I-70 en dirección oeste es la rampa de frenado de emergencia más utilizada en EE. UU.; al igual que los demás lechos de frenado de Colorado, usa un lecho profundo de agregado triturado suelto (roca redondeada) para disipar la energía de un camión sin frenos. Fuente: CDOT / sección de manejo en montaña del Manual CDL de Colorado."},"77":{"q":"¿Cuál es el ANCHO máximo legal del vehículo en las autopistas de Colorado antes de requerir un permiso de sobredimensión de CDOT?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El límite legal de ancho de Colorado es de 8 pies 6 pulgadas (102 pulgadas); las cargas que excedan esto requieren un permiso de sobredimensión de CDOT, y las de más de 11 pies de ancho generalmente requieren un vehículo piloto/escolta delantero en las autopistas estatales designadas. Fuente: CDOT Freight & Permitting / CRS 42-4-502."},"78":{"q":"En una pendiente de montaña de Colorado, ¿cuál es la técnica de frenado correcta que debe usar el conductor de un CMV para evitar necesitar una rampa de frenado de emergencia?","options":["Mantener los frenos de servicio aplicados de manera constante durante todo el descenso","Seleccionar una marcha baja antes del descenso y usar aplicaciones de freno ligeras e intermitentes","Poner en neutro para ahorrar combustible y bajar en punto muerto","Aplicar la válvula manual del remolque de forma continua mientras se va en marcha alta"],"explanation":"La guía de manejo en montaña del Manual CDL de Colorado indica a los conductores seleccionar una marcha baja segura ANTES de comenzar a bajar una pendiente larga y usar los frenos de manera intermitente (frenado por golpes o snub braking) para que los frenos no se sobrecalienten ni pierdan eficacia; bajar en neutro es ilegal y peligroso. Fuente: Manual CDL de Colorado (Manejo en Montaña)."},"79":{"q":"¿Qué agencia de Colorado emite las licencias de conducir comerciales (CDL) y administra las pruebas de conocimientos requeridas?","options":["El Departamento de Transporte de Colorado (CDOT)","El Departamento de Ingresos de Colorado, División de Vehículos Motorizados (DMV)","La División de Puertos de Entrada de la Patrulla Estatal de Colorado","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Colorado, las CDL las emite la División de Vehículos Motorizados (DMV) del Departamento de Ingresos; las pruebas de conocimientos se toman en una oficina del DMV/Vehículos Motorizados de servicio completo. Fuente: Colorado DMV, dmv.colorado.gov (First-time CDL Driver / CDL General Information)."},"80":{"q":"¿Cuál es el puntaje mínimo para aprobar la prueba de Conocimientos Generales de la CDL de Colorado, que contiene 50 preguntas?","options":["70% (al menos 35 de 50 correctas)","75% (al menos 38 de 50 correctas)","90% (al menos 45 de 50 correctas)","80% (al menos 40 de 50 correctas)"],"explanation":"La prueba de Conocimientos Generales de la CDL de Colorado tiene 50 preguntas y requiere 80% — al menos 40 correctas — para aprobar, en concordancia con el Manual CDL de Colorado y los estándares de evaluación del DMV. Fuente: Colorado DMV / Manual CDL de Colorado."},"81":{"q":"La prueba de habilidades de la CDL de Colorado se compone de tres partes. ¿Cuál conjunto enumera correctamente esas tres partes?","options":["Conocimientos escritos, inspección previa al viaje y manejo en carretera","Verificación de frenos de aire, estacionamiento en paralelo y prueba de señales viales","Control básico del vehículo, evaluación de hazmat y manejo en carretera","Inspección previa al viaje, control básico del vehículo y manejo en carretera"],"explanation":"La prueba de habilidades de la CDL de Colorado tiene tres partes: la inspección previa al viaje, el control básico del vehículo (maniobras) y la prueba de manejo en carretera, reflejando la estructura federal de la prueba de habilidades de la CDL adoptada por Colorado. Fuente: Manual CDL de Colorado; Colorado DMV."},"82":{"q":"Antes de que un solicitante de CDL por primera vez en Colorado pueda tomar la prueba de habilidades, ¿qué capacitación obligatoria a nivel federal debe completarse y verificarse?","options":["Un curso de manejo defensivo aprobado por la Patrulla Estatal de Colorado","Un seminario de CDOT sobre aseguramiento de cargas de sobredimensión/sobrepeso","Capacitación de Conductor de Nivel de Entrada (ELDT) de un proveedor registrado ante la FMCSA","Una orientación de seguridad en aula del Departamento de Ingresos"],"explanation":"Desde el 7 de febrero de 2022, Colorado exige la Capacitación de Conductor de Nivel de Entrada (ELDT) completada a través de un proveedor registrado ante la FMCSA (registrada en el Training Provider Registry) antes de que un nuevo solicitante, un solicitante de ascenso de clase o un nuevo solicitante de aval H/P/S pueda tomar la prueba de habilidades. Fuente: Colorado DMV; 49 CFR Part 380 / FMCSA TPR."},"83":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Colorado, y puede renovarse?","options":["Válido por 180 días y renovable una vez","Válido por 60 días y renovable dos veces","Válido por cinco años y renovable anualmente","Válido por un año y no elegible para renovación"],"explanation":"Un CLP de Colorado es válido por un año y NO es renovable; si vence antes de obtener la CDL, el solicitante debe volver a tomar la(s) prueba(s) de conocimientos para un nuevo CLP. Fuente: Colorado DMV (CDL General Information / First-time CDL Driver)."},"84":{"q":"Después de que se le emite un Permiso de Aprendiz Comercial a un solicitante de Colorado, ¿cuánto tiempo debe tenerlo antes de poder tomar la prueba de habilidades de la CDL?","options":["Al menos 30 días calendario","Al menos 7 días calendario","Al menos 14 días calendario","Al menos 60 días calendario"],"explanation":"Colorado sigue la norma federal de que un CLP debe poseerse durante al menos 14 días calendario antes de que el titular pueda tomar la prueba de habilidades de la CDL. Fuente: 49 CFR 383.25; Colorado DMV."},"85":{"q":"Los solicitantes de CDL de Colorado deben completar una autocertificación que declara su tipo de manejo. ¿Cuántas categorías de autocertificación hay?","options":["Dos","Tres","Cinco","Cuatro"],"explanation":"Hay cuatro categorías de autocertificación: Interestatal No Exceptuado, Interestatal Exceptuado, Intraestatal No Exceptuado e Intraestatal Exceptuado. En Colorado esto se declara en el formulario DR 2904/DR 2907. Fuente: formulario DR 2904 de Colorado DMV; 49 CFR 383.71."},"86":{"q":"Un conductor de Colorado que opera en comercio interestatal y debe cumplir las reglas de calificación del conductor del 49 CFR Part 391 (y por lo tanto debe portar un certificado médico) debe autocertificarse bajo cuál categoría?","options":["Interestatal Exceptuado","Intraestatal No Exceptuado","Intraestatal Exceptuado","Interestatal No Exceptuado"],"explanation":"Un conductor que opera en comercio interestatal que está sujeto a y cumple los requisitos de calificación del 49 CFR Part 391 — y debe portar un certificado de examinador médico — se autocertifica como Interestatal No Exceptuado. Fuente: formulario DR 2904 de Colorado DMV; 49 CFR 383.71."},"87":{"q":"Para cumplir con el requisito médico del DOT, ¿qué documento debe obtener y presentar un solicitante de CDL de Colorado?","options":["Una nota de un médico general confirmando buena salud","Una tarjeta de aptitud física de la Patrulla Estatal de Colorado","Un Certificado de Examinador Médico de un proveedor en el Registro Nacional de la FMCSA","Una exención médica de permiso de CDOT"],"explanation":"La mayoría de los titulares de CDL de Colorado deben obtener un Certificado de Examinador Médico (tarjeta médica del DOT) de un examinador incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA. Fuente: Colorado DMV (CDL DOT Medical); FMCSA National Registry."},"88":{"q":"Para un conductor de CDL no exceptuado típico de Colorado, ¿cuál es la duración máxima de validez de un Certificado de Examinador Médico del DOT?","options":["Hasta dos años","Hasta cinco años","Hasta un año","Hasta tres años"],"explanation":"Un certificado de examinador médico del DOT se emite por un máximo de dos años (y puede ser más corto si el examinador anota una condición que requiere monitoreo). El conductor debe mantener un certificado vigente en el expediente del Colorado DMV. Fuente: 49 CFR 391.43; Colorado DMV (CDL DOT Medical)."},"89":{"q":"Si un conductor de CDL no exceptuado autocertificado de Colorado deja que el certificado médico en el expediente del DMV caduque, ¿cuál es la consecuencia típica?","options":["La CDL se revoca de manera inmediata y permanente","La CDL se degrada de modo que se eliminan los privilegios comerciales hasta que se presente un certificado médico vigente","No pasa nada hasta la renovación de la CDL a los cinco años","El conductor se reclasifica automáticamente como Interestatal Exceptuado"],"explanation":"Si el certificado médico de un conductor no exceptuado vence y no se presenta uno vigente, Colorado degrada la licencia, eliminando los privilegios de manejo comercial hasta que haya un certificado válido en el expediente. Fuente: Colorado DMV (CDL DOT Medical); 49 CFR 383.73."},"90":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Colorado para manejo comercial INTERESTATAL o para transportar materiales peligrosos con placas?","options":["21 años","18 años","19 años","25 años"],"explanation":"Colorado sigue el mínimo federal: un conductor debe tener 21 años para operar en comercio interestatal o para transportar materiales peligrosos con placas. Los conductores de 18 a 20 años están limitados a operación intraestatal. Fuente: Colorado DMV; 49 CFR 383."},"91":{"q":"Un titular de CDL de Colorado que tiene de 18 a 20 años está restringido a manejar únicamente dentro de Colorado. ¿Cuál código de restricción de licencia refleja este límite de solo intraestatal?","options":["Restricción \"K\" (solo intraestatal)","Restricción \"L\" (sin frenos de aire)","Restricción \"Z\" (sin frenos de aire completos)","Restricción \"E\" (sin transmisión manual)"],"explanation":"Colorado aplica la restricción \"K\" (solo intraestatal) a los titulares de CDL que no pueden operar en comercio interestatal, incluidos los conductores de 18 a 20 años. Fuente: Colorado DMV (CDL Restrictions)."},"92":{"q":"¿Cuál conjunto de documentos debe presentar en el DMV un solicitante de CDL por primera vez en Colorado?","options":["Solo una licencia de conducir regular vigente de Colorado","Comprobante de identidad, comprobante de presencia legal en EE. UU., comprobante de número de Seguro Social y comprobante de residencia en Colorado","Un pasaporte y un permiso de carga de CDOT","Solamente una carta del empleador y dos fotos tamaño pasaporte"],"explanation":"Los solicitantes de CDL de Colorado deben comprobar identidad, presencia legal en EE. UU., número de Seguro Social y domicilio residencial en Colorado (por ejemplo, una factura de servicios o un estado de cuenta bancario). Fuente: Colorado DMV (First-time CDL Driver)."},"93":{"q":"¿Cómo confirma el DMV la finalización del ELDT de un solicitante de CDL de Colorado antes de permitir la prueba de habilidades?","options":["El solicitante envía por correo un certificado en papel a CDOT para su aprobación","El solicitante lleva una declaración jurada notariada del instructor","El proveedor lo reporta electrónicamente al Training Provider Registry de la FMCSA, que el DMV consulta","La Patrulla Estatal de Colorado emite una carta de autorización de ELDT"],"explanation":"Los proveedores de ELDT registrados ante la FMCSA presentan los registros de finalización al Training Provider Registry (TPR) federal; el DMV de Colorado verifica el registro electrónicamente antes de permitir la prueba de habilidades. Fuente: Colorado DMV; FMCSA TPR / 49 CFR Part 380."},"94":{"q":"En el orden correcto, ¿cuáles son los primeros tres pasos principales para un solicitante de CDL por primera vez en Colorado?","options":["Tomar la prueba de habilidades, luego obtener el CLP, luego completar el ELDT","Aprobar la(s) prueba(s) de conocimientos y obtener el CLP, luego completar el ELDT, luego tomar la prueba de habilidades","Completar el ELDT, luego tomar la prueba de habilidades, luego aprobar la prueba de conocimientos","Obtener la tarjeta médica, luego tomar la prueba de habilidades, luego tomar la prueba de conocimientos"],"explanation":"La secuencia de Colorado es: aprobar la(s) prueba(s) de conocimientos requerida(s) y recibir el CLP, completar el ELDT aprobado por la FMCSA (teoría y práctica al volante), luego tomar la prueba de habilidades de tres partes (después del periodo de espera de 14 días del CLP). Fuente: Colorado DMV (First-time CDL Driver)."},"95":{"q":"Durante la parte de manejo en carretera de la prueba de habilidades de la CDL de Colorado, ¿qué evalúa principalmente el examinador?","options":["La capacidad del solicitante de operar el vehículo de forma segura en tráfico real sobre una ruta establecida","Si el solicitante puede recitar el contenido del manual de la CDL","Solamente la velocidad de estacionamiento en paralelo del solicitante","El cumplimiento del vehículo con los límites del permiso de sobredimensión/sobrepeso"],"explanation":"La prueba de manejo en carretera evalúa la operación segura en tráfico real sobre una ruta predeterminada — vueltas, intersecciones, cambios de carril y manejo general. El retroceso/las maniobras se califican en la parte aparte de control básico. Fuente: Manual CDL de Colorado; Colorado DMV."},"96":{"q":"Un conductor de Colorado transporta únicamente suministros agrícolas en su totalidad dentro de Colorado y está exento de partes de las reglas estatales de calificación del conductor. ¿Cuál categoría de autocertificación corresponde a este conductor?","options":["Intraestatal Exceptuado","Interestatal No Exceptuado","Interestatal Exceptuado","Intraestatal No Exceptuado"],"explanation":"Un conductor que opera únicamente dentro de Colorado y que está exceptuado de todos o parte de los requisitos estatales de calificación del conductor se autocertifica como Intraestatal Exceptuado y, por lo general, no está obligado a presentar un certificado médico del DOT. Fuente: formulario DR 2904 de Colorado DMV; 49 CFR 383.71."},"97":{"q":"Respecto a las tarifas de la CDL en Colorado, ¿cuál afirmación es la más precisa para una guía de estudio?","options":["Las pruebas de conocimientos y de habilidades de la CDL siempre son gratuitas en Colorado","Las tarifas están fijadas permanentemente por la ley federal y nunca cambian","Los montos específicos de las tarifas los establece el estado y pueden cambiar, por lo que los solicitantes deben confirmar las tarifas vigentes con el DMV","Solo el examen médico tiene una tarifa; el DMV no cobra nada por la licencia"],"explanation":"Colorado cobra tarifas por la evaluación y emisión de la CDL, pero los montos exactos los establece el estado y están sujetos a cambios; los solicitantes deben verificar las tarifas vigentes con el DMV en lugar de basarse en una cifra fija. Fuente: Colorado DMV (CDL General Information / fee schedule)."}},"hi":{"0":{"q":"कोलोराडो राजमार्गों पर, ओवरसाइज़ परमिट की आवश्यकता से पहले एक मानक वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई कितनी होती है (दर्पणों और आवश्यक सुरक्षा उपकरणों को छोड़कर)?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"कोलोराडो वाहन की चौड़ाई को 8 feet 6 inches (102 inches) तक सीमित करता है। क्लीयरेंस लाइटें, रियरव्यू दर्पण और अन्य आवश्यक सहायक उपकरण इस सीमा में नहीं गिने जाते। स्रोत: C.R.S. 42-4-502 (Width of vehicles)।"},"1":{"q":"कोलोराडो राजमार्गों पर किसी वाहन की, चाहे लदा हो या बिना लदे, अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["13 feet 6 inches","14 feet 0 inches","14 feet 6 inches","15 feet 0 inches"],"explanation":"कोई चालक ऐसा वाहन नहीं चला सकता, चाहे बिना लदे हो या लदान के साथ, जो 14 feet 6 inches की ऊँचाई से अधिक हो। स्रोत: C.R.S. 42-4-504 (Height and length of vehicles)।"},"2":{"q":"कोलोराडो कानून के तहत, एक एकल मोटर वाहन की अधिकतम कुल लंबाई कितनी होती है (आगे और पीछे के बंपर सहित)?","options":["40 feet","45 feet","53 feet","60 feet"],"explanation":"कोई एकल मोटर वाहन, आगे और पीछे के बंपर सहित, अत्यधिक कुल लंबाई में 45 feet से अधिक नहीं हो सकता। स्रोत: C.R.S. 42-4-504 (Height and length of vehicles)।"},"3":{"q":"कोलोराडो राजमार्गों पर एक साथ जुड़े वाहनों के संयोजन की अधिकतम कुल लंबाई कितनी होती है (बिना किसी विशेष परमिट के)?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"वाहनों का कोई संयोजन 70 feet की कुल लंबाई से अधिक नहीं हो सकता, और एक संयोजन में चार से अधिक इकाइयाँ नहीं हो सकतीं। स्रोत: C.R.S. 42-4-504 (Height and length of vehicles)।"},"4":{"q":"कोलोराडो में, न्यूमैटिक टायरों से सुसज्जित एकल एक्सल पर अनुमत अधिकतम वज़न है:","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,000 pounds"],"explanation":"जब किसी एकल एक्सल के पहिए न्यूमैटिक टायरों से सुसज्जित हों, तो अधिकतम लदान 20,000 pounds होता है। स्रोत: C.R.S. 42-4-507 (Wheel and axle loads)।"},"5":{"q":"कोलोराडो इंटरस्टेट राजमार्ग पर चल रहे टैंडम एक्सल समूह पर अनुमत अधिकतम वज़न कितना होता है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"इंटरस्टेट प्रणाली पर कोलोराडो संघीय टैंडम-एक्सल सीमा 36,000 pounds का पालन करता है। (गैर-इंटरस्टेट राज्य राजमार्गों पर टैंडम सीमा 40,000 pounds है।) स्रोत: C.R.S. 42-4-507 (Wheel and axle loads)।"},"6":{"q":"गैर-इंटरस्टेट कोलोराडो राज्य राजमार्ग पर, टैंडम एक्सल समूह पर अनुमत अधिकतम वज़न कितना होता है?","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"गैर-इंटरस्टेट राज्य राजमार्गों पर कोलोराडो टैंडम एक्सल पर 40,000 pounds तक की अनुमति देता है, जो 36,000-pound इंटरस्टेट सीमा से अधिक है। स्रोत: C.R.S. 42-4-507 (Wheel and axle loads)।"},"7":{"q":"कोलोराडो में इंटरस्टेट प्रणाली पर ओवरवेट परमिट के बिना अनुमत अधिकतम सकल वाहन वज़न कितना होता है?","options":["76,000 pounds","80,000 pounds","85,000 pounds","90,000 pounds"],"explanation":"इंटरस्टेट राजमार्गों पर कोलोराडो संघीय अधिकतम सकल वज़न 80,000 pounds लागू करता है, जो संघीय ब्रिज फॉर्मूला द्वारा नियंत्रित होता है। स्रोत: C.R.S. 42-4-508 (Gross weight of vehicles and loads)।"},"8":{"q":"राज्य वज़न तालिका के तहत, परमिट के बिना, कोलोराडो गैर-इंटरस्टेट (राज्य और स्थानीय) राजमार्गों पर अनुमत अधिकतम सकल वाहन वज़न कितना होता है?","options":["80,000 pounds","82,000 pounds","85,000 pounds","90,000 pounds"],"explanation":"गैर-इंटरस्टेट राजमार्गों पर कोलोराडो की अपनी सकल-वज़न तालिका 85,000 pounds तक की अनुमति देती है, जो 80,000-pound इंटरस्टेट सीमा से अधिक है। स्रोत: C.R.S. 42-4-508 (Gross weight of vehicles and loads)।"},"9":{"q":"कोलोराडो वज़न उद्देश्यों के लिए 'टैंडम एक्सल' को कैसे परिभाषित करता है?","options":["दो या अधिक लगातार एक्सल जो 40 inches से अधिक और 96 inches से अधिक नहीं की दूरी पर हों","ठीक 48 inches की दूरी पर स्थित दो एक्सल","कोई भी दो एक्सल जो 40 inches से कम दूरी पर हों","तीन या अधिक एक्सल जो 96 inches से अधिक दूरी पर हों"],"explanation":"टैंडम एक्सल दो या अधिक लगातार एक्सल होते हैं जिनके केंद्र समानांतर ऊर्ध्वाधर तलों के बीच आते हैं जो 40 inches से अधिक और 96 inches से अधिक नहीं की दूरी पर हों, और जो वाहन की पूरी चौड़ाई में फैले हों। स्रोत: C.R.S. 42-4-507 (Wheel and axle loads)।"},"10":{"q":"इंटरस्टेट प्रणाली पर एक्सल अंतराल के आधार पर अधिकतम अनुमेय सकल वज़न निर्धारित करने के लिए कोलोराडो किस फॉर्मूले का उपयोग करता है?","options":["राज्य माइलेज-टैक्स फॉर्मूला","संघीय ब्रिज फॉर्मूला (bridge gross weight formula)","केवल टायर-चौड़ाई-प्रति-इंच फॉर्मूला","बिना एक्सल अंतराल के एक निश्चित 80,000-pound सपाट नियम"],"explanation":"इंटरस्टेट राजमार्गों पर कोलोराडो संघीय ब्रिज फॉर्मूला का उपयोग करके प्रति एक्सल समूह सकल वज़न को सीमित करता है, जो अनुमेय वज़न को एक्सलों की संख्या और अत्यधिक एक्सलों के बीच की दूरी से जोड़ता है, और 80,000 pounds पर सीमित है। स्रोत: C.R.S. 42-4-508; संघीय 23 CFR 658 (bridge formula)।"},"11":{"q":"कोलोराडो के सामान्य (गैर-इंटरस्टेट) सकल वज़न फॉर्मूले W = 1,000(L + 40) में, 'L' किसका प्रतिनिधित्व करता है?","options":["वाहन पर एक्सलों की संख्या","टनों में कुल लदान वज़न","पहले और अंतिम एक्सल के केंद्रों के बीच की दूरी feet में","ट्रेलर की कानूनी लंबाई"],"explanation":"कोलोराडो के गैर-इंटरस्टेट सकल-वज़न फॉर्मूले W = 1,000(L + 40) में, 'L' समूह के पहले और अंतिम एक्सल के केंद्रों के बीच की दूरी feet में है, और W अधिकतम सकल वज़न pounds में है, जो 85,000 pounds से अधिक नहीं होना चाहिए। स्रोत: C.R.S. 42-4-508 (Gross weight of vehicles and loads)।"},"12":{"q":"कोलोराडो राज्य राजमार्ग पर 11 feet चौड़ा लदान ढो रहे एक चालक को निम्नलिखित में से क्या करना चाहिए?","options":["कुछ नहीं; 11 feet कानूनी चौड़ाई सीमा के भीतर है","CDOT ओवरसाइज़ परमिट प्राप्त करें क्योंकि लदान 8 feet 6 inches से अधिक है","केवल एक झंडा प्रदर्शित करें, किसी परमिट की आवश्यकता नहीं","सकल वज़न को घटाकर 80,000 pounds करें"],"explanation":"कानूनी 8 feet 6 inches से अधिक चौड़ा कोई भी लदान यात्रा से पहले CDOT से एक राज्य ओवरसाइज़ परमिट की आवश्यकता रखता है। 11-foot चौड़ा लदान ओवरसाइज़ है। स्रोत: C.R.S. 42-4-502 और 42-4-510; CDOT Permit Office।"},"13":{"q":"कोलोराडो में, राज्य राजमार्ग प्रणाली पर यात्रा के लिए ओवरसाइज़ और ओवरवेट परमिट किसके द्वारा जारी किए जाते हैं:","options":["Colorado Department of Revenue, Motor Vehicle Division","Colorado Department of Transportation (CDOT) Permit Office","जिस काउंटी से यात्रा शुरू होती है उसका शेरिफ","Federal Motor Carrier Safety Administration"],"explanation":"राज्य राजमार्ग प्रणाली के लिए ओवरसाइज़/ओवरवेट परमिट CDOT Permit Office द्वारा जारी किए जाते हैं, आमतौर पर ऑनलाइन COOPR (Colorado Oversize Overweight Permitting and Routing) प्रणाली के माध्यम से। स्रोत: C.R.S. 42-4-510; CDOT freight.colorado.gov।"},"14":{"q":"उस ऑनलाइन प्रणाली का नाम क्या है जिसका उपयोग कोलोराडो वाहकों के लिए ओवरसाइज़/ओवरवेट परमिट ऑर्डर करने और स्वीकृत मार्ग प्राप्त करने के लिए करता है?","options":["COOPR (Colorado Oversize Overweight Permitting and Routing)","IRP (International Registration Plan)","PRISM (Performance Registration Information Systems Management)","UCR (Unified Carrier Registration)"],"explanation":"कोलोराडो ओवरसाइज़/ओवरवेट परमिट COOPR प्रणाली के माध्यम से जारी करता है, जहाँ वाहक ऑनलाइन आवेदन करते हैं, शुल्क का भुगतान करते हैं और रूटिंग प्राप्त करते हैं; कई परमिट स्वयं जारी किए जा सकते हैं। स्रोत: CDOT, coopr.codot.gov; C.R.S. 42-4-510।"},"15":{"q":"कोलोराडो ओवरसाइज़ परमिट के तहत, ढीली घास (गोल गाँठों सहित) को कितनी चौड़ाई तक ढोया जा सकता है?","options":["8 feet 6 inches","10 feet 6 inches","12 feet","14 feet"],"explanation":"कोलोराडो का चौड़ाई कानून ढीली घास को, गोल गाँठों सहित, 12 feet चौड़ाई तक परिवहन करने की अनुमति देता है; आयताकार (गठरीदार) घास 10 feet 6 inches तक सीमित है। स्रोत: C.R.S. 42-4-502 (Width of vehicles)।"},"16":{"q":"कोलोराडो राजमार्गों पर, स्टील-टायर वाले वाहन के किसी एक पहिए पर, टायर के क्रॉस-सेक्शनल चौड़ाई के प्रति इंच, अधिकतम वज़न कितना होता है?","options":["300 pounds per inch","500 pounds per inch","650 pounds per inch","800 pounds per inch"],"explanation":"स्टील-टायर वाले वाहन के किसी एक पहिए पर सकल वज़न टायर की क्रॉस-सेक्शनल चौड़ाई के 500 pounds per inch से अधिक नहीं हो सकता। स्रोत: C.R.S. 42-4-507 (Wheel and axle loads)।"},"17":{"q":"कोलोराडो कुछ वैकल्पिक-ईंधन वाहनों को, भारी ईंधन/पावर प्रणाली के लिए, मानक अधिकतम सकल और एक्सल वज़न सीमाओं से कितना अधिक होने की अनुमति देता है?","options":["400 pounds तक","1,000 pounds तक","2,000 pounds तक","5,000 pounds तक"],"explanation":"कोलोराडो वैकल्पिक ईंधन से चलने वाले वाहनों को सकल और एक्सल वज़न सीमाओं से 2,000 pounds तक अधिक होने की अनुमति देता है, जो संघीय प्राकृतिक गैस/इलेक्ट्रिक वाहन वज़न भत्ते के अनुरूप है। स्रोत: C.R.S. 42-4-508 (Gross weight of vehicles and loads)।"},"18":{"q":"जब कोलोराडो में वाहनों का संयोजन लदा हुआ हो, तो संयोजन के प्रत्येक वाहन को आमतौर पर कुल सकल वज़न का कम से कम कितना हिस्सा वहन करना चाहिए (कुछ यूटिलिटी/पोल ट्रेलरों के लिए सीमित अपवादों के साथ)?","options":["कुल सकल वज़न का कम से कम 5 प्रतिशत","कुल सकल वज़न का कम से कम 10 प्रतिशत","कुल सकल वज़न का कम से कम 25 प्रतिशत","कुल सकल वज़न का कम से कम 50 प्रतिशत"],"explanation":"वाहन संयोजन में, प्रत्येक वाहन को कुल सकल वज़न का कम से कम 10 प्रतिशत वहन करना चाहिए, सिवाय निश्चित यूटिलिटी लदान या पोल ढोने के लिए उपयोग किए जाने वाले विशेष ट्रेलरों के। स्रोत: C.R.S. 42-4-508 (Gross weight of vehicles and loads)।"},"19":{"q":"कोलोराडो का एक शांति अधिकारी जो मानता है कि कोई वाहन ओवरवेट है, चालक को तौले जाने की आवश्यकता दे सकता है और, यदि वाहन कानूनी सीमा से अधिक है, तो चालक से क्या करवा सकता है?","options":["वाणिज्यिक चालक लाइसेंस तुरंत समर्पित करें","सकल वज़न को कानूनी सीमा तक लाने के लिए पर्याप्त माल उतारें","आगे बढ़ने से पहले मौके पर नकद में ओवरवेट जुर्माना भरें","गंतव्य तक जारी रखें और 24 घंटे के भीतर पोर्ट ऑफ एंट्री पर रिपोर्ट करें"],"explanation":"वाहन के ओवरवेट होने का विश्वास करने का कारण रखने वाला अधिकारी इसे पोर्टेबल या स्थिर तराजू पर (या पाँच मील के भीतर नज़दीकी सार्वजनिक तराजू पर) तौले जाने की आवश्यकता दे सकता है और, यदि यह गैर-कानूनी रूप से ओवरवेट है, तो चालक से सकल वज़न को कानूनी सीमा तक घटाने के लिए पर्याप्त लदान हटाने की आवश्यकता दे सकता है। स्रोत: C.R.S. 42-4-509 (Vehicles weighed - excess removed)।"},"20":{"q":"कोलोराडो में, 26,001 pounds या अधिक की Gross Combination Weight Rating (GCWR) वाले वाहनों के किसी भी संयोजन को चलाने के लिए, जहाँ खींचे जा रहे वाहन का GVWR 10,000 pounds से अधिक हो, कौन सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"कोलोराडो एक Class A CDL को 26,001 lbs या अधिक की GCWR वाले वाहनों के किसी भी संयोजन के रूप में परिभाषित करता है, बशर्ते खींची गई इकाई का GVWR 10,000 lbs से अधिक हो। स्रोत: Colorado CDL Manual (Colorado DMV/Dept. of Revenue), CDL श्रेणी परिभाषाएँ; C.R.S. 42-2-402।"},"21":{"q":"कौन सी कोलोराडो CDL श्रेणी 26,001 pounds या अधिक GVWR वाले एक एकल वाहन को कवर करती है जो 10,000 pounds GVWR से अधिक न होने वाले किसी अन्य वाहन को खींच सकता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"कोलोराडो में 26,001 lbs या अधिक GVWR वाले किसी भी एकल वाहन के लिए Class B CDL आवश्यक है, जो 10,000 lbs GVWR से अधिक न होने वाली इकाई को खींच सकता है। स्रोत: Colorado CDL Manual (Colorado DMV), श्रेणी परिभाषाएँ।"},"22":{"q":"एक चालक 26,001 pounds GVWR से कम का एक एकल वाहन चलाता है जो चालक सहित 18 यात्रियों को ले जाने के लिए डिज़ाइन किया गया है। कौन सी कोलोराडो CDL श्रेणी आवश्यक है?","options":["किसी CDL की आवश्यकता नहीं","Class A","Class B","Class C"],"explanation":"एक Class C CDL उन वाहनों को कवर करती है जो Class A या B वज़न परिभाषाओं को पूरा नहीं करते लेकिन 16 या अधिक यात्रियों (चालक सहित) को परिवहन करने के लिए डिज़ाइन किए गए हैं या प्लेकार्ड किए गए खतरनाक पदार्थ ले जाते हैं। स्रोत: Colorado CDL Manual (Colorado DMV), श्रेणी परिभाषाएँ।"},"23":{"q":"प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक पदार्थ परिवहन करने के लिए एक कोलोराडो CDL धारक को कौन सा एंडोर्समेंट प्राप्त करना चाहिए?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"प्लेकार्ड किए गए खतरनाक पदार्थ ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है। कोलोराडो में इसके लिए HazMat ज्ञान परीक्षा पास करना, ELDT सिद्धांत पूरा करना और एक TSA सुरक्षा खतरा मूल्यांकन पास करना आवश्यक है। स्रोत: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383।"},"24":{"q":"केवल इंट्रास्टेट (राज्य के भीतर) ड्राइविंग के लिए कोलोराडो CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years old","18 years old","19 years old","21 years old"],"explanation":"कोलोराडो केवल इंट्रास्टेट संचालन के लिए 18 वर्ष की आयु में CDL की अनुमति देता है। 18 से 20 वर्ष के चालकों को एक 'K' प्रतिबंध मिलता है जो उन्हें कोलोराडो के भीतर ड्राइविंग तक सीमित करता है। स्रोत: Colorado DMV; C.R.S. 42-2-403।"},"25":{"q":"इंटरस्टेट (राज्य सीमाओं के पार) ड्राइविंग के लिए मान्य कोलोराडो CDL प्राप्त करने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"इंटरस्टेट वाणिज्यिक ड्राइविंग के लिए न्यूनतम आयु 21 आवश्यक है। 18 से 20 वर्ष के चालक 'K' प्रतिबंध (केवल इंट्रास्टेट) वाला CDL रखते हैं। स्रोत: Colorado DMV; FMCSA 49 CFR 391.11।"},"26":{"q":"कोलोराडो में अपनाए गए संघीय नियमों के तहत, CDL कौशल परीक्षा देने के लिए पात्र होने से पहले एक Commercial Learner Permit (CLP) को कितने समय तक रखा जाना चाहिए?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 60 days","कम से कम 180 days"],"explanation":"एक CLP धारक CLP के प्रारंभिक जारी होने के बाद कम से कम 14 days बीतने तक CDL कौशल परीक्षा नहीं दे सकता। स्रोत: FMCSA 49 CFR 383.25, Colorado DMV द्वारा लागू।"},"27":{"q":"एक कोलोराडो चालक के लिए कौन सा एंडोर्समेंट आवश्यक है जो 1,000 gallons या अधिक की कुल रेटेड क्षमता वाले तरल पदार्थ को थोक में ले जाने वाला टैंक वाहन ढोता है?","options":["H endorsement","N endorsement","T endorsement","S endorsement"],"explanation":"119 gallons से अधिक की व्यक्तिगत रेटेड क्षमता और 1,000 gallons या अधिक की कुल रेटेड क्षमता वाले टैंकों वाले टैंक वाहन को चलाने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। इसके लिए टैंकर ज्ञान परीक्षा पास करना आवश्यक है। स्रोत: Colorado DMV CDL Endorsements; 49 CFR 383.5।"},"28":{"q":"एक कोलोराडो चालक डबल या ट्रिपल ट्रेलर खींचने के लिए T एंडोर्समेंट चाहता है। इसे जोड़ने के लिए चालक को क्या करना चाहिए?","options":["केवल एक ज्ञान (लिखित) परीक्षा पास करें","एक ज्ञान परीक्षा और एक कौशल परीक्षा पास करें","एक TSA पृष्ठभूमि जाँच पास करें","बिहाइंड-द-व्हील ELDT प्रशिक्षण पूरा करें"],"explanation":"T (Doubles/Triples) एंडोर्समेंट के लिए कोलोराडो में केवल doubles/triples ज्ञान परीक्षा पास करना आवश्यक है; किसी अलग कौशल परीक्षा की आवश्यकता नहीं है। इसे एक Class A CDL में जोड़ा जा सकता है। स्रोत: Colorado DMV CDL Endorsements & Requirements।"},"29":{"q":"एक वाणिज्यिक वाहन में 16 या अधिक यात्रियों (चालक सहित) को परिवहन करने के लिए एक कोलोराडो चालक को कौन सा एंडोर्समेंट चाहिए?","options":["S endorsement","N endorsement","P endorsement","H endorsement"],"explanation":"चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। कोलोराडो में इसके लिए यात्री ज्ञान परीक्षा, ELDT, और एक यात्री वाहन में कौशल परीक्षा आवश्यक है। स्रोत: Colorado DMV CDL Endorsements & Requirements।"},"30":{"q":"कोलोराडो में, कौन सा एंडोर्समेंट एक पूर्वापेक्षा है जिसे School Bus (S) एंडोर्समेंट के साथ (या उससे पहले) प्राप्त किया जाना चाहिए?","options":["N (Tanker) endorsement","P (Passenger) endorsement","H (HazMat) endorsement","T (Doubles/Triples) endorsement"],"explanation":"P (Passenger) एंडोर्समेंट S (School Bus) एंडोर्समेंट के लिए एक पूर्वापेक्षा है; एक आवेदक P के बिना S नहीं रख सकता। स्रोत: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383.93।"},"31":{"q":"कौन सी इकाई उस रजिस्ट्री को बनाए रखती है जिस पर एक कोलोराडो CDL आवेदक के Entry-Level Driver Training (ELDT) प्रदाता का सूचीबद्ध होना आवश्यक है?","options":["Colorado Department of Education","FMCSA Training Provider Registry","Colorado State Patrol","Transportation Security Administration"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता के माध्यम से पूरा किया जाना चाहिए; Colorado DMV कौशल/ज्ञान परीक्षा की अनुमति देने से पहले TPR के माध्यम से पूर्णता सत्यापित करता है। स्रोत: FMCSA TPR; Colorado DMV।"},"32":{"q":"निम्नलिखित में से किसके लिए ELDT (Entry-Level Driver Training) में बिहाइंड-द-व्हील प्रशिक्षण शामिल करने के बजाय, ज्ञान परीक्षा से पहले पूरा किया गया केवल सिद्धांत प्रशिक्षण शामिल होता है?","options":["पहली बार Class A CDL","पहली बार Class B CDL","H (HazMat) endorsement","P (Passenger) endorsement"],"explanation":"H (HazMat) एंडोर्समेंट के लिए, ELDT केवल सिद्धांत है और HazMat ज्ञान परीक्षा देने से पहले पूरा किया जाना चाहिए। Class A, B, P, और S के लिए सिद्धांत और बिहाइंड-द-व्हील ELDT दोनों आवश्यक हैं। स्रोत: FMCSA 49 CFR 380 Subpart F; FMCSA TPR।"},"33":{"q":"कोलोराडो HazMat (H) एंडोर्समेंट जारी या नवीनीकृत किए जाने से पहले, आवेदक को कौन सी अतिरिक्त मंज़ूरी प्राप्त करनी चाहिए?","options":["एक DOT चिकित्सा छूट","एक TSA Security Threat Assessment (पृष्ठभूमि जाँच)","एक Colorado Department of Education AIM पंजीकरण","एक SAE Level 2 निरीक्षण प्रमाणपत्र"],"explanation":"H एंडोर्समेंट के आवेदकों को एंडोर्समेंट जारी या नवीनीकृत किए जाने से पहले एक TSA Security Threat Assessment पास करना होगा, जिसमें फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच शामिल होती है। स्रोत: TSA/FMCSA 49 CFR 1572; Colorado DMV CDL FAQ।"},"34":{"q":"कोलोराडो CDL या CLP के लिए आवेदन करते समय, आवेदक को कोलोराडो पते (निवास) के कितने प्रमाण प्रस्तुत करने होंगे?","options":["पते का एक प्रमाण","पते के दो प्रमाण","पते के तीन प्रमाण","पते के किसी प्रमाण की आवश्यकता नहीं"],"explanation":"Colorado DMV को पहचान के प्रमाण के अतिरिक्त, पिछले वर्ष के भीतर दिनांकित, कोलोराडो पता सिद्ध करने वाले दो दस्तावेज़ों की आवश्यकता होती है। स्रोत: Colorado DMV Required Identification Documents।"},"35":{"q":"पहचान और कोलोराडो निवास के प्रमाण के अतिरिक्त, एक कोलोराडो CDL आवेदक को आवेदन पर और क्या प्रदान करना चाहिए?","options":["केवल एक पासपोर्ट","अपने Social Security number का प्रमाण","एक नोटरीकृत नियोक्ता पत्र","दो चरित्र संदर्भ"],"explanation":"कोलोराडो आवेदकों से, पहचान और वैध उपस्थिति/निवास दस्तावेज़ों के साथ, अपना Social Security कार्ड या अपने Social Security number का अन्य स्वीकार्य प्रमाण प्रस्तुत करने की आवश्यकता रखता है। स्रोत: Colorado DMV Required Identification Documents।"},"36":{"q":"निम्नलिखित में से कौन सा चार संघीय चिकित्सा स्व-प्रमाणन श्रेणियों में से एक है जिनमें से एक कोलोराडो CDL धारक को चुनना होगा?","options":["Non-Excepted Interstate","Placarded Interstate","Restricted Intrastate","Conditional Interstate"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। संघीय शारीरिक योग्यता नियमों के अधीन एक चालक Non-Excepted Interstate चुनता है। स्रोत: FMCSA 49 CFR 383.71; Colorado DMV।"},"37":{"q":"एक कोलोराडो CDL धारक जो केवल कोलोराडो के भीतर ड्राइव करता है लेकिन फिर भी चिकित्सा योग्यता मानकों को पूरा करना चाहिए, उसे किस श्रेणी के तहत स्व-प्रमाणित करना चाहिए?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"केवल कोलोराडो के भीतर संचालित करने वाला एक चालक जिसे फिर भी चिकित्सा मानकों को पूरा करना आवश्यक है, Non-Excepted Intrastate (NA) के रूप में स्व-प्रमाणित करता है। स्रोत: FMCSA 49 CFR 383.71; Colorado DMV स्व-प्रमाणन श्रेणियाँ।"},"38":{"q":"TSA पृष्ठभूमि जाँच के अलावा, एक कोलोराडो चालक को CDL में HazMat (H) एंडोर्समेंट जोड़ने के लिए क्या करना चाहिए?","options":["एक HazMat ज्ञान (लिखित) परीक्षा पास करें","केवल एक HazMat कौशल/रोड परीक्षा पास करें","एक doubles/triples निरीक्षण रिपोर्ट जमा करें","पहले एक CLP पर एक वर्ष के लिए एंडोर्समेंट रखें"],"explanation":"H एंडोर्समेंट जोड़ने के लिए HazMat ज्ञान परीक्षा पास करना आवश्यक है (साथ ही ELDT सिद्धांत और एक TSA Security Threat Assessment); कोई अलग HazMat कौशल परीक्षा नहीं है। स्रोत: Colorado DMV CDL Endorsements & Requirements; 49 CFR 383।"},"39":{"q":"कोलोराडो में एक वाणिज्यिक मोटर वाहन चलाते समय अनुमत अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है?","options":["0.02","0.04","0.08","0.10"],"explanation":"कोलोराडो में एक चालक 0.04 या अधिक के BAC के साथ CMV नहीं चला सकता - जो गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा का आधा है। स्रोत: Colorado CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51।"},"40":{"q":"कोलोराडो के निहित-सहमति कानून के तहत, यदि कोई CDL धारक अल्कोहल या नशीली दवाओं के लिए रासायनिक परीक्षण कराने से इनकार करता है तो क्या होता है?","options":["बिना किसी अयोग्यता के एक चेतावनी जारी की जाती है","CDL को पहले प्रमुख अपराध के समान अवधि के लिए अयोग्य ठहराया जाता है","केवल एक जुर्माना लगाया जाता है","लाइसेंस 30 days के लिए निलंबित किया जाता है"],"explanation":"आवश्यक परीक्षण से इनकार करना कोलोराडो में एक प्रमुख अपराध माना जाता है, जो 1-year की अयोग्यता (प्लेकार्ड किए गए खतरनाक पदार्थ ढोने पर 3 years) रखता है - पहले DUI/BAC उल्लंघन के समान। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51; C.R.S. 42-2-126।"},"41":{"q":"पहले प्रमुख अपराध के लिए, जैसे कि 0.04 या अधिक के BAC के साथ CMV चलाना, एक कोलोराडो CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है (जब प्लेकार्ड किए गए खतरनाक पदार्थ नहीं ढो रहे हों)?","options":["60 days","6 months","1 year","3 years"],"explanation":"एक पहला प्रमुख अपराध कोलोराडो में 1-year की CDL अयोग्यता में परिणत होता है। स्रोत: Colorado CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51।"},"42":{"q":"यदि चालक उस समय प्लेकार्ड किए गए खतरनाक पदार्थ परिवहन कर रहा था, तो पहले प्रमुख अपराध के लिए अयोग्यता कितनी लंबी होती है?","options":["1 year","2 years","3 years","5 years"],"explanation":"प्लेकार्ड किए गए खतरनाक पदार्थ परिवहन करते समय एक पहला प्रमुख अपराध कोलोराडो में अयोग्यता को 3 years तक बढ़ा देता है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"43":{"q":"एक कोलोराडो CDL धारक द्वारा किए गए दूसरे प्रमुख अपराध (उदाहरण के लिए, दूसरा DUI) के लिए अयोग्यता क्या है?","options":["3 years","5 years","10 years","आजीवन"],"explanation":"एक दूसरा प्रमुख अपराध कोलोराडो में आजीवन CDL अयोग्यता में परिणत होता है, हालाँकि कुछ शर्तों के तहत 10 years के बाद पुनर्बहाली संभव हो सकती है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"44":{"q":"निम्नलिखित में से किसे एक कोलोराडो CDL धारक के लिए 'प्रमुख अपराध' के रूप में वर्गीकृत किया गया है?","options":["आगे चल रहे वाहन का बहुत निकट से पीछा करना","एक CMV से जुड़ी दुर्घटना के स्थल को छोड़ना","सीमा से 15 mph अधिक गति करना","एक अनुचित लेन परिवर्तन"],"explanation":"दुर्घटना के स्थल को छोड़ना एक प्रमुख अपराध है (पहले पर 1-year / दूसरे पर आजीवन अयोग्यता)। अन्य विकल्प गंभीर यातायात उल्लंघन हैं, प्रमुख अपराध नहीं। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"45":{"q":"किसी अपराध (felony) को करने के लिए एक वाणिज्यिक मोटर वाहन का उपयोग करना कोलोराडो CDL नियमों के तहत माना जाता है एक:","options":["गंभीर यातायात उल्लंघन","प्रमुख अपराध","आउट-ऑफ-सर्विस उल्लंघन","रेलरोड-क्रॉसिंग उल्लंघन"],"explanation":"किसी अपराध (felony) के दौरान एक CMV का उपयोग करना एक प्रमुख अपराध है, जो पहली दोषसिद्धि के लिए 1-year की अयोग्यता और दूसरी के लिए आजीवन रखता है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"46":{"q":"किसी भी गंभीर यातायात उल्लंघन के लिए पहली दोषसिद्धि के परिणामस्वरूप कोलोराडो में क्या CDL अयोग्यता होती है?","options":["कोई अयोग्यता नहीं","30 days","60 days","120 days"],"explanation":"एक अकेला गंभीर यातायात उल्लंघन अपने आप किसी चालक को अयोग्य नहीं ठहराता; अयोग्यता केवल 3 years के भीतर ऐसे दूसरे या तीसरे उल्लंघन से शुरू होती है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"47":{"q":"एक 3-year की अवधि के भीतर किए गए दूसरे गंभीर यातायात उल्लंघन के लिए एक कोलोराडो CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है?","options":["30 days","60 days","120 days","1 year"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघन 60-day की अयोग्यता में परिणत होते हैं। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"48":{"q":"एक 3-year की अवधि के भीतर तीसरे गंभीर यातायात उल्लंघन के लिए अयोग्यता कितनी लंबी होती है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर तीन गंभीर यातायात उल्लंघन 120-day की अयोग्यता में परिणत होते हैं। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"49":{"q":"पोस्ट की गई सीमा से कितनी गति पर एक गति उल्लंघन एक कोलोराडो CDL धारक के लिए 'गंभीर यातायात उल्लंघन' के रूप में गिना जाता है?","options":["10 mph or more over","15 mph or more over","20 mph or more over","25 mph or more over"],"explanation":"पोस्ट की गई गति सीमा से 15 mph or more above गति करना एक गंभीर यातायात उल्लंघन है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"50":{"q":"निम्नलिखित में से किसे एक कोलोराडो CDL धारक के लिए गंभीर यातायात उल्लंघन के रूप में नहीं गिना जाता है?","options":["लापरवाह ड्राइविंग","बहुत निकट से पीछा करना","0.04 के BAC के साथ CMV चलाना","अनियमित या अनुचित लेन परिवर्तन"],"explanation":"0.04 या अधिक के BAC के साथ ड्राइविंग एक प्रमुख अपराध है, गंभीर यातायात उल्लंघन नहीं। लापरवाह ड्राइविंग, बहुत निकट से पीछा करना और अनुचित लेन परिवर्तन गंभीर यातायात उल्लंघन हैं। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"51":{"q":"एक CMV चलाते समय बार-बार टेक्स्टिंग करना या हैंड-हेल्ड मोबाइल फोन का उपयोग करना कोलोराडो CDL नियमों के तहत वर्गीकृत किया जाता है एक:","options":["प्रमुख अपराध","गंभीर यातायात उल्लंघन","आउट-ऑफ-सर्विस उल्लंघन","गैर-अयोग्य करने वाला उल्लंघन"],"explanation":"एक CMV चलाते समय टेक्स्टिंग करना या हैंड-हेल्ड फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है; 3 years के भीतर कई दोषसिद्धियाँ 60/120-day की अयोग्यताओं को ट्रिगर करती हैं। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51, 392.80/392.82।"},"52":{"q":"कोलोराडो का 2025 हैंड्स-फ्री राज्य कानून (SB24-065) आमतौर पर हैंड-हेल्ड डिवाइस के उपयोग पर प्रतिबंध लगाता है, लेकिन यह CMV चलाने वाले CDL चालकों पर कैसे लागू होता है?","options":["CDL चालक छूट प्राप्त हैं क्योंकि सख्त संघीय नियम पहले से ही हैंड-हेल्ड फोन के उपयोग पर प्रतिबंध लगाते हैं","यह CMV चालकों के लिए संघीय नियम को पूरी तरह से प्रतिस्थापित करता है","यह कोलोराडो में किसी भी चालक पर लागू नहीं होता","यह CMV चालकों को लाइट पर रुके होने पर टेक्स्ट करने की अनुमति देता है"],"explanation":"CMV चालक राज्य हैंड्स-फ्री कानून से छूट प्राप्त हैं क्योंकि अधिक कठोर संघीय नियम (2012 से प्रभावी) पहले से ही एक CMV चलाते समय किसी भी हैंड-हेल्ड फोन के उपयोग और टेक्स्टिंग पर प्रतिबंध लगाता है। स्रोत: Colorado SB24-065; FMCSA 49 CFR 392.80/392.82।"},"53":{"q":"कोलोराडो CMV चालकों पर लागू होने वाले संघीय नियम के तहत, एक CMV चलाते समय टेक्स्टिंग करने या हैंड-हेल्ड फोन का उपयोग करने के लिए अधिकतम चालक जुर्माना क्या है?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"चालकों को $2,750 तक के नागरिक दंड का सामना करना पड़ता है ($11,000 का आँकड़ा नियोक्ताओं पर लागू होता है)। स्रोत: FMCSA Mobile Phone/No-Texting rule, 49 CFR 392.80/392.82।"},"54":{"q":"कोलोराडो में पहले रेलरोड हाईवे-ग्रेड-क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["30 days","60 days","120 days","1 year"],"explanation":"एक पहला रेलरोड-क्रॉसिंग उल्लंघन न्यूनतम 60-day की अयोग्यता रखता है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"55":{"q":"3 years के भीतर एक दूसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन क्या न्यूनतम CDL अयोग्यता में परिणत होता है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर एक दूसरा रेलरोड-क्रॉसिंग उल्लंघन न्यूनतम 120-day की अयोग्यता रखता है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"56":{"q":"3 years के भीतर एक तीसरा या बाद का रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन क्या न्यूनतम अयोग्यता में परिणत होता है?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 years के भीतर तीन या अधिक रेलरोड-क्रॉसिंग उल्लंघन न्यूनतम 1-year की अयोग्यता रखते हैं। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"57":{"q":"हैज़मैट या यात्रियों को न ढोने वाले एक कोलोराडो CDL चालक द्वारा एक आउट-ऑफ-सर्विस (OOS) आदेश के पहले उल्लंघन के लिए अयोग्यता सीमा क्या है?","options":["30 to 60 days","केवल 90 days","180 days to 1 year","2 to 5 years"],"explanation":"हैज़मैट या यात्रियों का परिवहन न करने वाले चालक के लिए एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन 180 days to 1 year की अयोग्यता में परिणत होता है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"58":{"q":"10 years के भीतर एक दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन (गैर-हैज़मैट, गैर-यात्री) क्या अयोग्यता सीमा में परिणत होता है?","options":["120 days to 6 months","180 days to 1 year","2 to 5 years","आजीवन"],"explanation":"10 years के भीतर एक दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन 2- to 5-year की अयोग्यता रखता है। स्रोत: Colorado CDL Manual, Section 1; 49 CFR 383.51।"},"59":{"q":"कोलोराडो के 'स्लो डाउन, मूव ओवर' कानून के तहत, एक ही दिशा में दो लेन वाले राजमार्ग पर चमकती एम्बर/पीली बत्ती दिखाने वाले स्थिर टो ट्रक के पास पहुँचते समय CMV के चालक को क्या करना चाहिए?","options":["तय की गई गति पर चलते रहें लेकिन हॉर्न बजाएँ","स्थिर वाहन से कम से कम एक चलती लेन की दूरी वाली लेन में चले जाएँ","जब तक टो ट्रक हट न जाए तब तक पूरी तरह रुक जाएँ","दाईं ओर के शोल्डर पर जाकर धीरे-धीरे आगे निकल जाएँ"],"explanation":"कोलोराडो का मूव ओवर कानून (CRS 42-4-705) एक ही दिशा में कम से कम दो लेन वाले राजमार्ग पर चालकों से यह माँग करता है कि वे चमकती बत्ती दिखाने वाले स्थिर आपातकालीन, टोइंग या सार्वजनिक-उपयोगिता वाहन से कम से कम एक चलती लेन की दूरी वाली लेन में जाकर रास्ता दें। स्रोत: Colorado CDL Manual / CRS 42-4-705।"},"60":{"q":"65 mph पर तय की गई कोलोराडो राजमार्ग पर, भारी यातायात के कारण एक CMV चालक रुकी हुई गश्ती कार के लिए सुरक्षित रूप से लेन नहीं बदल सकता। CRS 42-4-705 किस गति को सुरक्षित मानता है?","options":["65 mph, क्योंकि लेन बदलना असंभव था","45 mph (तय सीमा से 20 mph कम) को सुरक्षित माना जाता है","तय सीमा चाहे जो भी हो, 25 mph","लेन साफ होने तक पूरी तरह रुकना"],"explanation":"कोलोराडो का मूव ओवर कानून (CRS 42-4-705) यह प्रावधान करता है कि जब चालक लेन नहीं बदल सकता, तो 45 mph या उससे अधिक तय की गई सड़कों पर तय सीमा से 20 mph कम गति (यहाँ 45 mph) को सुरक्षित माना जाता है, और 45 mph से कम वाली सड़कों पर 25 mph या उससे कम को सुरक्षित माना जाता है। स्रोत: CRS 42-4-705।"},"61":{"q":"जब कोलोराडो के स्कूल-बस स्टॉप संकेत सक्रिय होते हैं, तो आने वाले चालक को बस तक पहुँचने से कम से कम कितनी दूरी पहले रुकना चाहिए?","options":["10 feet","15 feet","20 feet","50 feet"],"explanation":"CRS 42-4-1903 के अनुसार जो चालक अपनी लाल दृश्य संकेत बत्तियाँ सक्रिय किए हुए रुकी हुई स्कूल बस से मिलता है या उसे ओवरटेक करता है, उसे बस तक पहुँचने से कम से कम 20 feet पहले रुकना चाहिए और तब तक आगे नहीं बढ़ना चाहिए जब तक बत्तियाँ सक्रिय रहती हैं। स्रोत: Colorado CDL Manual / CRS 42-4-1903।"},"62":{"q":"कोलोराडो के स्कूल-बस कानून के तहत, चालक को ऐसी स्कूल बस के लिए कब रुकना आवश्यक नहीं है जो अपनी लाल बत्तियाँ चमकाते हुए बच्चों को चढ़ा या उतार रही हो?","options":["जब भी चालक 25 mph से कम गति पर चल रहा हो","जब बस अलग-अलग सड़कमार्गों में विभाजित राजमार्ग के किसी भिन्न सड़कमार्ग पर हो","जब चालक की दिशा में एक से अधिक लेन हो","जब भी बस किसी व्यावसायिक क्षेत्र के भीतर हो"],"explanation":"CRS 42-4-1903 कहता है कि अलग-अलग सड़कमार्गों वाले राजमार्ग पर चलने वाले चालक को किसी भिन्न सड़कमार्ग पर मौजूद स्कूल बस से मिलने या उसे पार करने पर रुकने की आवश्यकता नहीं है। अविभाजित सड़क पर, दोनों दिशाओं का यातायात रुकना चाहिए। स्रोत: CRS 42-4-1903।"},"63":{"q":"प्लेकार्ड लगे खतरनाक पदार्थ ढोने वाला एक कोलोराडो चालक एक रेलमार्ग ग्रेड क्रॉसिंग के पास पहुँचता है। निकटतम रेल से कितनी दूरी के भीतर वाहन को रुकना चाहिए?","options":["50 feet के भीतर लेकिन 15 feet से कम नहीं","100 feet के भीतर लेकिन 50 feet से कम नहीं","25 feet के भीतर लेकिन 10 feet से कम नहीं","75 feet के भीतर लेकिन 25 feet से कम नहीं"],"explanation":"CRS 42-4-707 के अनुसार प्लेकार्ड लगे हैज़मैट वाहनों, स्कूली बच्चों को ले जाने वाली स्कूल बसों, और यात्री ढोने वाले वाणिज्यिक वाहनों को निकटतम रेल से 50 feet के भीतर लेकिन 15 feet से कम नहीं रुकना चाहिए, फिर आगे बढ़ने से पहले देखना और सुनना चाहिए। स्रोत: Colorado CDL Manual / CRS 42-4-707।"},"64":{"q":"जब एक प्लेकार्ड लगा कोलोराडो CMV रुकने के बाद रेलमार्ग की पटरियाँ पार करता है, तो CRS 42-4-707 के तहत कौन-सा अतिरिक्त प्रतिबंध लागू होता है?","options":["चालक को कर्षण जाँचने के लिए उल्टा-फिर-आगे चलकर पार करना चाहिए","चालक को पटरियाँ पार करते समय हाथ से गियर नहीं बदलना चाहिए","चालक को पूरे क्रॉसिंग के दौरान फोर-वे फ्लैशर सक्रिय रखने चाहिए","चालक को केवल 5 mph से कम गति पर ही पार करना चाहिए"],"explanation":"CRS 42-4-707 निर्देश देता है कि चालक केवल तभी पार करे जब क्रॉसिंग पार करते समय गियर बदलने की कोई आवश्यकता न हो और पटरियाँ पार करते समय हाथ से गियर नहीं बदलेगा, जिससे रेल पर रुक जाने का जोखिम कम हो। स्रोत: CRS 42-4-707।"},"65":{"q":"किस प्रकार के रेलमार्ग क्रॉसिंग पर कोलोराडो कानून प्लेकार्ड लगे या बस चालक से अनिवार्य रूप से रुकने की माँग नहीं करता?","options":["स्वचालित गेट रहित कोई भी क्रॉसिंग","ऐसा क्रॉसिंग जहाँ कोई पुलिस अधिकारी या मानव झंडाधारी यातायात निर्देशित कर रहा हो","किसी आवासीय क्षेत्र में कोई भी क्रॉसिंग","दो या अधिक पटरियों के सेट वाला क्रॉसिंग"],"explanation":"CRS 42-4-707 अनिवार्य रुकने में छूट देता है जहाँ कोई पुलिस अधिकारी या मानव झंडाधारी यातायात निर्देशित करता है, जहाँ कोई यातायात-नियंत्रण संकेत यातायात निर्देशित करता है, व्यावसायिक क्षेत्र में स्ट्रीट-रेलवे क्रॉसिंग पर, और आधिकारिक 'exempt' चिह्न वाले क्रॉसिंग पर। स्रोत: CRS 42-4-707।"},"66":{"q":"किसी भिन्न तय सीमा के अभाव में, अंतरराज्यीय प्रणाली का हिस्सा होने वाले सतही, चार-लेन वाले कोलोराडो राजमार्ग पर अधिकतम गति सीमा क्या है?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"CRS 42-4-1101 अंतरराज्यीय प्रणाली पर सतही चार-लेन राजमार्गों पर वैधानिक अधिकतम के रूप में 65 mph निर्धारित करता है (CDOT विशिष्ट खंडों पर अधिक या कम सीमाएँ तय कर सकता है)। स्रोत: CRS 42-4-1101।"},"67":{"q":"कोलोराडो कानून उसी राजमार्ग पर बड़े ट्रकों की गति सीमा को यात्री कारों की तुलना में किस प्रकार मानता है?","options":["ट्रकों की कारों से 10 mph कम एक अलग राज्यव्यापी सीमा होती है","ट्रकों को ढलानों पर तय सीमा से 15 mph कम रहना चाहिए","ट्रक उसी तय सीमा का पालन करते हैं; कोलोराडो में ट्रकों के लिए कोई सामान्य भिन्न गति सीमा नहीं है","ट्रकों को तय सीमा चाहे जो भी हो, राज्यव्यापी 55 mph तक सीमित किया गया है"],"explanation":"कोलोराडो का गति क़ानून (CRS 42-4-1101) श्रेणी या वजन के अनुसार ट्रकों के लिए कोई अलग, कम राज्यव्यापी गति सीमा स्थापित नहीं करता; CMV अन्य वाहनों के समान ही तय सीमाओं का पालन करते हैं। स्रोत: CRS 42-4-1101।"},"68":{"q":"CRS 42-4-1101 के तहत, कोलोराडो में 'खुले पहाड़ी राजमार्ग' पर प्राइमा फेसी गति सीमा क्या है?","options":["30 mph","40 mph","50 mph","55 mph"],"explanation":"CRS 42-4-1101 प्राइमा फेसी सीमाओं में खुले पहाड़ी राजमार्गों पर 40 mph (और संकरे, घुमावदार पहाड़ी राजमार्गों या अंधे मोड़ों पर 20 mph) को सूचीबद्ध करता है। स्रोत: CRS 42-4-1101।"},"69":{"q":"कोलोराडो का 2024 ट्रक लेन कानून कुछ निश्चित I-70 पहाड़ी स्थानों पर 16,000 lbs या उससे अधिक वजन वाले ट्रकों को सबसे बाईं लेन से प्रतिबंधित करता है। इनमें से कौन-सा उन निर्दिष्ट क्षेत्रों में से एक है?","options":["I-25 पर Monument Hill","Vail Pass","I-25 पर Raton Pass","Grand Junction इंटरचेंज"],"explanation":"कोलोराडो का बाईं-लेन ट्रक प्रतिबंध 16,000 lbs या उससे भारी ट्रकों को I-70 के उन खंडों पर सबसे बाईं लेन से प्रतिबंधित करता है जिनमें Floyd Hill, Georgetown Hill, Eisenhower Tunnel, Dowd Junction, और Vail Pass शामिल हैं, जहाँ एक दिशा में कम से कम तीन लेन हैं। स्रोत: CDOT / 2024 Colorado law (SB24-100)।"},"70":{"q":"उन I-70 खंडों पर जहाँ कोलोराडो भारी ट्रकों को सबसे बाईं लेन से प्रतिबंधित करता है, कानून किस अपवाद की अनुमति देता है?","options":["यातायात हल्का होने पर ट्रक बाईं लेन का उपयोग कर सकते हैं","ट्रक किसी अन्य वाहन से आगे निकलने के लिए सबसे बाईं लेन का उपयोग कर सकते हैं","ट्रक केवल रात में ही बाईं लेन का उपयोग कर सकते हैं","किसी भी स्थिति में कोई अपवाद नहीं है"],"explanation":"निर्दिष्ट I-70 पहाड़ी हिस्सों पर कोलोराडो का ट्रक बाईं-लेन प्रतिबंध फिर भी ट्रकों को आगे निकलते समय सबसे बाईं लेन का उपयोग करने की अनुमति देता है; यह प्रतिबंध बाईं लेन में लगातार चलने को लक्षित करता है। स्रोत: CDOT / 2024 Colorado law (SB24-100)।"},"71":{"q":"कोलोराडो का वाणिज्यिक वाहन चेन 'मस्ट-कैरी' कानून CMVs को I-70 पहाड़ी गलियारे पर किस वार्षिक अवधि के दौरान चेन साथ रखने की माँग करता है?","options":["October 1 से April 30 तक","September 1 से May 31 तक","November 1 से March 31 तक","पूरे साल, बिना किसी मौसमी अवधि के"],"explanation":"कोलोराडो का मस्ट-कैरी कानून वाणिज्यिक वाहनों (GVWR 16,001 lbs या अधिक) से माँग करता है कि वे I-70 पर Dotsero (MP 133) और Morrison (MP 259) के बीच September 1 से May 31 तक पर्याप्त चेन साथ रखें। स्रोत: CDOT / CRS 42-4-106।"},"72":{"q":"जब कोलोराडो वाणिज्यिक वाहन चेन कानून लागू होता है, तो आगे बढ़ने के लिए चार या अधिक ड्राइव पहियों वाले CMV को कैसे सुसज्जित किया जाना चाहिए?","options":["ड्राइव-पहिया टायरों में से कम से कम चार पर चेन या ATDs","केवल स्टीयर टायरों पर चेन","चालक की पसंद के किन्हीं दो टायरों पर चेन","केवल स्नो-रेटेड टायर हमेशा पर्याप्त होते हैं"],"explanation":"जब चेन कानून सक्रिय होता है, तो CMV के ड्राइव-पहिया टायरों में से कम से कम चार पर चेन या वैकल्पिक कर्षण उपकरण (ATDs) होने चाहिए (या यदि उसमें चार से कम हैं तो सभी ड्राइव टायरों पर)। स्रोत: CDOT Chain Law / CRS 42-4-106।"},"73":{"q":"I-70 पहाड़ी गलियारा जहाँ कोलोराडो का वाणिज्यिक वाहन चेन कानून लागू होता है, किन दो बिंदुओं के बीच चलता है?","options":["Grand Junction (MP 26) और Denver (MP 275)","Dotsero (MP 133) और Morrison (MP 259)","Glenwood Springs (MP 116) और Golden (MP 263)","Vail (MP 176) और Idaho Springs (MP 240)"],"explanation":"कोलोराडो की वाणिज्यिक चेन/मस्ट-कैरी आवश्यकता I-70 पर Dotsero निकास (Milepost 133) और Morrison निकास (Milepost 259) के बीच लागू होती है। स्रोत: CDOT / CRS 42-4-106।"},"74":{"q":"कोलोराडो अंतरराज्यीय राजमार्ग पर, सड़क के चलने वाले भाग पर CMV को रोकने के बाद, समतल, सीधी सड़क पर आने वाले यातायात की ओर तीन चेतावनी उपकरण चालक को कितने feet के भीतर रखने चाहिए?","options":["5, 50, और 100 feet पर","10, 100, और 200 feet पर","25, 150, और 300 feet पर","50, 250, और 500 feet पर"],"explanation":"कोलोराडो संघीय FMCSR मानक का पालन करता है जिसके अनुसार अविभाजित, समतल सड़क पर रुके हुए CMV से आने वाले यातायात की ओर चेतावनी उपकरण 10 feet, 100 feet, और 200 feet पर रखे जाने चाहिए। स्रोत: Colorado CDL Manual / 49 CFR 392.22 (कोलोराडो में अपनाया गया)।"},"75":{"q":"एक कोलोराडो CMV को एक तीखे मोड़ के ठीक आगे सड़क पर रुकने के लिए मजबूर होना पड़ता है जो उसे आने वाले यातायात से छिपा देता है। चेतावनी उपकरणों को कैसे समायोजित किया जाना चाहिए?","options":["तीनों को पिछले बम्पर के 10 feet के भीतर रखें","पर्याप्त चेतावनी देने के लिए उपकरण को मोड़ की ओर 100 से 500 feet पीछे ले जाएँ","पिछले उपकरणों को छोड़ दें और केवल आगे झंडा लगाएँ","तीनों को कैब के बगल में सेंटरलाइन पर रखें"],"explanation":"जब किसी मोड़, पहाड़ी की चोटी, या अन्य दृश्य बाधा के 500 feet के भीतर रुका हो, तो चालक चेतावनी उपकरण को बाधा की दिशा में ले जाता है ताकि यह वाहन से 100 से 500 feet पर हो और पर्याप्त चेतावनी दे। स्रोत: Colorado CDL Manual / 49 CFR 392.22।"},"76":{"q":"कोलोराडो का सबसे अधिक उपयोग किया जाने वाला रनअवे ट्रक रैम्प, पश्चिम-गामी I-70 पर Eisenhower Tunnel के पास, किस प्रकार के उपकरण के रूप में सबसे अच्छी तरह वर्णित है?","options":["एक ग्रेवल अरेस्टर बेड जो रनअवे ट्रक को रोकने के लिए गहरे ढीले अग्रीगेट का उपयोग करता है","लेन के आर-पार खींचा गया एक स्टील केबल नेट","ढलान के नीचे एक पानी से भरा क्रैश कुशन","फुटपाथ में जड़ी एक चुंबकीय ब्रेकिंग पट्टी"],"explanation":"पश्चिम-गामी I-70 पर Lower Straight Creek रैम्प अमेरिका में सबसे अधिक उपयोग किया जाने वाला रनअवे ट्रक रैम्प है; कोलोराडो के अन्य अरेस्टर बेडों की तरह यह रनअवे ट्रक की ऊर्जा को नष्ट करने के लिए ढीले कुचले अग्रीगेट (गोल पत्थर) के गहरे बेड का उपयोग करता है। स्रोत: CDOT / Colorado CDL Manual पर्वत-ड्राइविंग खंड।"},"77":{"q":"CDOT से ओवरसाइज़ परमिट की आवश्यकता होने से पहले कोलोराडो राजमार्गों पर अधिकतम कानूनी वाहन चौड़ाई क्या है?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"कोलोराडो की कानूनी चौड़ाई सीमा 8 feet 6 inches (102 inches) है; इससे अधिक भार के लिए CDOT ओवरसाइज़ परमिट की आवश्यकता होती है, और 11 feet से अधिक चौड़े के लिए आमतौर पर निर्दिष्ट राज्य राजमार्गों पर एक फ्रंट पायलट/एस्कॉर्ट वाहन की आवश्यकता होती है। स्रोत: CDOT Freight & Permitting / CRS 42-4-502।"},"78":{"q":"कोलोराडो पहाड़ी ढलान पर, रनअवे रैम्प की आवश्यकता से बचने के लिए CMV चालक को किस सही ब्रेकिंग तकनीक का उपयोग करना चाहिए?","options":["पूरी उतराई के दौरान सर्विस ब्रेक को लगातार दबाए रखें","उतराई से पहले एक निचला गियर चुनें और हल्के, रुक-रुक कर ब्रेक लगाएँ","ईंधन बचाने के लिए न्यूट्रल में डालकर ढलान से कोस्ट करें","हाई गियर में रहते हुए ट्रेलर हैंड वाल्व को लगातार लगाएँ"],"explanation":"Colorado CDL Manual की पर्वत-ड्राइविंग मार्गदर्शिका चालकों को निर्देश देती है कि वे लंबी ढलान से नीचे जाना शुरू करने से पहले एक सुरक्षित निचला गियर चुनें और ब्रेक का रुक-रुक कर उपयोग करें (स्नब ब्रेकिंग) ताकि ब्रेक ज़्यादा गर्म होकर फेल न हों; न्यूट्रल में कोस्ट करना अवैध और खतरनाक है। स्रोत: Colorado CDL Manual (Mountain Driving)।"},"79":{"q":"कौन-सी कोलोराडो एजेंसी वाणिज्यिक चालक लाइसेंस (CDLs) जारी करती है और आवश्यक ज्ञान परीक्षाएँ संचालित करती है?","options":["Colorado Department of Transportation (CDOT)","Colorado Department of Revenue, Division of Motor Vehicles (DMV)","Colorado State Patrol Ports of Entry Division","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"कोलोराडो में, CDLs Department of Revenue's Division of Motor Vehicles (DMV) द्वारा जारी किए जाते हैं; ज्ञान परीक्षाएँ एक पूर्ण-सेवा DMV/Motor Vehicle कार्यालय में दी जाती हैं। स्रोत: Colorado DMV, dmv.colorado.gov (First-time CDL Driver / CDL General Information)।"},"80":{"q":"कोलोराडो CDL General Knowledge परीक्षा, जिसमें 50 प्रश्न होते हैं, पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["70% (50 में से कम से कम 35 सही)","75% (50 में से कम से कम 38 सही)","90% (50 में से कम से कम 45 सही)","80% (50 में से कम से कम 40 सही)"],"explanation":"कोलोराडो CDL General Knowledge परीक्षा में 50 प्रश्न होते हैं और उत्तीर्ण होने के लिए 80% — कम से कम 40 सही — की आवश्यकता होती है, जो Colorado CDL Manual और DMV परीक्षण मानकों के अनुरूप है। स्रोत: Colorado DMV / Colorado CDL Manual।"},"81":{"q":"कोलोराडो CDL कौशल परीक्षा तीन भागों से बनी होती है। कौन-सा सेट उन तीन भागों को सही ढंग से सूचीबद्ध करता है?","options":["लिखित ज्ञान, प्री-ट्रिप निरीक्षण, और सड़क पर ड्राइविंग","एयर ब्रेक जाँच, समानांतर पार्किंग, और एक रोड साइन परीक्षा","बुनियादी वाहन नियंत्रण, हैज़मैट स्क्रीनिंग, और सड़क पर ड्राइविंग","प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग"],"explanation":"कोलोराडो की CDL कौशल परीक्षा के तीन भाग हैं: प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण (युक्तियाँ), और सड़क पर ड्राइविंग परीक्षा, जो कोलोराडो द्वारा अपनाई गई संघीय CDL कौशल परीक्षा संरचना को प्रतिबिंबित करती है। स्रोत: Colorado CDL Manual; Colorado DMV।"},"82":{"q":"पहली बार आवेदन करने वाला कोलोराडो CDL आवेदक कौशल परीक्षा देने से पहले, कौन-सा संघीय रूप से अनिवार्य प्रशिक्षण पूरा और सत्यापित होना चाहिए?","options":["Colorado State Patrol द्वारा अनुमोदित एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक CDOT ओवरसाइज़/ओवरवेट लोड-सिक्योरमेंट सेमिनार","किसी FMCSA-पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक Department of Revenue कक्षा सुरक्षा अभिविन्यास"],"explanation":"Feb. 7, 2022 से, कोलोराडो में किसी नए आवेदक, क्लास अपग्रेड, या नए H/P/S एंडोर्समेंट आवेदक के कौशल परीक्षा देने से पहले किसी FMCSA-पंजीकृत प्रदाता के माध्यम से पूरा किया गया (Training Provider Registry में दर्ज) Entry-Level Driver Training (ELDT) आवश्यक है। स्रोत: Colorado DMV; 49 CFR Part 380 / FMCSA TPR।"},"83":{"q":"कोलोराडो Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है, और क्या इसका नवीनीकरण किया जा सकता है?","options":["180 दिनों के लिए वैध और एक बार नवीकरणीय","60 दिनों के लिए वैध और दो बार नवीकरणीय","पाँच वर्षों के लिए वैध और प्रतिवर्ष नवीकरणीय","एक वर्ष के लिए वैध और नवीनीकरण के लिए पात्र नहीं"],"explanation":"कोलोराडो CLP एक वर्ष के लिए वैध है और नवीकरणीय नहीं है; यदि CDL प्राप्त करने से पहले यह समाप्त हो जाता है, तो आवेदक को नए CLP के लिए ज्ञान परीक्षा(एँ) फिर से देनी होंगी। स्रोत: Colorado DMV (CDL General Information / First-time CDL Driver)।"},"84":{"q":"किसी कोलोराडो आवेदक को Commercial Learner's Permit जारी होने के बाद, CDL कौशल परीक्षा देने से पहले इसे कितने समय तक रखना आवश्यक है?","options":["कम से कम 30 कैलेंडर दिन","कम से कम 7 कैलेंडर दिन","कम से कम 14 कैलेंडर दिन","कम से कम 60 कैलेंडर दिन"],"explanation":"कोलोराडो संघीय नियम का पालन करता है कि CDL कौशल परीक्षा देने से पहले CLP को कम से कम 14 कैलेंडर दिनों तक रखा जाना चाहिए। स्रोत: 49 CFR 383.25; Colorado DMV।"},"85":{"q":"कोलोराडो CDL आवेदकों को अपने ड्राइविंग के प्रकार की घोषणा करते हुए एक स्व-प्रमाणन पूरा करना होता है। कितनी स्व-प्रमाणन श्रेणियाँ हैं?","options":["दो","तीन","पाँच","चार"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, और Excepted Intrastate। कोलोराडो में यह फॉर्म DR 2904/DR 2907 पर घोषित किया जाता है। स्रोत: Colorado DMV form DR 2904; 49 CFR 383.71।"},"86":{"q":"एक कोलोराडो चालक जो अंतरराज्यीय वाणिज्य में संचालन करता है और जिसे 49 CFR Part 391 चालक-योग्यता नियमों को पूरा करना होता है (और इसलिए जिसे एक चिकित्सा प्रमाणपत्र साथ रखना होता है), उसे किस श्रेणी के तहत स्व-प्रमाणित करना चाहिए?","options":["Excepted Interstate","Non-excepted Intrastate","Excepted Intrastate","Non-excepted Interstate"],"explanation":"अंतरराज्यीय वाणिज्य में संचालन करने वाला एक चालक जो 49 CFR Part 391 योग्यता आवश्यकताओं के अधीन है और उन्हें पूरा करता है — और जिसे एक चिकित्सा परीक्षक का प्रमाणपत्र रखना होता है — Non-excepted Interstate के रूप में स्व-प्रमाणित करता है। स्रोत: Colorado DMV form DR 2904; 49 CFR 383.71।"},"87":{"q":"DOT चिकित्सा आवश्यकता को पूरा करने के लिए, कोलोराडो CDL आवेदक को कौन-सा दस्तावेज़ प्राप्त करके प्रस्तुत करना होगा?","options":["अच्छे स्वास्थ्य की पुष्टि करने वाला एक सामान्य चिकित्सक का नोट","एक Colorado State Patrol फिटनेस क्लीयरेंस कार्ड","FMCSA National Registry पर मौजूद किसी प्रदाता से एक Medical Examiner's Certificate","एक CDOT परमिट चिकित्सा छूट"],"explanation":"अधिकांश कोलोराडो CDL धारकों को FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध किसी परीक्षक से एक Medical Examiner's Certificate (DOT medical card) प्राप्त करना होगा। स्रोत: Colorado DMV (CDL DOT Medical); FMCSA National Registry।"},"88":{"q":"एक सामान्य non-excepted कोलोराडो CDL चालक के लिए, DOT Medical Examiner's Certificate की अधिकतम वैधता अवधि क्या है?","options":["दो वर्ष तक","पाँच वर्ष तक","एक वर्ष तक","तीन वर्ष तक"],"explanation":"एक DOT चिकित्सा परीक्षक का प्रमाणपत्र अधिकतम दो वर्षों के लिए जारी किया जाता है (और यदि परीक्षक किसी ऐसी स्थिति को नोट करता है जिसकी निगरानी आवश्यक है तो यह कम हो सकता है)। चालक को Colorado DMV के पास एक वर्तमान प्रमाणपत्र फ़ाइल पर रखना होगा। स्रोत: 49 CFR 391.43; Colorado DMV (CDL DOT Medical)।"},"89":{"q":"यदि एक स्व-प्रमाणित non-excepted कोलोराडो CDL चालक DMV के पास फ़ाइल पर मौजूद चिकित्सा प्रमाणपत्र को समाप्त होने देता है, तो विशिष्ट परिणाम क्या है?","options":["CDL तुरंत और स्थायी रूप से रद्द कर दिया जाता है","CDL को डाउनग्रेड कर दिया जाता है ताकि एक वर्तमान चिकित्सा प्रमाणपत्र फ़ाइल किए जाने तक वाणिज्यिक विशेषाधिकार हटा दिए जाएँ","पाँच-वर्षीय CDL नवीनीकरण तक कुछ नहीं होता","चालक को स्वचालित रूप से Excepted Interstate के रूप में पुनर्वर्गीकृत किया जाता है"],"explanation":"यदि किसी non-excepted चालक का चिकित्सा प्रमाणपत्र समाप्त हो जाता है और एक वर्तमान प्रमाणपत्र प्रस्तुत नहीं किया जाता, तो कोलोराडो लाइसेंस को डाउनग्रेड कर देता है, जब तक एक वैध प्रमाणपत्र फ़ाइल पर न हो तब तक वाणिज्यिक ड्राइविंग विशेषाधिकार हटा देता है। स्रोत: Colorado DMV (CDL DOT Medical); 49 CFR 383.73।"},"90":{"q":"अंतरराज्यीय वाणिज्यिक ड्राइविंग के लिए या प्लेकार्ड लगे खतरनाक पदार्थों के परिवहन के लिए कोलोराडो CDL जारी किए जाने हेतु न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"कोलोराडो संघीय न्यूनतम का पालन करता है: अंतरराज्यीय वाणिज्य में संचालन करने या प्लेकार्ड लगे खतरनाक पदार्थ ढोने के लिए चालक का 21 वर्ष का होना आवश्यक है। 18-20 वर्ष के चालक अंतःराज्यीय संचालन तक सीमित हैं। स्रोत: Colorado DMV; 49 CFR 383।"},"91":{"q":"18 से 20 वर्ष की आयु का एक कोलोराडो CDL धारक केवल कोलोराडो के भीतर ड्राइविंग तक सीमित है। कौन-सा लाइसेंस प्रतिबंध कोड इस केवल-अंतःराज्यीय सीमा को दर्शाता है?","options":["प्रतिबंध \"K\" (केवल अंतःराज्यीय)","प्रतिबंध \"L\" (कोई एयर ब्रेक नहीं)","प्रतिबंध \"Z\" (कोई पूर्ण एयर ब्रेक नहीं)","प्रतिबंध \"E\" (कोई मैनुअल ट्रांसमिशन नहीं)"],"explanation":"कोलोराडो उन CDL धारकों पर \"K\" प्रतिबंध (केवल अंतःराज्यीय) लागू करता है जो अंतरराज्यीय वाणिज्य में संचालन नहीं कर सकते, जिसमें 18-20 वर्ष की आयु के चालक शामिल हैं। स्रोत: Colorado DMV (CDL Restrictions)।"},"92":{"q":"पहली बार आवेदन करने वाले कोलोराडो CDL आवेदक को DMV पर कौन-सा दस्तावेज़ों का सेट प्रस्तुत करना होगा?","options":["केवल एक वर्तमान कोलोराडो नियमित चालक लाइसेंस","पहचान का प्रमाण, अमेरिका में वैध उपस्थिति का प्रमाण, Social Security number का प्रमाण, और कोलोराडो निवास का प्रमाण","एक पासपोर्ट और एक CDOT लोड परमिट","केवल एक नियोक्ता पत्र और दो पासपोर्ट फोटो"],"explanation":"कोलोराडो CDL आवेदकों को पहचान, अमेरिका में वैध उपस्थिति, Social Security number, और कोलोराडो आवासीय पता (जैसे, उपयोगिता बिल या बैंक विवरण) सिद्ध करना होगा। स्रोत: Colorado DMV (First-time CDL Driver)।"},"93":{"q":"कौशल परीक्षा की अनुमति देने से पहले DMV द्वारा कोलोराडो CDL आवेदक की ELDT पूर्णता की पुष्टि कैसे की जाती है?","options":["आवेदक अनुमोदन के लिए CDOT को एक कागज़ी प्रमाणपत्र डाक से भेजता है","आवेदक प्रशिक्षक से एक नोटरीकृत शपथपत्र लाता है","प्रदाता इसे इलेक्ट्रॉनिक रूप से FMCSA Training Provider Registry को रिपोर्ट करता है, जिसे DMV जाँचता है","Colorado State Patrol एक ELDT क्लीयरेंस पत्र जारी करता है"],"explanation":"FMCSA-पंजीकृत ELDT प्रदाता पूर्णता रिकॉर्ड संघीय Training Provider Registry (TPR) को प्रस्तुत करते हैं; कोलोराडो का DMV कौशल परीक्षा की अनुमति देने से पहले रिकॉर्ड को इलेक्ट्रॉनिक रूप से सत्यापित करता है। स्रोत: Colorado DMV; FMCSA TPR / 49 CFR Part 380।"},"94":{"q":"सही क्रम में, पहली बार आवेदन करने वाले कोलोराडो CDL आवेदक के लिए पहले तीन प्रमुख चरण क्या हैं?","options":["कौशल परीक्षा दें, फिर CLP प्राप्त करें, फिर ELDT पूरा करें","ज्ञान परीक्षा(एँ) उत्तीर्ण करें और CLP प्राप्त करें, फिर ELDT पूरा करें, फिर कौशल परीक्षा दें","ELDT पूरा करें, फिर कौशल परीक्षा दें, फिर ज्ञान परीक्षा उत्तीर्ण करें","मेडिकल कार्ड प्राप्त करें, फिर कौशल परीक्षा दें, फिर ज्ञान परीक्षा दें"],"explanation":"कोलोराडो का क्रम है: आवश्यक ज्ञान परीक्षा(एँ) उत्तीर्ण करें और CLP प्राप्त करें, FMCSA-अनुमोदित ELDT (सिद्धांत और पहिए-के-पीछे) पूरा करें, फिर तीन-भाग वाली कौशल परीक्षा दें (14-दिन की CLP होल्ड अवधि के बाद)। स्रोत: Colorado DMV (First-time CDL Driver)।"},"95":{"q":"कोलोराडो CDL कौशल परीक्षा के सड़क-पर भाग के दौरान, परीक्षक मुख्य रूप से किसका मूल्यांकन कर रहा होता है?","options":["एक निर्धारित मार्ग पर वास्तविक यातायात में वाहन को सुरक्षित रूप से संचालित करने की आवेदक की क्षमता","क्या आवेदक CDL मैनुअल की सामग्री सुना सकता है","केवल आवेदक की समानांतर-पार्किंग गति","ओवरसाइज़/ओवरवेट परमिट सीमाओं के साथ वाहन का अनुपालन"],"explanation":"सड़क-पर परीक्षा एक पूर्व-निर्धारित मार्ग पर वास्तविक यातायात में सुरक्षित संचालन का मूल्यांकन करती है — मोड़, चौराहे, लेन परिवर्तन, और सामान्य ड्राइविंग। बैकिंग/युक्तियाँ अलग बुनियादी-नियंत्रण भाग में स्कोर की जाती हैं। स्रोत: Colorado CDL Manual; Colorado DMV।"},"96":{"q":"एक कोलोराडो चालक पूरी तरह कोलोराडो के भीतर केवल कृषि आपूर्ति ढोता है और राज्य चालक-योग्यता नियमों के कुछ भागों से छूट प्राप्त है। कौन-सी स्व-प्रमाणन श्रेणी इस चालक के लिए उपयुक्त है?","options":["Excepted Intrastate","Non-excepted Interstate","Excepted Interstate","Non-excepted Intrastate"],"explanation":"केवल कोलोराडो के भीतर संचालन करने वाला एक चालक जो राज्य चालक-योग्यता आवश्यकताओं के सभी या किसी भाग से छूट प्राप्त है, Excepted Intrastate के रूप में स्व-प्रमाणित करता है और आमतौर पर उसे DOT चिकित्सा प्रमाणपत्र फ़ाइल करने की आवश्यकता नहीं होती। स्रोत: Colorado DMV form DR 2904; 49 CFR 383.71।"},"97":{"q":"कोलोराडो में CDL शुल्क के संबंध में, अध्ययन गाइड के लिए कौन-सा कथन सबसे सटीक है?","options":["कोलोराडो में CDL ज्ञान और कौशल परीक्षण हमेशा निःशुल्क होता है","शुल्क संघीय कानून द्वारा स्थायी रूप से तय किए गए हैं और कभी नहीं बदलते","विशिष्ट शुल्क राशियाँ राज्य द्वारा निर्धारित की जाती हैं और बदल सकती हैं, इसलिए आवेदकों को DMV से वर्तमान शुल्क की पुष्टि करनी चाहिए","केवल चिकित्सा परीक्षा का शुल्क है; DMV लाइसेंस के लिए कुछ भी शुल्क नहीं लेता"],"explanation":"कोलोराडो CDL परीक्षण और जारी करने के लिए शुल्क लेता है, लेकिन सटीक राशियाँ राज्य द्वारा निर्धारित की जाती हैं और बदलने के अधीन हैं; आवेदकों को किसी निश्चित आंकड़े पर निर्भर रहने के बजाय DMV से वर्तमान शुल्क सत्यापित करना चाहिए। स्रोत: Colorado DMV (CDL General Information / fee schedule)।"}},"ar":{"0":{"q":"على الطرق السريعة في كولورادو، ما هو الحد الأقصى القانوني لعرض المركبة التجارية القياسية (باستثناء المرايا وملحقات السلامة المطلوبة) قبل أن تكون هناك حاجة إلى تصريح للحمولة الزائدة الحجم؟","options":["8 أقدام و0 بوصة (96 بوصة)","8 أقدام و6 بوصات (102 بوصة)","9 أقدام و0 بوصة (108 بوصات)","10 أقدام و0 بوصة (120 بوصة)"],"explanation":"تحدّ كولورادو عرض المركبة بـ 8 أقدام و6 بوصات (102 بوصة). لا تُحتسب أضواء التخليص ومرايا الرؤية الخلفية والملحقات الأخرى المطلوبة ضمن هذا الحد. المصدر: C.R.S. 42-4-502 (عرض المركبات)."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، محمّلة أو غير محمّلة، على الطرق السريعة في كولورادو؟","options":["13 قدمًا و6 بوصات","14 قدمًا و0 بوصة","14 قدمًا و6 بوصات","15 قدمًا و0 بوصة"],"explanation":"لا يجوز للسائق تشغيل مركبة، غير محمّلة أو محمّلة بحمولة، يتجاوز ارتفاعها 14 قدمًا و6 بوصات. المصدر: C.R.S. 42-4-504 (ارتفاع المركبات وطولها)."},"2":{"q":"بموجب قانون كولورادو، ما هو الحد الأقصى للطول الإجمالي لمركبة آلية واحدة (شاملًا المصدّين الأمامي والخلفي)؟","options":["40 قدمًا","45 قدمًا","53 قدمًا","60 قدمًا"],"explanation":"لا يجوز أن يتجاوز طول أي مركبة آلية واحدة 45 قدمًا في أقصى طول إجمالي لها، بما في ذلك المصدّان الأمامي والخلفي. المصدر: C.R.S. 42-4-504 (ارتفاع المركبات وطولها)."},"3":{"q":"ما هو الحد الأقصى للطول الإجمالي الكلي لمجموعة مركبات مقترنة معًا على الطرق السريعة في كولورادو (بدون تصريح خاص)؟","options":["60 قدمًا","65 قدمًا","70 قدمًا","75 قدمًا"],"explanation":"لا يجوز أن تتجاوز أي مجموعة مركبات طولًا إجماليًا كليًا قدره 70 قدمًا، ولا يجوز أن تتألف المجموعة من أكثر من أربع وحدات. المصدر: C.R.S. 42-4-504 (ارتفاع المركبات وطولها)."},"4":{"q":"في كولورادو، الحد الأقصى للوزن المسموح به على محور واحد مزوّد بإطارات هوائية هو:","options":["16,000 رطل","18,000 رطل","20,000 رطل","22,000 رطل"],"explanation":"عندما تكون العجلات على محور واحد مزوّدة بإطارات هوائية، يكون الحد الأقصى للحمولة 20,000 رطل. المصدر: C.R.S. 42-4-507 (حمولات العجلات والمحاور)."},"5":{"q":"ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور ترادفية تعمل على طريق سريع بين الولايات (INTERSTATE) في كولورادو؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"على نظام الطرق السريعة بين الولايات، تتبع كولورادو الحد الفيدرالي للمحور الترادفي وقدره 36,000 رطل. (أما على الطرق السريعة للولاية غير بين الولايات فيكون حد المحور الترادفي 40,000 رطل.) المصدر: C.R.S. 42-4-507 (حمولات العجلات والمحاور)."},"6":{"q":"على طريق سريع للولاية غير بين الولايات في كولورادو، ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور ترادفية؟","options":["34,000 رطل","36,000 رطل","40,000 رطل","44,000 رطل"],"explanation":"على الطرق السريعة للولاية غير بين الولايات، تسمح كولورادو بما يصل إلى 40,000 رطل على المحور الترادفي، وهو أعلى من حد 36,000 رطل المطبّق بين الولايات. المصدر: C.R.S. 42-4-507 (حمولات العجلات والمحاور)."},"7":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به على نظام الطرق بين الولايات (INTERSTATE) في كولورادو بدون تصريح للوزن الزائد؟","options":["76,000 رطل","80,000 رطل","85,000 رطل","90,000 رطل"],"explanation":"على الطرق السريعة بين الولايات، تطبّق كولورادو الحد الأقصى الفيدرالي للوزن الإجمالي وقدره 80,000 رطل، الذي تحكمه صيغة الجسر الفيدرالية. المصدر: C.R.S. 42-4-508 (الوزن الإجمالي للمركبات والحمولات)."},"8":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به على الطرق السريعة غير بين الولايات (طرق الولاية والطرق المحلية) في كولورادو بموجب جدول أوزان الولاية، في غياب تصريح؟","options":["80,000 رطل","82,000 رطل","85,000 رطل","90,000 رطل"],"explanation":"على الطرق السريعة غير بين الولايات، يسمح جدول الوزن الإجمالي الخاص بكولورادو بما يصل إلى 85,000 رطل، وهو ما يتجاوز سقف 80,000 رطل المطبّق بين الولايات. المصدر: C.R.S. 42-4-508 (الوزن الإجمالي للمركبات والحمولات)."},"9":{"q":"كيف تعرّف كولورادو 'المحور الترادفي' لأغراض الوزن؟","options":["محوران أو أكثر متتاليان متباعدان بأكثر من 40 بوصة وبما لا يزيد عن 96 بوصة","محوران متباعدان بمسافة 48 بوصة بالضبط","أي محورين متباعدين بأقل من 40 بوصة","ثلاثة محاور أو أكثر متباعدة بأكثر من 96 بوصة"],"explanation":"المحور الترادفي هو محوران أو أكثر متتاليان تقع مراكزها بين مستويين رأسيين متوازيين متباعدين بأكثر من 40 بوصة وبما لا يزيد عن 96 بوصة، ويمتدان عبر العرض الكامل للمركبة. المصدر: C.R.S. 42-4-507 (حمولات العجلات والمحاور)."},"10":{"q":"أي صيغة تستخدمها كولورادو لتحديد الحد الأقصى المسموح به للوزن الإجمالي بناءً على تباعد المحاور على نظام الطرق بين الولايات؟","options":["صيغة ضريبة الأميال الخاصة بالولاية","صيغة الجسر الفيدرالية (صيغة وزن الجسر الإجمالي)","صيغة عرض الإطار لكل بوصة فقط","قاعدة ثابتة موحدة قدرها 80,000 رطل بدون تباعد المحاور"],"explanation":"على الطرق السريعة بين الولايات، تحدّ كولورادو الوزن الإجمالي لكل مجموعة محاور باستخدام صيغة الجسر الفيدرالية، التي تربط الوزن المسموح به بعدد المحاور والمسافة بين المحورين الأقصيين، بحد أقصى قدره 80,000 رطل. المصدر: C.R.S. 42-4-508؛ federal 23 CFR 658 (bridge formula)."},"11":{"q":"في صيغة الوزن الإجمالي العامة (غير بين الولايات) في كولورادو W = 1,000(L + 40)، ماذا تمثّل 'L'؟","options":["عدد المحاور على المركبة","إجمالي وزن الحمولة بالأطنان","المسافة بالأقدام بين مركزي المحورين الأول والأخير","الطول القانوني للمقطورة"],"explanation":"في صيغة الوزن الإجمالي غير بين الولايات في كولورادو W = 1,000(L + 40)، تمثّل 'L' المسافة بالأقدام بين مركزي المحورين الأول والأخير في المجموعة، وتمثّل W الحد الأقصى للوزن الإجمالي بالأرطال، على ألا يتجاوز 85,000 رطل. المصدر: C.R.S. 42-4-508 (الوزن الإجمالي للمركبات والحمولات)."},"12":{"q":"السائق الذي ينقل حمولة بعرض 11 قدمًا على طريق سريع للولاية في كولورادو يجب عليه القيام بأي مما يلي؟","options":["لا شيء؛ 11 قدمًا ضمن حد العرض القانوني","الحصول على تصريح للحمولة الزائدة الحجم من CDOT لأن الحمولة تتجاوز 8 أقدام و6 بوصات","عرض علم فقط، دون الحاجة إلى تصريح","تخفيض الوزن الإجمالي إلى 80,000 رطل"],"explanation":"أي حمولة أعرض من الحد القانوني البالغ 8 أقدام و6 بوصات تتطلب تصريحًا للحمولة الزائدة الحجم من CDOT قبل السفر. الحمولة بعرض 11 قدمًا تُعد زائدة الحجم. المصدر: C.R.S. 42-4-502 و42-4-510؛ مكتب تصاريح CDOT."},"13":{"q":"في كولورادو، تصاريح الحمولة الزائدة الحجم والوزن الزائد للسفر على نظام الطرق السريعة للولاية تصدر من قبل:","options":["قسم المركبات الآلية في إدارة الإيرادات بولاية كولورادو","مكتب تصاريح إدارة النقل بولاية كولورادو (CDOT)","مأمور المقاطعة التي تبدأ منها الرحلة","الإدارة الفيدرالية لسلامة ناقلات النقل الآلي"],"explanation":"تصاريح الحمولة الزائدة الحجم/الوزن الزائد لنظام الطرق السريعة للولاية تصدر من قبل مكتب تصاريح CDOT، عمومًا من خلال نظام COOPR الإلكتروني (Colorado Oversize Overweight Permitting and Routing). المصدر: C.R.S. 42-4-510؛ CDOT freight.colorado.gov."},"14":{"q":"ما اسم النظام الإلكتروني الذي تستخدمه كولورادو لتمكين الناقلين من طلب تصاريح الحمولة الزائدة الحجم/الوزن الزائد والحصول على مسارات معتمدة؟","options":["COOPR (Colorado Oversize Overweight Permitting and Routing)","IRP (International Registration Plan)","PRISM (Performance Registration Information Systems Management)","UCR (Unified Carrier Registration)"],"explanation":"تصدر كولورادو تصاريح الحمولة الزائدة الحجم/الوزن الزائد من خلال نظام COOPR، حيث يتقدم الناقلون بالطلب عبر الإنترنت، ويدفعون الرسوم، ويتلقون التوجيه؛ ويمكن إصدار العديد من التصاريح ذاتيًا. المصدر: CDOT، coopr.codot.gov؛ C.R.S. 42-4-510."},"15":{"q":"بموجب تصريح الحمولة الزائدة الحجم في كولورادو، يمكن نقل القش السائب (بما في ذلك البالات المستديرة) حتى أي عرض؟","options":["8 أقدام و6 بوصات","10 أقدام و6 بوصات","12 قدمًا","14 قدمًا"],"explanation":"يسمح قانون العرض في كولورادو بنقل القش السائب، بما في ذلك البالات المستديرة، حتى عرض 12 قدمًا؛ أما القش المستطيل (المبلّط) فيقتصر على 10 أقدام و6 بوصات. المصدر: C.R.S. 42-4-502 (عرض المركبات)."},"16":{"q":"على الطرق السريعة في كولورادو، ما هو الحد الأقصى للوزن على أي عجلة واحدة من مركبة ذات إطارات فولاذية، لكل بوصة من عرض المقطع العرضي للإطار؟","options":["300 رطل لكل بوصة","500 رطل لكل بوصة","650 رطلًا لكل بوصة","800 رطل لكل بوصة"],"explanation":"لا يجوز أن يتجاوز الوزن الإجمالي على أي عجلة واحدة من مركبة ذات إطارات فولاذية 500 رطل لكل بوصة من عرض المقطع العرضي للإطار. المصدر: C.R.S. 42-4-507 (حمولات العجلات والمحاور)."},"17":{"q":"تسمح كولورادو لبعض مركبات الوقود البديل بتجاوز الحدود القياسية القصوى للوزن الإجمالي ووزن المحور بأي قدر، لمراعاة نظام الوقود/الطاقة الأثقل؟","options":["حتى 400 رطل","حتى 1,000 رطل","حتى 2,000 رطل","حتى 5,000 رطل"],"explanation":"تسمح كولورادو للمركبات التي تعمل بالوقود البديل بتجاوز حدود الوزن الإجمالي ووزن المحور بما يصل إلى 2,000 رطل، بما يتوافق مع البدل الفيدرالي لوزن مركبات الغاز الطبيعي/الكهربائية. المصدر: C.R.S. 42-4-508 (الوزن الإجمالي للمركبات والحمولات)."},"18":{"q":"عند تحميل مجموعة مركبات في كولورادو، يجب على كل مركبة في المجموعة عمومًا أن تحمل على الأقل أي نسبة من إجمالي الوزن الإجمالي (مع استثناءات محدودة لبعض مقطورات المرافق/الأعمدة)؟","options":["ما لا يقل عن 5 بالمئة من إجمالي الوزن الإجمالي","ما لا يقل عن 10 بالمئة من إجمالي الوزن الإجمالي","ما لا يقل عن 25 بالمئة من إجمالي الوزن الإجمالي","ما لا يقل عن 50 بالمئة من إجمالي الوزن الإجمالي"],"explanation":"في مجموعة المركبات، يجب أن تتحمل كل مركبة ما لا يقل عن 10 بالمئة من إجمالي الوزن الإجمالي، باستثناء المقطورات المتخصصة المستخدمة لنقل حمولات المرافق الثابتة أو الأعمدة. المصدر: C.R.S. 42-4-508 (الوزن الإجمالي للمركبات والحمولات)."},"19":{"q":"ضابط السلام في كولورادو الذي يعتقد أن مركبة ما زائدة الوزن قد يطلب من السائق وزن المركبة، وإذا كانت المركبة تتجاوز الحد القانوني، فقد يطلب من السائق القيام بماذا؟","options":["تسليم رخصة قيادة المركبات التجارية فورًا","تفريغ ما يكفي من البضائع لخفض الوزن الإجمالي إلى الحد القانوني","دفع غرامة الوزن الزائد نقدًا في الموقع قبل المتابعة","الاستمرار إلى الوجهة والإبلاغ إلى نقطة دخول خلال 24 ساعة"],"explanation":"يجوز للضابط الذي لديه سبب للاعتقاد بأن مركبة ما زائدة الوزن أن يطلب وزنها على موازين محمولة أو ثابتة (أو موازين عامة قريبة ضمن خمسة أميال)، وإذا كانت زائدة الوزن بشكل غير قانوني، أن يطلب من السائق إزالة ما يكفي من الحمولة لخفض الوزن الإجمالي إلى الحد القانوني. المصدر: C.R.S. 42-4-509 (وزن المركبات - إزالة الفائض)."},"20":{"q":"في كولورادو، أي فئة من رخصة القيادة التجارية (CDL) مطلوبة لتشغيل أي مجموعة مركبات بتصنيف وزن إجمالي مجمّع (GCWR) قدره 26,001 رطل أو أكثر، حيث يتجاوز تصنيف الوزن الإجمالي (GVWR) للمركبة المقطورة 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف كولورادو رخصة CDL من الفئة A بأنها أي مجموعة مركبات بتصنيف GCWR قدره 26,001 رطل أو أكثر، شريطة أن يتجاوز تصنيف GVWR للوحدة المقطورة 10,000 رطل. المصدر: دليل CDL في كولورادو (Colorado DMV/إدارة الإيرادات)، تعريفات فئات CDL؛ C.R.S. 42-2-402."},"21":{"q":"أي فئة من رخصة CDL في كولورادو تغطي مركبة واحدة بتصنيف GVWR قدره 26,001 رطل أو أكثر يجوز لها قطر مركبة أخرى لا يتجاوز تصنيف GVWR لها 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تُطلب رخصة CDL من الفئة B في كولورادو لأي مركبة واحدة بتصنيف GVWR قدره 26,001 رطل أو أكثر، يجوز لها قطر وحدة لا تتجاوز 10,000 رطل من تصنيف GVWR. المصدر: دليل CDL في كولورادو (Colorado DMV)، تعريفات الفئات."},"22":{"q":"يشغّل سائق مركبة واحدة بتصنيف GVWR أقل من 26,001 رطل مصممة لنقل 18 راكبًا بما في ذلك السائق. أي فئة من رخصة CDL في كولورادو مطلوبة؟","options":["لا تُطلب رخصة CDL","الفئة A","الفئة B","الفئة C"],"explanation":"تغطي رخصة CDL من الفئة C المركبات التي لا تستوفي تعريفات الوزن للفئة A أو B لكنها مصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو نقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: دليل CDL في كولورادو (Colorado DMV)، تعريفات الفئات."},"23":{"q":"أي مصادقة يجب على حامل رخصة CDL في كولورادو الحصول عليها لنقل المواد الخطرة بكميات تتطلب لوحات تحذيرية؟","options":["مصادقة N","مصادقة T","مصادقة H","مصادقة P"],"explanation":"تُطلب مصادقة H (المواد الخطرة) لنقل المواد الخطرة ذات اللوحات التحذيرية. في كولورادو، تتطلب اجتياز اختبار المعرفة الخاص بـ HazMat، وإكمال الجزء النظري من ELDT، واجتياز تقييم تهديد أمني من قبل TSA. المصدر: Colorado DMV، مصادقات ومتطلبات CDL؛ 49 CFR 383."},"24":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في كولورادو للقيادة داخل الولاية (within-state) فقط؟","options":["16 عامًا","18 عامًا","19 عامًا","21 عامًا"],"explanation":"تسمح كولورادو برخصة CDL في سن 18 عامًا للتشغيل داخل الولاية فقط. يحصل السائقون الذين تتراوح أعمارهم بين 18 و20 عامًا على قيد 'K' يقتصر بهم القيادة داخل كولورادو. المصدر: Colorado DMV؛ C.R.S. 42-2-403."},"25":{"q":"ما هو الحد الأدنى للعمر المطلوب للحصول على رخصة CDL في كولورادو صالحة للقيادة بين الولايات (عبر حدود الولايات)؟","options":["18 عامًا","19 عامًا","21 عامًا","25 عامًا"],"explanation":"تتطلب القيادة التجارية بين الولايات حدًا أدنى للعمر قدره 21 عامًا. يحمل السائقون من سن 18 إلى 20 رخصة CDL بقيد 'K' (داخل الولاية فقط). المصدر: Colorado DMV؛ FMCSA 49 CFR 391.11."},"26":{"q":"بموجب القواعد الفيدرالية المعتمدة في كولورادو، كم يجب أن يُحتفظ بتصريح المتعلم التجاري (CLP) قبل أن يكون الحامل مؤهلًا لأداء اختبار مهارات CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل","180 يومًا على الأقل"],"explanation":"لا يجوز لحامل CLP أداء اختبار مهارات CDL حتى مرور 14 يومًا على الأقل منذ الإصدار الأولي لـ CLP. المصدر: FMCSA 49 CFR 383.25، كما تطبّقه Colorado DMV."},"27":{"q":"أي مصادقة مطلوبة لسائق في كولورادو ينقل مركبة صهريج تحمل سوائل بكميات سائبة بسعة مصنّفة إجمالية قدرها 1,000 غالون أو أكثر؟","options":["مصادقة H","مصادقة N","مصادقة T","مصادقة S"],"explanation":"تُطلب مصادقة N (مركبة الصهريج) لتشغيل مركبة صهريج بخزانات بسعة مصنّفة فردية تتجاوز 119 غالونًا وسعة مصنّفة إجمالية قدرها 1,000 غالون أو أكثر. وتتطلب اجتياز اختبار المعرفة الخاص بالصهاريج. المصدر: Colorado DMV، مصادقات CDL؛ 49 CFR 383.5."},"28":{"q":"يريد سائق في كولورادو الحصول على مصادقة T لجر مقطورات مزدوجة أو ثلاثية. ماذا يجب على السائق فعله لإضافتها؟","options":["اجتياز اختبار معرفة (تحريري) فقط","اجتياز اختبار معرفة واختبار مهارات","اجتياز فحص خلفية من TSA","إكمال تدريب ELDT خلف عجلة القيادة"],"explanation":"تتطلب مصادقة T (المقطورات المزدوجة/الثلاثية) اجتياز اختبار المعرفة الخاص بالمقطورات المزدوجة/الثلاثية فقط في كولورادو؛ ولا يُطلب اختبار مهارات منفصل. ويمكن إضافتها إلى رخصة CDL من الفئة A. المصدر: Colorado DMV، مصادقات ومتطلبات CDL."},"29":{"q":"أي مصادقة يحتاجها سائق في كولورادو لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) في مركبة تجارية؟","options":["مصادقة S","مصادقة N","مصادقة P","مصادقة H"],"explanation":"تُطلب مصادقة P (الركاب) لنقل 16 راكبًا أو أكثر بما في ذلك السائق. في كولورادو، تتطلب اختبار المعرفة الخاص بالركاب، وELDT، واختبار مهارات في مركبة ركاب. المصدر: Colorado DMV، مصادقات ومتطلبات CDL."},"30":{"q":"في كولورادو، أي مصادقة تُعد شرطًا مسبقًا يجب الحصول عليه مع مصادقة الحافلة المدرسية (S) (أو قبلها)؟","options":["مصادقة N (الصهريج)","مصادقة P (الركاب)","مصادقة H (المواد الخطرة)","مصادقة T (المقطورات المزدوجة/الثلاثية)"],"explanation":"مصادقة P (الركاب) هي شرط مسبق لمصادقة S (الحافلة المدرسية)؛ لا يمكن لمتقدم أن يحمل S دون P. المصدر: Colorado DMV، مصادقات ومتطلبات CDL؛ 49 CFR 383.93."},"31":{"q":"أي جهة تحتفظ بالسجل الذي يجب أن يكون مزوّد تدريب السائقين المبتدئين (ELDT) الخاص بمتقدم رخصة CDL في كولورادو مدرجًا فيه؟","options":["إدارة التعليم بولاية كولورادو","سجل مزوّدي التدريب التابع لـ FMCSA","دورية ولاية كولورادو","إدارة أمن النقل"],"explanation":"يجب إكمال ELDT من خلال مزوّد مدرج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA؛ وتتحقق Colorado DMV من الإكمال عبر TPR قبل السماح باختبار المهارات/المعرفة. المصدر: FMCSA TPR؛ Colorado DMV."},"32":{"q":"لأي مما يلي يتألف ELDT (تدريب السائقين المبتدئين) من تدريب نظري فقط يُكمل قبل اختبار المعرفة، بدلًا من أن يتضمن تدريبًا خلف عجلة القيادة؟","options":["رخصة CDL من الفئة A لأول مرة","رخصة CDL من الفئة B لأول مرة","مصادقة H (المواد الخطرة)","مصادقة P (الركاب)"],"explanation":"بالنسبة لمصادقة H (المواد الخطرة)، يكون ELDT نظريًا فقط ويجب إكماله قبل أداء اختبار المعرفة الخاص بـ HazMat. أما الفئات A وB وP وS فتتطلب كلًا من التدريب النظري وتدريب ELDT خلف عجلة القيادة. المصدر: FMCSA 49 CFR 380 Subpart F؛ FMCSA TPR."},"33":{"q":"قبل إصدار أو تجديد مصادقة المواد الخطرة (H) في كولورادو، ما هي الموافقة الإضافية التي يجب على المتقدم الحصول عليها؟","options":["إعفاء طبي من DOT","تقييم تهديد أمني من TSA (فحص خلفية)","تسجيل AIM من إدارة التعليم بولاية كولورادو","شهادة فحص من المستوى الثاني SAE"],"explanation":"يجب على المتقدمين لمصادقة H اجتياز تقييم تهديد أمني من TSA، الذي يشمل فحوصات خلفية قائمة على البصمات، قبل إصدار المصادقة أو تجديدها. المصدر: TSA/FMCSA 49 CFR 1572؛ Colorado DMV، الأسئلة الشائعة حول CDL."},"34":{"q":"عند التقدم بطلب للحصول على رخصة CDL أو CLP في كولورادو، كم عدد إثباتات العنوان (الإقامة) في كولورادو التي يجب على المتقدم تقديمها؟","options":["إثبات عنوان واحد","إثباتان للعنوان","ثلاثة إثباتات للعنوان","لا يُطلب إثبات عنوان"],"explanation":"تتطلب Colorado DMV وثيقتين تثبتان العنوان في كولورادو، مؤرختين خلال العام الأخير، بالإضافة إلى إثبات الهوية. المصدر: Colorado DMV، وثائق الهوية المطلوبة."},"35":{"q":"بالإضافة إلى إثبات الهوية والإقامة في كولورادو، ما الذي يجب على متقدم رخصة CDL في كولورادو تقديمه أيضًا عند التقديم؟","options":["جواز سفر فقط","إثبات رقم الضمان الاجتماعي الخاص به","خطاب موثّق من صاحب العمل","مرجعين شخصيين"],"explanation":"تتطلب كولورادو من المتقدمين تقديم بطاقة الضمان الاجتماعي الخاصة بهم أو إثبات مقبول آخر لرقم الضمان الاجتماعي، إلى جانب وثائق الهوية والوجود القانوني/الإقامة. المصدر: Colorado DMV، وثائق الهوية المطلوبة."},"36":{"q":"أي مما يلي يُعد واحدة من فئات التصديق الذاتي الطبي الفيدرالية الأربع التي يجب على حامل رخصة CDL في كولورادو الاختيار من بينها؟","options":["غير مستثنى بين الولايات (Non-Excepted Interstate)","ذو لوحات تحذيرية بين الولايات","مقيّد داخل الولاية","مشروط بين الولايات"],"explanation":"فئات التصديق الذاتي الأربع هي: غير مستثنى بين الولايات (NI)، ومستثنى بين الولايات (EI)، وغير مستثنى داخل الولاية (NA)، ومستثنى داخل الولاية (EA). السائق الخاضع لقواعد التأهيل البدني الفيدرالية يختار غير مستثنى بين الولايات. المصدر: FMCSA 49 CFR 383.71؛ Colorado DMV."},"37":{"q":"حامل رخصة CDL في كولورادو يقود داخل كولورادو فقط لكنه لا يزال ملزمًا باستيفاء معايير التأهيل الطبي ينبغي أن يصدّق ذاتيًا تحت أي فئة؟","options":["غير مستثنى بين الولايات","مستثنى بين الولايات","غير مستثنى داخل الولاية","مستثنى داخل الولاية"],"explanation":"السائق الذي يعمل داخل كولورادو فقط ولا يزال ملزمًا باستيفاء المعايير الطبية يصدّق ذاتيًا بصفته غير مستثنى داخل الولاية (NA). المصدر: FMCSA 49 CFR 383.71؛ Colorado DMV، فئات التصديق الذاتي."},"38":{"q":"إلى جانب فحص الخلفية من TSA، ماذا يجب على سائق في كولورادو فعله لإضافة مصادقة المواد الخطرة (H) إلى رخصة CDL؟","options":["اجتياز اختبار معرفة (تحريري) خاص بـ HazMat","اجتياز اختبار مهارات/طريق خاص بـ HazMat فقط","تقديم تقرير فحص للمقطورات المزدوجة/الثلاثية","حمل المصادقة لمدة سنة على CLP أولًا"],"explanation":"إضافة مصادقة H تتطلب اجتياز اختبار المعرفة الخاص بـ HazMat (بالإضافة إلى الجزء النظري من ELDT وتقييم تهديد أمني من TSA)؛ ولا يوجد اختبار مهارات منفصل لـ HazMat. المصدر: Colorado DMV، مصادقات ومتطلبات CDL؛ 49 CFR 383."},"39":{"q":"ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) المسموح به أثناء تشغيل مركبة آلية تجارية في كولورادو؟","options":["0.02","0.04","0.08","0.10"],"explanation":"في كولورادو، لا يجوز للسائق تشغيل مركبة آلية تجارية (CMV) بتركيز كحول في الدم (BAC) قدره 0.04 أو أكثر - أي نصف حد 0.08 المطبّق على السائقين غير التجاريين. المصدر: دليل CDL في كولورادو، القسم 1 (حالات سحب الأهلية)؛ 49 CFR 383.51."},"40":{"q":"بموجب قانون الموافقة الضمنية في كولورادو، ماذا يحدث إذا رفض حامل رخصة CDL الخضوع لاختبار كيميائي للكحول أو المخدرات؟","options":["يصدر تحذير دون سحب الأهلية","تُسحب أهلية CDL للفترة نفسها المطبّقة على أول مخالفة كبرى","تُفرض غرامة فقط","تُعلّق الرخصة لمدة 30 يومًا"],"explanation":"يُعامل رفض الاختبار المطلوب كمخالفة كبرى في كولورادو، ويستتبع سحب الأهلية لمدة سنة واحدة (3 سنوات في حال نقل مواد خطرة ذات لوحات تحذيرية) - وهو نفس عقوبة أول مخالفة قيادة تحت تأثير الكحول/BAC. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51؛ C.R.S. 42-2-126."},"41":{"q":"بالنسبة لأول مخالفة كبرى، مثل قيادة مركبة آلية تجارية بتركيز كحول في الدم (BAC) قدره 0.04 أو أكثر، كم تدوم مدة سحب أهلية حامل رخصة CDL في كولورادو (عند عدم نقل مواد خطرة ذات لوحات تحذيرية)؟","options":["60 يومًا","6 أشهر","سنة واحدة","3 سنوات"],"explanation":"تؤدي أول مخالفة كبرى إلى سحب أهلية CDL لمدة سنة واحدة في كولورادو. المصدر: دليل CDL في كولورادو، القسم 1 (حالات سحب الأهلية)؛ 49 CFR 383.51."},"42":{"q":"كم تدوم مدة سحب الأهلية لأول مخالفة كبرى إذا كان السائق ينقل مواد خطرة ذات لوحات تحذيرية في ذلك الوقت؟","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"ترفع أول مخالفة كبرى أثناء نقل مواد خطرة ذات لوحات تحذيرية مدة سحب الأهلية إلى 3 سنوات في كولورادو. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"43":{"q":"ما هي مدة سحب الأهلية لثاني مخالفة كبرى (على سبيل المثال، ثاني مخالفة قيادة تحت تأثير الكحول) يرتكبها حامل رخصة CDL في كولورادو؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي ثاني مخالفة كبرى إلى سحب أهلية CDL مدى الحياة في كولورادو، رغم أن إعادة الترخيص قد تكون ممكنة بعد 10 سنوات وفق شروط معينة. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"44":{"q":"أي مما يلي يُصنّف على أنه 'مخالفة كبرى' لحامل رخصة CDL في كولورادو؟","options":["السير خلف المركبة التي في الأمام بمسافة قريبة جدًا","مغادرة موقع حادث يتعلق بمركبة آلية تجارية","تجاوز السرعة بمقدار 15 ميلًا في الساعة فوق الحد","تغيير غير صحيح للمسار"],"explanation":"مغادرة موقع الحادث مخالفة كبرى (سحب الأهلية سنة واحدة لأول مرة / مدى الحياة للمرة الثانية). أما الخيارات الأخرى فهي مخالفات مرورية خطيرة، وليست مخالفات كبرى. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"45":{"q":"يُعامل استخدام مركبة آلية تجارية لارتكاب جناية بموجب قواعد CDL في كولورادو على أنه:","options":["مخالفة مرورية خطيرة","مخالفة كبرى","مخالفة أمر إيقاف عن الخدمة","مخالفة معبر سكة حديد"],"explanation":"استخدام مركبة آلية تجارية في ارتكاب جناية مخالفة كبرى، تستتبع سحب الأهلية لمدة سنة واحدة لأول إدانة ومدى الحياة للثانية. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"46":{"q":"أول إدانة بأي مخالفة مرورية خطيرة تؤدي إلى أي سحب لأهلية CDL في كولورادو؟","options":["لا سحب للأهلية","30 يومًا","60 يومًا","120 يومًا"],"explanation":"المخالفة المرورية الخطيرة الواحدة لا تؤدي بحد ذاتها إلى سحب أهلية السائق؛ ويبدأ سحب الأهلية فقط مع ثاني أو ثالث مخالفة من هذا النوع خلال 3 سنوات. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"47":{"q":"كم تدوم مدة سحب أهلية حامل رخصة CDL في كولورادو لثاني مخالفة مرورية خطيرة تُرتكب خلال فترة 3 سنوات؟","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى سحب الأهلية لمدة 60 يومًا. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"48":{"q":"كم تدوم مدة سحب الأهلية لثالث مخالفة مرورية خطيرة خلال فترة 3 سنوات؟","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات إلى سحب الأهلية لمدة 120 يومًا. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"49":{"q":"عند أي سرعة فوق الحد المعلن تُحتسب مخالفة تجاوز السرعة على أنها 'مخالفة مرورية خطيرة' لحامل رخصة CDL في كولورادو؟","options":["10 ميل في الساعة أو أكثر فوق الحد","15 ميلًا في الساعة أو أكثر فوق الحد","20 ميلًا في الساعة أو أكثر فوق الحد","25 ميلًا في الساعة أو أكثر فوق الحد"],"explanation":"تجاوز السرعة بمقدار 15 ميلًا في الساعة أو أكثر فوق الحد المعلن للسرعة مخالفة مرورية خطيرة. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"50":{"q":"أي مما يلي لا يُحتسب مخالفة مرورية خطيرة لحامل رخصة CDL في كولورادو؟","options":["القيادة المتهورة","السير خلف المركبة بمسافة قريبة جدًا","قيادة مركبة آلية تجارية بتركيز كحول في الدم (BAC) قدره 0.04","تغييرات المسار غير المنتظمة أو غير الصحيحة"],"explanation":"القيادة بتركيز كحول في الدم (BAC) قدره 0.04 أو أكثر مخالفة كبرى، وليست مخالفة مرورية خطيرة. أما القيادة المتهورة، والسير خلف المركبة بمسافة قريبة جدًا، وتغييرات المسار غير الصحيحة فهي مخالفات مرورية خطيرة. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"51":{"q":"تُصنّف الرسائل النصية أو استخدام هاتف محمول يدوي أثناء قيادة مركبة آلية تجارية بشكل متكرر بموجب قواعد CDL في كولورادو على أنها:","options":["مخالفة كبرى","مخالفة مرورية خطيرة","مخالفة أمر إيقاف عن الخدمة","مخالفة لا تستوجب سحب الأهلية"],"explanation":"الرسائل النصية أو استخدام هاتف يدوي أثناء قيادة مركبة آلية تجارية مخالفة مرورية خطيرة؛ وتؤدي الإدانات المتعددة خلال 3 سنوات إلى سحب الأهلية لمدة 60/120 يومًا. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51، 392.80/392.82."},"52":{"q":"قانون كولورادو لاستخدام اليدين الحرّتين لعام 2025 (SB24-065) يحظر عمومًا استخدام الأجهزة اليدوية، لكن كيف يُطبّق على سائقي CDL الذين يشغّلون مركبة آلية تجارية؟","options":["سائقو CDL معفون لأن القواعد الفيدرالية الأكثر صرامة تحظر بالفعل استخدام الهاتف اليدوي","يحلّ محل القاعدة الفيدرالية بالكامل لسائقي المركبات الآلية التجارية","لا يُطبّق على أي سائق في كولورادو","يسمح لسائقي المركبات الآلية التجارية بإرسال الرسائل النصية إذا توقفوا عند إشارة"],"explanation":"سائقو المركبات الآلية التجارية معفون من قانون الولاية لاستخدام اليدين الحرّتين لأن القاعدة الفيدرالية الأكثر صرامة (السارية منذ 2012) تحظر بالفعل أي استخدام لهاتف يدوي وإرسال الرسائل النصية أثناء قيادة مركبة آلية تجارية. المصدر: Colorado SB24-065؛ FMCSA 49 CFR 392.80/392.82."},"53":{"q":"بموجب القاعدة الفيدرالية التي تنطبق على سائقي المركبات الآلية التجارية في كولورادو، ما هو الحد الأقصى لغرامة السائق على إرسال الرسائل النصية أو استخدام هاتف يدوي أثناء قيادة مركبة آلية تجارية؟","options":["$500","$1,000","$2,750","$11,000"],"explanation":"يواجه السائقون عقوبات مدنية تصل إلى $2,750 (ينطبق مبلغ $11,000 على أصحاب العمل). المصدر: قاعدة FMCSA للهاتف المحمول/عدم إرسال الرسائل النصية، 49 CFR 392.80/392.82."},"54":{"q":"ما هو الحد الأدنى لسحب أهلية CDL لأول مخالفة معبر سكة حديد بمستوى الطريق في كولورادو؟","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تستتبع أول مخالفة معبر سكة حديد سحب الأهلية لمدة لا تقل عن 60 يومًا. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"55":{"q":"ثاني مخالفة معبر سكة حديد بمستوى الطريق خلال 3 سنوات تؤدي إلى أي حد أدنى لسحب أهلية CDL؟","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"تستتبع ثاني مخالفة معبر سكة حديد خلال 3 سنوات سحب الأهلية لمدة لا تقل عن 120 يومًا. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"56":{"q":"ثالث مخالفة معبر سكة حديد بمستوى الطريق أو ما بعدها خلال 3 سنوات تؤدي إلى أي حد أدنى لسحب الأهلية؟","options":["120 يومًا","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"تستتبع ثلاث مخالفات معبر سكة حديد أو أكثر خلال 3 سنوات سحب الأهلية لمدة لا تقل عن سنة واحدة. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"57":{"q":"ما هو نطاق سحب الأهلية لأول مخالفة لأمر الإيقاف عن الخدمة (OOS) من قبل سائق CDL في كولورادو لا ينقل مواد خطرة أو ركابًا؟","options":["30 إلى 60 يومًا","90 يومًا فقط","180 يومًا إلى سنة واحدة","2 إلى 5 سنوات"],"explanation":"تؤدي أول مخالفة لأمر الإيقاف عن الخدمة إلى سحب الأهلية لمدة 180 يومًا إلى سنة واحدة بالنسبة لسائق لا ينقل مواد خطرة أو ركابًا. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"58":{"q":"ثاني مخالفة لأمر الإيقاف عن الخدمة خلال 10 سنوات (دون مواد خطرة، دون ركاب) تؤدي إلى أي نطاق لسحب الأهلية؟","options":["120 يومًا إلى 6 أشهر","180 يومًا إلى سنة واحدة","2 إلى 5 سنوات","مدى الحياة"],"explanation":"تستتبع ثاني مخالفة لأمر الإيقاف عن الخدمة خلال 10 سنوات سحب الأهلية لمدة 2 إلى 5 سنوات. المصدر: دليل CDL في كولورادو، القسم 1؛ 49 CFR 383.51."},"59":{"q":"بموجب قانون كولورادو \"خفّف السرعة، وأفسح المجال\" (Slow Down, Move Over)، ماذا يجب على سائق المركبة التجارية (CMV) فعله عند الاقتراب من شاحنة قطر متوقفة تعرض أضواء كهرمانية/صفراء وامضة على طريق سريع به مساران في الاتجاه نفسه؟","options":["الاستمرار بالسرعة المحددة مع إطلاق البوق","الانتقال إلى مسار يبعد على الأقل بمسار متحرك واحد عن المركبة المتوقفة","التوقف تمامًا حتى تتحرك شاحنة القطر مبتعدة","الانتقال إلى الكتف الأيمن والمرور ببطء"],"explanation":"يقتضي قانون \"أفسح المجال\" في كولورادو (CRS 42-4-705) من السائقين على طريق سريع به مساران على الأقل في الاتجاه نفسه أن يفسحوا المجال بالانتقال إلى مسار يبعد على الأقل بمسار متحرك واحد عن أي مركبة طوارئ أو قطر أو مرفق عام متوقفة وتعرض أضواء وامضة. المصدر: دليل كولورادو CDL / CRS 42-4-705."},"60":{"q":"على طريق سريع في كولورادو محدد بسرعة 65 mph، لا يستطيع سائق مركبة تجارية (CMV) تغيير المسار بأمان لتجنب سيارة دورية متوقفة بسبب كثافة المرور. ما السرعة التي يفترض القانون CRS 42-4-705 أنها آمنة؟","options":["65 mph، بما أن الانتقال جانبًا كان مستحيلًا","45 mph (أقل بـ 20 mph من المحدد) تُفترض آمنة","25 mph بصرف النظر عن الحد المحدد","التوقف الكامل حتى يخلو المسار"],"explanation":"ينص قانون \"أفسح المجال\" في كولورادو (CRS 42-4-705) على أنه عندما لا يستطيع السائق الانتقال جانبًا، فعلى الطرق المحددة بـ 45 mph أو أعلى تُفترض سرعة أقل بـ 20 mph من الحد المحدد آمنة (هنا 45 mph)، وعلى الطرق دون 45 mph تُفترض سرعة 25 mph أو أقل آمنة. المصدر: CRS 42-4-705."},"61":{"q":"عند تفعيل إشارات توقف حافلة المدرسة في كولورادو، ما الحد الأدنى للمسافة قبل الوصول إلى الحافلة التي يجب أن يتوقف عندها السائق المقترب؟","options":["10 feet","15 feet","20 feet","50 feet"],"explanation":"يقتضي القانون CRS 42-4-1903 من السائق الذي يقابل أو يتجاوز حافلة مدرسية متوقفة وأضواؤها الحمراء المرئية مفعّلة أن يتوقف على مسافة لا تقل عن 20 feet قبل الوصول إلى الحافلة وألا يتابع حتى تتوقف الأضواء عن العمل. المصدر: دليل كولورادو CDL / CRS 42-4-1903."},"62":{"q":"بموجب قانون حافلات المدارس في كولورادو، متى لا يُطلب من السائق التوقف لحافلة مدرسية تُحمّل أو تُنزل الأطفال وأضواؤها الحمراء وامضة؟","options":["كلما كان السائق يسير بسرعة أقل من 25 mph","عندما تكون الحافلة على طريق مختلف من طريق سريع مقسوم إلى طرق منفصلة","عندما يكون هناك أكثر من مسار في اتجاه السائق","كلما كانت الحافلة ضمن منطقة تجارية"],"explanation":"ينص القانون CRS 42-4-1903 على أن السائق على طريق سريع ذي طرق منفصلة لا يحتاج إلى التوقف عند مقابلة أو تجاوز حافلة مدرسية موجودة على طريق مختلف. أما على طريق غير مقسوم، فيجب أن يتوقف المرور في كلا الاتجاهين. المصدر: CRS 42-4-1903."},"63":{"q":"يقترب سائق في كولورادو ينقل مواد خطرة موضوعًا عليها لوحات تحذيرية (placarded) من تقاطع سكة حديد. ضمن أي مسافة من أقرب قضيب يجب أن تتوقف المركبة؟","options":["ضمن 50 feet ولكن ليس أقل من 15 feet","ضمن 100 feet ولكن ليس أقل من 50 feet","ضمن 25 feet ولكن ليس أقل من 10 feet","ضمن 75 feet ولكن ليس أقل من 25 feet"],"explanation":"يقتضي القانون CRS 42-4-707 من مركبات المواد الخطرة ذات اللوحات التحذيرية، وحافلات المدارس التي تنقل أطفال المدارس، والمركبات التجارية الناقلة للركاب أن تتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب، ثم تنظر وتُصغي قبل المتابعة. المصدر: دليل كولورادو CDL / CRS 42-4-707."},"64":{"q":"أثناء عبور مركبة تجارية (CMV) ذات لوحات تحذيرية لقضبان السكة الحديد في كولورادو بعد التوقف، ما القيد الإضافي الذي ينطبق بموجب CRS 42-4-707؟","options":["يجب على السائق العبور بالرجوع للخلف ثم للأمام لاختبار التماسك","يجب على السائق ألا يبدّل التروس يدويًا أثناء عبور القضبان","يجب على السائق تفعيل الأضواء الوامضة الرباعية على طول المعبر بأكمله","يجب على السائق العبور فقط بسرعة أقل من 5 mph"],"explanation":"يوجّه القانون CRS 42-4-707 بأن يعبر السائق فقط إذا لم تكن هناك حاجة لتغيير التروس أثناء اجتياز المعبر، وألا يبدّل التروس يدويًا أثناء عبور القضبان، مما يقلل من خطر تعطّل المركبة على القضبان. المصدر: CRS 42-4-707."},"65":{"q":"عند أي نوع من تقاطعات السكة الحديد لا يقتضي قانون كولورادو من سائق مركبة ذات لوحات تحذيرية أو حافلة أن يقوم بالتوقف الإلزامي؟","options":["أي معبر بدون بوابات أوتوماتيكية","معبر يضبطه ضابط شرطة أو شخص يوجّه المرور (flagperson)","أي معبر في منطقة سكنية","معبر به مجموعتان أو أكثر من القضبان"],"explanation":"يستثني القانون CRS 42-4-707 التوقف الإلزامي حيث يوجّه ضابط شرطة أو شخص حامل علم المرور، وحيث توجّه إشارة ضبط مرور المرور، وعند معابر السكك الحديدية المتقاطعة مع الشوارع في منطقة تجارية، وعند المعابر المعلَّمة بلافتة \"exempt\" رسمية. المصدر: CRS 42-4-707."},"66":{"q":"ما هو الحد الأقصى للسرعة على طريق سريع مرصوف بأربعة مسارات في كولورادو ويشكل جزءًا من نظام الطرق السريعة بين الولايات، في حال عدم وجود حد محدد مختلف؟","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"يحدد القانون CRS 42-4-1101 سرعة 65 mph على الطرق السريعة المرصوفة ذات الأربعة مسارات في نظام الطرق بين الولايات كحد أقصى قانوني (يجوز لـ CDOT تحديد حدود أعلى أو أدنى على مقاطع معينة). المصدر: CRS 42-4-1101."},"67":{"q":"كيف يتعامل قانون كولورادو مع حد السرعة للشاحنات الكبيرة مقارنة بسيارات الركاب على الطريق السريع نفسه؟","options":["للشاحنات حد منفصل على مستوى الولاية أقل بـ 10 mph من السيارات","يجب أن تبقى الشاحنات أقل بـ 15 mph من الحد المحدد على المنحدرات","تتبع الشاحنات الحد المحدد نفسه؛ لا يوجد في كولورادو حد سرعة عام مختلف للشاحنات","تُقيَّد الشاحنات بـ 55 mph على مستوى الولاية بصرف النظر عن اللافتات"],"explanation":"لا يضع قانون السرعة في كولورادو (CRS 42-4-1101) حدًا منفصلًا أدنى للسرعة على مستوى الولاية للشاحنات بحسب الفئة أو الوزن؛ فالمركبات التجارية تتبع نفس الحدود المحددة كباقي المركبات. المصدر: CRS 42-4-1101."},"68":{"q":"بموجب CRS 42-4-1101، ما هو حد السرعة الظاهري (prima facie) على \"الطريق الجبلي المفتوح\" في كولورادو؟","options":["30 mph","40 mph","50 mph","55 mph"],"explanation":"يُدرج القانون CRS 42-4-1101 سرعة 40 mph على الطرق الجبلية المفتوحة (و20 mph على الطرق الجبلية الضيقة والملتوية أو المنعطفات المحجوبة الرؤية) ضمن الحدود الظاهرية. المصدر: CRS 42-4-1101."},"69":{"q":"يمنع قانون مسارات الشاحنات في كولورادو لعام 2024 الشاحنات التي تبلغ 16,000 lbs أو أكثر من المسار الأقصى يسارًا في مواقع جبلية معينة على I-70. أي من هذه هو إحدى تلك المناطق المحددة؟","options":["Monument Hill على I-25","Vail Pass","Raton Pass على I-25","تقاطع Grand Junction"],"explanation":"يمنع قيد المسار الأيسر للشاحنات في كولورادو الشاحنات التي تبلغ 16,000 lbs أو أثقل من المسار الأقصى يسارًا على مقاطع I-70 التي تشمل Floyd Hill وGeorgetown Hill ونفق Eisenhower وDowd Junction وVail Pass، حيث يوجد ثلاثة مسارات على الأقل في اتجاه واحد. المصدر: CDOT / قانون كولورادو 2024 (SB24-100)."},"70":{"q":"على مقاطع I-70 حيث تقيّد كولورادو الشاحنات الثقيلة عن المسار الأقصى يسارًا، ما الاستثناء الذي يسمح به القانون؟","options":["يجوز للشاحنات استخدام المسار الأيسر عندما يكون المرور خفيفًا","يجوز للشاحنات استخدام المسار الأقصى يسارًا لتجاوز مركبة أخرى","يجوز للشاحنات استخدام المسار الأيسر ليلًا فقط","لا يوجد أي استثناء بأي حال"],"explanation":"لا يزال قيد المسار الأيسر للشاحنات في كولورادو على مقاطع I-70 الجبلية المحددة يسمح للشاحنات باستخدام المسار الأقصى يسارًا عند التجاوز؛ فالحظر يستهدف السير المستمر في المسار الأيسر. المصدر: CDOT / قانون كولورادو 2024 (SB24-100)."},"71":{"q":"يقتضي قانون كولورادو لإلزامية حمل السلاسل (Chain Must-Carry) من المركبات التجارية حمل السلاسل على ممر I-70 الجبلي خلال أي فترة سنوية؟","options":["من 1 أكتوبر حتى 30 أبريل","من 1 سبتمبر حتى 31 مايو","من 1 نوفمبر حتى 31 مارس","طوال العام، دون نافذة موسمية"],"explanation":"يقتضي قانون الإلزام بالحمل في كولورادو من المركبات التجارية (التي يبلغ وزنها الإجمالي المقنّن GVWR 16,001 lbs أو أكثر) حمل سلاسل كافية من 1 سبتمبر حتى 31 مايو على I-70 بين Dotsero (MP 133) وMorrison (MP 259). المصدر: CDOT / CRS 42-4-106."},"72":{"q":"عندما يكون قانون السلاسل للمركبات التجارية في كولورادو ساري المفعول، كيف يجب أن تكون مركبة تجارية (CMV) بأربع عجلات دفع أو أكثر مجهّزة لكي تتابع السير؟","options":["سلاسل أو أجهزة جر بديلة (ATDs) على ما لا يقل عن أربعة من إطارات عجلات الدفع","سلاسل على إطارات التوجيه فقط","سلاسل على أي إطارين من اختيار السائق","الإطارات المصنّفة للثلوج وحدها كافية دائمًا"],"explanation":"عندما يكون قانون السلاسل فعّالًا، يجب أن يكون لدى المركبة التجارية (CMV) سلاسل أو أجهزة جر بديلة على ما لا يقل عن أربعة من إطارات عجلات الدفع (أو جميع إطارات الدفع إذا كان لديها أقل من أربعة). المصدر: قانون السلاسل CDOT / CRS 42-4-106."},"73":{"q":"ممر I-70 الجبلي حيث ينطبق قانون السلاسل للمركبات التجارية في كولورادو يمتد بين أي نقطتين؟","options":["Grand Junction (MP 26) وDenver (MP 275)","Dotsero (MP 133) وMorrison (MP 259)","Glenwood Springs (MP 116) وGolden (MP 263)","Vail (MP 176) وIdaho Springs (MP 240)"],"explanation":"ينطبق متطلب السلاسل/الإلزام بالحمل التجاري في كولورادو على I-70 بين مخرج Dotsero (Milepost 133) ومخرج Morrison (Milepost 259). المصدر: CDOT / CRS 42-4-106."},"74":{"q":"على الطريق السريع بين الولايات في كولورادو، بعد توقف مركبة تجارية (CMV) على الجزء المخصص للمرور، ضمن كم قدمًا يجب على السائق وضع أجهزة التحذير الثلاثة باتجاه المرور المقترب على طريق مستوٍ ومستقيم؟","options":["عند 5 و50 و100 feet","عند 10 و100 و200 feet","عند 25 و150 و300 feet","عند 50 و250 و500 feet"],"explanation":"تتبع كولورادو المعيار الفيدرالي FMCSR الذي يقتضي وضع أجهزة التحذير عند 10 feet و100 feet و200 feet من المركبة التجارية المتوقفة باتجاه المرور المقترب على طريق غير مقسوم ومستوٍ. المصدر: دليل كولورادو CDL / 49 CFR 392.22 (المعتمد في كولورادو)."},"75":{"q":"اضطرت مركبة تجارية (CMV) في كولورادو للتوقف على الطريق مباشرة بعد منعطف حاد يحجبها عن المرور المقترب. كيف ينبغي تعديل أجهزة التحذير؟","options":["وضع الثلاثة جميعها ضمن 10 feet من المصد الخلفي","تحريك الجهاز باتجاه المنعطف بمسافة 100 إلى 500 feet للخلف لإعطاء تحذير كافٍ","حذف الأجهزة الخلفية والاكتفاء بالإشارة من الأمام","وضع الثلاثة جميعها على خط الوسط بجانب المقصورة"],"explanation":"عند التوقف ضمن 500 feet من منعطف أو قمة تل أو عائق رؤية آخر، يحرّك السائق جهاز التحذير باتجاه العائق ليكون على مسافة 100 إلى 500 feet من المركبة لإعطاء تحذير كافٍ. المصدر: دليل كولورادو CDL / 49 CFR 392.22."},"76":{"q":"منحدر الشاحنات الهاربة الأكثر استخدامًا في كولورادو، على I-70 المتجه غربًا قرب نفق Eisenhower، يوصف أفضل وصف بأنه أي نوع من الأجهزة؟","options":["فراش حصى موقف (gravel arrestor bed) يستخدم ركامًا سائبًا عميقًا لإيقاف الشاحنة الهاربة","شبكة كابلات فولاذية ممدودة عبر المسار","وسادة تصادم مملوءة بالماء عند أسفل المنحدر","شريط فرملة مغناطيسي مدمج في الرصيف"],"explanation":"منحدر Lower Straight Creek على I-70 المتجه غربًا هو منحدر الشاحنات الهاربة الأكثر استخدامًا في الولايات المتحدة؛ ومثل فرش الإيقاف الأخرى في كولورادو، يستخدم فراشًا عميقًا من الركام المسحوق السائب (صخور مدوّرة) لتبديد طاقة الشاحنة الهاربة. المصدر: CDOT / قسم القيادة الجبلية في دليل كولورادو CDL."},"77":{"q":"ما هو الحد الأقصى القانوني لعَرض المركبة على الطرق السريعة في كولورادو قبل أن يُطلب تصريح حمولة كبيرة الحجم (oversize permit) من CDOT؟","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"الحد القانوني للعرض في كولورادو هو 8 feet 6 inches (102 inches)؛ والحمولات التي تتجاوز هذا تتطلب تصريح حمولة كبيرة الحجم من CDOT، والتي يزيد عرضها عن 11 feet تتطلب عمومًا مركبة مرافقة/استكشاف أمامية على الطرق السريعة الحكومية المحددة. المصدر: CDOT للشحن والتصاريح / CRS 42-4-502."},"78":{"q":"على منحدر جبلي في كولورادو، ما تقنية الفرملة الصحيحة التي ينبغي لسائق مركبة تجارية (CMV) استخدامها لتجنب الحاجة إلى منحدر للشاحنات الهاربة؟","options":["الضغط على فرامل الخدمة بثبات طوال النزول","اختيار ترس منخفض قبل النزول واستخدام تطبيقات فرملة خفيفة ومتقطعة","التحويل إلى الوضع المحايد لتوفير الوقود والانزلاق نزولًا","تطبيق صمام اليد للمقطورة باستمرار أثناء التواجد في ترس مرتفع"],"explanation":"توجّه إرشادات القيادة الجبلية في دليل كولورادو CDL السائقين إلى اختيار ترس منخفض آمن قبل بدء النزول على منحدر طويل واستخدام الفرامل بشكل متقطع (snub braking) كي لا تسخن الفرامل وتتلاشى فعاليتها؛ والانزلاق في الوضع المحايد غير قانوني وخطير. المصدر: دليل كولورادو CDL (القيادة الجبلية)."},"79":{"q":"أي وكالة في كولورادو تصدر رخص القيادة التجارية (CDLs) وتدير اختبارات المعرفة المطلوبة؟","options":["إدارة النقل في كولورادو (CDOT)","قسم المركبات الآلية (DMV) التابع لإدارة الإيرادات في كولورادو","قسم موانئ الدخول التابع لدورية ولاية كولورادو","الإدارة الفيدرالية لسلامة ناقلات المركبات الآلية (FMCSA)"],"explanation":"في كولورادو، تصدر رخص القيادة التجارية (CDLs) من قسم المركبات الآلية (DMV) التابع لإدارة الإيرادات؛ وتُجرى اختبارات المعرفة في مكتب DMV/المركبات الآلية للخدمة الكاملة. المصدر: Colorado DMV، dmv.colorado.gov (سائق CDL لأول مرة / معلومات CDL عامة)."},"80":{"q":"ما الحد الأدنى لدرجة النجاح في اختبار المعرفة العامة لـ CDL في كولورادو، الذي يتضمن 50 سؤالًا؟","options":["70% (على الأقل 35 من 50 صحيحة)","75% (على الأقل 38 من 50 صحيحة)","90% (على الأقل 45 من 50 صحيحة)","80% (على الأقل 40 من 50 صحيحة)"],"explanation":"يحتوي اختبار المعرفة العامة لـ CDL في كولورادو على 50 سؤالًا ويتطلب 80% — على الأقل 40 إجابة صحيحة — للنجاح، بما يتوافق مع دليل كولورادو CDL ومعايير اختبار DMV. المصدر: Colorado DMV / دليل كولورادو CDL."},"81":{"q":"يتكوّن اختبار المهارات لـ CDL في كولورادو من ثلاثة أجزاء. أي مجموعة تسرد هذه الأجزاء الثلاثة بشكل صحيح؟","options":["المعرفة الكتابية، وفحص ما قبل الرحلة، والقيادة على الطريق","فحص فرامل الهواء، والركن الموازي، واختبار إشارات الطريق","التحكم الأساسي بالمركبة، وفحص المواد الخطرة، والقيادة على الطريق","فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق"],"explanation":"يتضمن اختبار مهارات CDL في كولورادو ثلاثة أجزاء: فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة (المناورات)، واختبار القيادة على الطريق، بما يحاكي بنية اختبار مهارات CDL الفيدرالي المعتمد من كولورادو. المصدر: دليل كولورادو CDL؛ Colorado DMV."},"82":{"q":"قبل أن يتمكن المتقدم لـ CDL لأول مرة في كولورادو من إجراء اختبار المهارات، ما التدريب المنصوص عليه فيدراليًا الذي يجب إتمامه والتحقق منه؟","options":["دورة قيادة دفاعية معتمدة من دورية ولاية كولورادو","ندوة CDOT لتأمين الحمولات كبيرة الحجم/الزائدة الوزن","تدريب السائقين المبتدئين (ELDT) من مزوّد مسجّل لدى FMCSA","توجيه سلامة دراسي من إدارة الإيرادات"],"explanation":"منذ 7 فبراير 2022، تقتضي كولورادو إتمام تدريب السائقين المبتدئين (ELDT) عبر مزوّد مسجّل لدى FMCSA (مسجّل في سجل مزوّدي التدريب) قبل أن يتمكن المتقدم الجديد، أو المتقدم لترقية الفئة، أو المتقدم لمصادقة H/P/S جديدة من إجراء اختبار المهارات. المصدر: Colorado DMV؛ 49 CFR Part 380 / FMCSA TPR."},"83":{"q":"كم مدة صلاحية تصريح المتعلّم التجاري (CLP) في كولورادو، وهل يمكن تجديده؟","options":["صالح لمدة 180 يومًا وقابل للتجديد مرة واحدة","صالح لمدة 60 يومًا وقابل للتجديد مرتين","صالح لمدة خمس سنوات وقابل للتجديد سنويًا","صالح لمدة سنة واحدة وغير مؤهل للتجديد"],"explanation":"تصريح CLP في كولورادو صالح لمدة سنة واحدة وغير قابل للتجديد؛ إذا انتهت صلاحيته قبل الحصول على CDL، يجب على المتقدم إعادة اختبار(ات) المعرفة للحصول على CLP جديد. المصدر: Colorado DMV (معلومات CDL عامة / سائق CDL لأول مرة)."},"84":{"q":"بعد إصدار تصريح المتعلّم التجاري (CLP) لمتقدم في كولورادو، كم يجب الاحتفاظ به قبل أن يمكن إجراء اختبار مهارات CDL؟","options":["30 يومًا تقويميًا على الأقل","7 أيام تقويمية على الأقل","14 يومًا تقويميًا على الأقل","60 يومًا تقويميًا على الأقل"],"explanation":"تتبع كولورادو القاعدة الفيدرالية التي تقضي بالاحتفاظ بـ CLP لمدة 14 يومًا تقويميًا على الأقل قبل أن يتمكن حامله من إجراء اختبار مهارات CDL. المصدر: 49 CFR 383.25؛ Colorado DMV."},"85":{"q":"يجب على المتقدمين لـ CDL في كولورادو إتمام إقرار ذاتي (self-certification) يعلنون فيه نوع قيادتهم. كم عدد فئات الإقرار الذاتي؟","options":["اثنتان","ثلاث","خمس","أربع"],"explanation":"هناك أربع فئات للإقرار الذاتي: بين الولايات غير مستثنى، وبين الولايات مستثنى، وداخل الولاية غير مستثنى، وداخل الولاية مستثنى. في كولورادو يُعلن هذا في النموذج DR 2904/DR 2907. المصدر: نموذج Colorado DMV رقم DR 2904؛ 49 CFR 383.71."},"86":{"q":"السائق في كولورادو الذي يعمل في التجارة بين الولايات ويجب أن يستوفي قواعد تأهيل السائق في 49 CFR Part 391 (وبالتالي يجب أن يحمل شهادة طبية) ينبغي أن يقرّ ذاتيًا ضمن أي فئة؟","options":["بين الولايات مستثنى","داخل الولاية غير مستثنى","داخل الولاية مستثنى","بين الولايات غير مستثنى"],"explanation":"السائق الذي يعمل في التجارة بين الولايات والخاضع لمتطلبات التأهيل في 49 CFR Part 391 والمستوفي لها — والذي يجب أن يحمل شهادة فاحص طبي — يقرّ ذاتيًا بصفته بين الولايات غير مستثنى. المصدر: نموذج Colorado DMV رقم DR 2904؛ 49 CFR 383.71."},"87":{"q":"لاستيفاء المتطلب الطبي لـ DOT، أي وثيقة يجب على المتقدم لـ CDL في كولورادو الحصول عليها وتقديمها؟","options":["مذكرة طبيب عام تؤكد الصحة الجيدة","بطاقة لياقة من دورية ولاية كولورادو","شهادة فاحص طبي (Medical Examiner's Certificate) من مزوّد على السجل الوطني لـ FMCSA","إعفاء طبي لتصريح CDOT"],"explanation":"يجب على معظم حاملي CDL في كولورادو الحصول على شهادة فاحص طبي (بطاقة DOT الطبية) من فاحص مدرج على السجل الوطني لـ FMCSA للفاحصين الطبيين المعتمدين. المصدر: Colorado DMV (CDL DOT الطبي)؛ السجل الوطني لـ FMCSA."},"88":{"q":"بالنسبة لسائق CDL غير مستثنى نموذجي في كولورادو، ما الحد الأقصى لمدة صلاحية شهادة الفاحص الطبي لـ DOT؟","options":["حتى سنتين","حتى خمس سنوات","حتى سنة واحدة","حتى ثلاث سنوات"],"explanation":"تُصدر شهادة الفاحص الطبي لـ DOT لمدة أقصاها سنتان (وقد تكون أقصر إذا لاحظ الفاحص حالة تحتاج إلى متابعة). يجب على السائق الاحتفاظ بشهادة سارية في ملفه لدى Colorado DMV. المصدر: 49 CFR 391.43؛ Colorado DMV (CDL DOT الطبي)."},"89":{"q":"إذا ترك سائق CDL غير مستثنى ومقِرّ ذاتيًا في كولورادو الشهادة الطبية الموجودة في ملف DMV تنتهي صلاحيتها، ما العاقبة النموذجية؟","options":["تُلغى CDL فورًا وبشكل دائم","تُخفَّض درجة CDL بحيث تُزال امتيازات القيادة التجارية حتى تُقدَّم شهادة طبية سارية","لا يحدث شيء حتى تجديد CDL بعد خمس سنوات","يُعاد تصنيف السائق تلقائيًا بصفته بين الولايات مستثنى"],"explanation":"إذا انتهت صلاحية الشهادة الطبية لسائق غير مستثنى ولم تُقدَّم شهادة سارية، تُخفّض كولورادو الرخصة، فتزيل امتيازات القيادة التجارية حتى تكون شهادة سارية في الملف. المصدر: Colorado DMV (CDL DOT الطبي)؛ 49 CFR 383.73."},"90":{"q":"ما الحد الأدنى للعمر لإصدار CDL في كولورادو للقيادة التجارية بين الولايات (INTERSTATE) أو لنقل مواد خطرة ذات لوحات تحذيرية؟","options":["21 عامًا","18 عامًا","19 عامًا","25 عامًا"],"explanation":"تتبع كولورادو الحد الأدنى الفيدرالي: يجب أن يكون السائق بعمر 21 للعمل في التجارة بين الولايات أو لنقل المواد الخطرة ذات اللوحات التحذيرية. ويُقتصر السائقون بين 18-20 على العمل داخل الولاية. المصدر: Colorado DMV؛ 49 CFR 383."},"91":{"q":"حامل CDL في كولورادو الذي يتراوح عمره بين 18 و20 عامًا مقيّد بالقيادة داخل كولورادو فقط. أي رمز قيد رخصة يعكس هذا الحد المقتصر على داخل الولاية؟","options":["القيد \"K\" (داخل الولاية فقط)","القيد \"L\" (بدون فرامل هواء)","القيد \"Z\" (بدون فرامل هواء كاملة)","القيد \"E\" (بدون ناقل حركة يدوي)"],"explanation":"تطبّق كولورادو القيد \"K\" (داخل الولاية فقط) على حاملي CDL الذين لا يجوز لهم العمل في التجارة بين الولايات، بما في ذلك السائقون بين سن 18-20. المصدر: Colorado DMV (قيود CDL)."},"92":{"q":"أي مجموعة من الوثائق يجب على المتقدم لـ CDL لأول مرة في كولورادو تقديمها في DMV؟","options":["فقط رخصة قيادة عادية حالية من كولورادو","إثبات الهوية، وإثبات الوجود القانوني في الولايات المتحدة، وإثبات رقم الضمان الاجتماعي، وإثبات الإقامة في كولورادو","جواز سفر وتصريح حمولة من CDOT","خطاب من صاحب العمل وصورتان لجواز سفر فقط"],"explanation":"يجب على المتقدمين لـ CDL في كولورادو إثبات الهوية، والوجود القانوني في الولايات المتحدة، ورقم الضمان الاجتماعي، وعنوان الإقامة في كولورادو (مثل فاتورة خدمات أو كشف حساب بنكي). المصدر: Colorado DMV (سائق CDL لأول مرة)."},"93":{"q":"كيف تؤكد DMV إتمام المتقدم لـ CDL في كولورادو لتدريب ELDT قبل السماح باختبار المهارات؟","options":["يرسل المتقدم شهادة ورقية بالبريد إلى CDOT للموافقة","يحضر المتقدم إفادة موثّقة من المدرّب","يبلّغ المزوّد عنه إلكترونيًا إلى سجل مزوّدي التدريب التابع لـ FMCSA، الذي تتحقق منه DMV","تصدر دورية ولاية كولورادو خطاب تخليص ELDT"],"explanation":"يقدّم مزوّدو ELDT المسجّلون لدى FMCSA سجلات الإتمام إلى سجل مزوّدي التدريب الفيدرالي (TPR)؛ وتتحقق DMV في كولورادو من السجل إلكترونيًا قبل السماح باختبار المهارات. المصدر: Colorado DMV؛ FMCSA TPR / 49 CFR Part 380."},"94":{"q":"بالترتيب الصحيح، ما الخطوات الرئيسية الثلاث الأولى للمتقدم لـ CDL لأول مرة في كولورادو؟","options":["إجراء اختبار المهارات، ثم الحصول على CLP، ثم إتمام ELDT","اجتياز اختبار(ات) المعرفة والحصول على CLP، ثم إتمام ELDT، ثم إجراء اختبار المهارات","إتمام ELDT، ثم إجراء اختبار المهارات، ثم اجتياز اختبار المعرفة","الحصول على البطاقة الطبية، ثم إجراء اختبار المهارات، ثم إجراء اختبار المعرفة"],"explanation":"التسلسل في كولورادو هو: اجتياز اختبار(ات) المعرفة المطلوبة والحصول على CLP، وإتمام ELDT المعتمد من FMCSA (النظري والقيادة الفعلية)، ثم إجراء اختبار المهارات المكوّن من ثلاثة أجزاء (بعد فترة الاحتفاظ بـ CLP لمدة 14 يومًا). المصدر: Colorado DMV (سائق CDL لأول مرة)."},"95":{"q":"أثناء جزء القيادة على الطريق من اختبار مهارات CDL في كولورادو، ما الذي يقيّمه الفاحص بشكل أساسي؟","options":["قدرة المتقدم على تشغيل المركبة بأمان في حركة مرور حقيقية على مسار محدد","ما إذا كان المتقدم يستطيع تلاوة محتويات دليل CDL","سرعة المتقدم في الركن الموازي فقط","امتثال المركبة لحدود تصاريح الحمولات كبيرة الحجم/الزائدة الوزن"],"explanation":"يقيّم اختبار القيادة على الطريق التشغيل الآمن في حركة مرور فعلية على مسار محدد مسبقًا — المنعطفات، والتقاطعات، وتغييرات المسار، والقيادة العامة. أما الرجوع للخلف/المناورات فتُقيَّم في جزء التحكم الأساسي المنفصل. المصدر: دليل كولورادو CDL؛ Colorado DMV."},"96":{"q":"سائق في كولورادو ينقل فقط لوازم مزارع داخل كولورادو بالكامل ومُستثنى من أجزاء من قواعد تأهيل السائق في الولاية. أي فئة إقرار ذاتي تناسب هذا السائق؟","options":["داخل الولاية مستثنى","بين الولايات غير مستثنى","بين الولايات مستثنى","داخل الولاية غير مستثنى"],"explanation":"السائق الذي يعمل داخل كولورادو فقط والمستثنى من كل أو جزء من متطلبات تأهيل السائق في الولاية يقرّ ذاتيًا بصفته داخل الولاية مستثنى، وعمومًا لا يُطلب منه تقديم شهادة طبية لـ DOT. المصدر: نموذج Colorado DMV رقم DR 2904؛ 49 CFR 383.71."},"97":{"q":"فيما يتعلق برسوم CDL في كولورادو، أي عبارة هي الأدق لدليل دراسي؟","options":["اختبار المعرفة والمهارات لـ CDL مجاني دائمًا في كولورادو","الرسوم محددة بشكل دائم بموجب القانون الفيدرالي ولا تتغير أبدًا","مبالغ الرسوم المحددة تضعها الولاية ويمكن أن تتغير، لذا ينبغي على المتقدمين التأكد من الرسوم الحالية مع DMV","الفحص الطبي وحده له رسوم؛ ولا تتقاضى DMV شيئًا مقابل الرخصة"],"explanation":"تتقاضى كولورادو رسومًا مقابل اختبار CDL وإصداره، لكن المبالغ الدقيقة تضعها الولاية وهي عرضة للتغيير؛ وينبغي على المتقدمين التحقق من الرسوم الحالية مع DMV بدلًا من الاعتماد على رقم ثابت. المصدر: Colorado DMV (معلومات CDL عامة / جدول الرسوم)."}}};
